/**
 * Chapter Notes — embedded data (no fs dependency)
 * Data source: WCO HS 2022 Chapter Notes
 * Total chapters: 96, with notes: 94
 * Last updated: 2026-03-18
 */

import type { ChapterNote } from '../types';

let cachedNotes: ChapterNote[] | null = null;

export function getChapterNote(chapterNumber: number): ChapterNote | null {
  const notes = getAllChapterNotes();
  return notes.find(n => n.chapter_number === chapterNumber) || null;
}

export function getAllChapterNotes(): ChapterNote[] {
  if (cachedNotes) return cachedNotes;
  cachedNotes = EMBEDDED_CHAPTER_NOTES;
  return cachedNotes;
}

export function parseChapterNoteRules(note: ChapterNote | null): {
  excludes: string[];
  includes: string[];
  definitions: Record<string, string>;
} {
  if (!note || !note.chapter_note) {
    return { excludes: [], includes: [], definitions: {} };
  }
  const text = note.chapter_note;
  const excludes: string[] = [];
  const includes: string[] = [];
  const definitions: Record<string, string> = {};
  const excludePatterns = [
    /(?:does not (?:cover|include|apply to)|exclud(?:es|ing)|not classified in this chapter)[:\s]+([^.]+)/gi,
    /this (?:chapter|heading) does not (?:cover|include)[:\s]+([^.]+)/gi,
  ];
  for (const pattern of excludePatterns) {
    let match: RegExpExecArray | null;
    while ((match = pattern.exec(text)) !== null) {
      excludes.push(match[1].trim().substring(0, 200));
    }
  }
  const includePatterns = [
    /(?:includes?|covers?|applies to|means)[:\s]+([^.]+)/gi,
  ];
  for (const pattern of includePatterns) {
    let match: RegExpExecArray | null;
    while ((match = pattern.exec(text)) !== null) {
      if (!match[1].toLowerCase().includes('not ')) {
        includes.push(match[1].trim().substring(0, 200));
      }
    }
  }
  const defPattern = /['“]([^'”]+)['”]\s*means?\s+([^.]+)/gi;
  let defMatch: RegExpExecArray | null;
  while ((defMatch = defPattern.exec(text)) !== null) {
    definitions[defMatch[1].trim().toLowerCase()] = defMatch[2].trim().substring(0, 200);
  }
  return { excludes, includes, definitions };
}

// Embedded chapter notes — WCO HS 2022
const EMBEDDED_CHAPTER_NOTES: ChapterNote[] = [
  { chapter_number: 1, chapter_code: '01', description: 'LIVE ANIMALS', chapter_note: '1. This chapter covers all live animals except:\n\n    a) fish and crustaceans, molluscs and other aquatic invertebrates, of heading 0301, 0306, 0307 or 0308;\n\n    b) cultures of micro-organisms and other products of heading 3002; and\n\n    c) animals of heading 9508.\n\n2. In this chapter “purebred breeding animal” is defined as in (UK law equivalent to EU Regulation 1012/2016)', note_length: 384 },
  { chapter_number: 2, chapter_code: '02', description: 'MEAT AND EDIBLE MEAT OFFAL', chapter_note: '1. This chapter does not cover:\n\n   a) products of the kinds described in headings 0201 to 0208 or 0210, unfit or unsuitable for human consumption;\n\n   b) edible, non-living insects (heading 0410);\n\n   c) guts, bladders or stomachs of animals (heading 0504) or animal blood (heading 0511 or 3002); or\n\n   d) animal fat, other than products of heading 0209 (Chapter 15).\n\n### Additional chapter notes\n\n1. A. The following expressions have the meanings hereby assigned to them:\n\n   (a) ‘carcases of bovine animals’, for the purposes of subheadings 0201 10 and 0202 10: whole carcases of the slaughtered animals after having been bled, eviscerated and skinned, imported with or without the heads, with or without the feet and with or without the other offal’s attached. Where carcases are imported without the heads, the latter must have been separated from the carcase at the atloido-occipital joint. When imported without the feet, the latter must have been cut off at the carpo-metacarpal or tarso-metatarsal joints; ‘carcase’ includes the front part of the carcase comprising all the bones and the scrag, neck and shoulder, having more than 10 pairs of ribs;\n\n   (b) ‘half-carcases of bovine animals’, for the purposes of subheadings 0201 10 and 0202 10: the product resulting from the symmetrical division of the whole carcase through the centre of each cervical, dorsal, lumbar and sacral vertebra and through the centre of the sternum and of the ischio-pubic symphysis; ‘half-carcase’ includes the front part of the half-carcase comprising all the bones and the scrag, neck and shoulder, having more than 10 ribs;\n\n   (c) ‘compensated quarters’, for the purposes of codes 0201 20 20 and 0202 20 10: portions composed of either:\n\n      - forequarters comprising all the bones and the scrag, neck and shoulder, and cut at the tenth rib; and hindquarters comprising all the bones and the thigh and sirloin, and cut at the third rib, or\n\n      - forequarters comprising all the bones and the scrag, neck and shoulder, and cut at the fifth rib, with the whole of the flank and breast attached; and hindquarters comprising all the bones and the thigh and sirloin and cut at the eighth cut rib.\n\n      The forequarters and the hindquarters constituting ‘compensated quarters’ must be presented to customs at the same time and in equal numbers, and the total weight of the forequarters must be the same as that of the hindquarters; however, a difference between the weights of the two parts of the consignment is allowed, provided that this does not exceed 5 % of the weight of the heavier part (forequarters or hindquarters);\n\n   (d) ‘unseparated forequarters’, for the purposes of codes 0201 20 30 and 0202 20 30: the front part of a carcase, comprising all the bones and the scrag, neck and shoulder, with a minimum of four pairs of ribs and a maximum of 10 pairs of ribs (the first four pairs of ribs must be whole, the others may be cut), with or without the thin flank;\n\n   (e) ‘separated forequarters’, for the purposes of code 0201 20 30 and 0202 20 30: the front part of a half-carcase, comprising all the bones and the scrag, neck and shoulder, with a minimum of four ribs and a maximum of 10 ribs (the first four ribs must be whole, the others may be cut), with or without the thin flank;\n\n   (f) ‘unseparated hindquarters’, for the purposes of code 0201 20 50 and 0202 20 50: the rear part of a carcase comprising all the bones and the thigh and sirloin, including the fillet, with a minimum of three pairs of whole or cut ribs, with or without the shank and with or without the thin flank;\n\n   (g) ‘separated hindquarters’, for the purposes of code 0201 20 50 and 0202 20 50: the rear part of a half-carcase, comprising all the bones and the thigh and sirloin, including the fillet, with a minimum of three whole or cut ribs, with or without the shank and with or without the thin flank;\n\n   (h)   \n\n      1. ‘crop’ and ‘chuck and blade’ cuts, for the purposes of code 0202 30 50: the dorsal part of the forequarter, including the upper part of the shoulder, obtained from a forequarter with a minimum of four ribs and a maximum of 10 ribs by a cut along a straight line through the point where the first rib joins the first sternal segment to the point of reflection of the diaphragm on the tenth rib;\n\n      2. ‘brisket’ cut, for the purposes of code 0202 30 50: the lower part of the forequarter, comprising the brisket navel end and the brisket point end.\n\n   B. Products covered by additional chapter notes 1(A)(a) to (g) to this chapter may be presented with or without the vertebral column.\n\n   C. In determining the number of whole or cut ribs referred to in additional chapter note 1(A), only those attached to the vertebral column are to be taken into consideration. If the vertebral column has been removed, only the whole or cut ribs which otherwise would have been directly attached to the vertebral column are to be taken into consideration.\n\n2. A. The following expressions have the meanings hereby assigned to them:\n\n      (a) ‘carcases or half-carcases’, for the purposes of codes 0203 11 10 and 0203 21 10: slaughtered pigs, in the form of carcases of domestic swine which have been bled and eviscerated and from which the bristles and hooves have been removed. Half-carcases are derived from whole carcases by division through each cervical, dorsal, lumbar and sacral vertebra, through or along the sternum and through the ischio-pubic symphysis. These carcases or half-carcases may be with or without head, with or without the chaps, feet, flare fat, kidneys, tail or diaphragm. Half-carcases may be with or without spinal cord, brain or tongue. Carcases and half-carcases of sows may be with or without udders (mammary glands);\n\n      (b) ‘hams’ (legs), for the purposes of codes 0203 12 11, 0203 22 11, 0210 11 11 and 0210 11 31: the posterior (caudal) part of the half-carcase, including bones, with or without the foot, shank, rind or subcutaneous fat. The ham (leg) is separated from the rest of the half-carcase, so that it includes, at most, the last lumbar vertebra;\n\n      (c) ‘fore-ends’, for the purposes of codes 0203 19 11, 0203 29 11, 0210 19 30 and 0210 19 60: the anterior (cranial) part of the half-carcase without the head, with or without the chaps, including bones, with or without foot, shank, rind or subcutaneous fat. The fore-end is separated from the rest of the half-carcase, so that it includes, at most, the fifth dorsal vertebra. The upper (dorsal) part of the fore-end, whether or not containing the blade-bone and attached muscles (neckend in fresh or collar in salted condition), is considered a cut of the loin, when it is separated from the lower (ventral) part of the fore-end, at most by a cut just below the vertebral column;\n\n      (d) ‘shoulders’, for the purposes of codes 0203 12 19, 0203 22 19, 0210 11 19 and 0210 11 39: the lower part of the fore-end whether or not containing the blade-bone and attached muscles, including bones, with or without foot, shank, rind or subcutaneous fat. The blade-bone and attached muscles, presented separately, remain classified in this subheading as a part of the shoulder;\n\n      (e) ‘loins’, for the purposes of codes 0203 19 13, 0203 29 13, 0210 19 40 and 0210 19 70: the upper part of the half-carcase, extending from the first cervical vertebra to the caudal vertebrae, including bones, with or without the tenderloin, blade-bone, subcutaneous fat or rind. The loin is separated from the lower part of the half-carcase by a cut just below the vertebral column;\n\n      (f) ‘bellies’, for the purposes of code 0203 19 15, 0203 29 15, 0210 12 11 and 0210 12 19: the lower part of the half-carcase situated between the ham (leg) and the shoulder, commonly known as ‘streaky’, with or without bones, but with the rind and the subcutaneous fat;\n\n      (g) ‘bacon sides’, for the purposes of code 0210 19 10: the pig half-carcase without the head, cheek, chap, feet, tail, flare fat, kidney, tenderloin, blade-bone, sternum, vertebral column, pelvic bone and diaphragm;\n\n      (h) ‘spencers’, for the purposes of code 0210 19 10: the bacon side without the ham, whether or not boned;\n\n      (ij) ‘three-quarter sides’, for the purposes of code 0210 19 20: the bacon side without the fore-end, whether or not boned;\n\n      (k) ‘middles’, for the purposes of code 0210 19 20: the bacon side without the ham and the fore-end, whether or not boned. The subheading also includes cuts of middles containing tissue of loin and belly in natural proportion to the entire middles.\n\n      B. The parts of the cuts defined in paragraph 2(A)(f) fall in the same codes, only if they contain rind and subcutaneous fat. If the cuts falling in subheadings 0210 11 11, 0210 11 19, 0210 11 31, 0210 11 39, 0210 19 30 and 0210 19 60 are derived from a bacon side from which the bones indicated under paragraph 2(A)(g) have already been removed, the lines of cutting must follow those defined under paragraph 2(A)(b), (c) and (d) accordingly; in any case, these cuts or parts thereof must contain bones.\n\n      C. Codes 0206 49 00 and 0210 99 49, include, in particular, heads or halves of heads of domestic swine, with or without the brains, cheeks or tongues, and parts thereof. The head is separated from the rest of the half-carcase as follows:\n\n      - by a straight cut parallel to the cranium; or\n\n      - by a cut parallel to the cranium up to the level of the eyes and then inclined to the front of the head, thereby causing the chaps to remain attached to the half-carcase. The cheeks, snouts and ears as well as the meat attached to the head, particularly to the rear part, are considered parts of heads. \n\n      However, the cuts of boneless meat of the fore-end, presented alone (jowls, chaps, or chaps and jowls together), fall in codes 0203 19 55, 0203 29 55, 0210 19 50 or 0210 19 81, as the case may be.\n\n      D. For the purposes of codes 0209 10 11 and 0209 10 19, ‘subcutaneous pig fat’ has the meaning of the fatty tissue which accumulates under the rind of the pig and adheres to it, irrespective of the part of the pig from which it comes; in any case, the weight of the fatty tissue must exceed the weight of the rind. These subheadings also include subcutaneous pig fat from which the rind has been removed.\n\n      E. For the purposes of codes 0210 11 31, 0210 11 39, 0210 12 19 and 0210 19 60 to 0210 19 89, products in which the water/protein ratio in the meat (nitrogen content × 6.25) is 2.8 or less is considered as ‘dried or smoked’. The nitrogen content is determined in accordance with ISO method 937-1978. \n\n3. A. For the purposes of heading 0204, the following expressions have the meanings hereby assigned to them:\n\n      (a) ‘carcases’, for the purposes of subheadings 0204 10, 0204 21, 0204 30, 0204 41, and codes 0204 50 11 and 0204 50 51: whole carcases of the slaughtered animals after having been bled, eviscerated and skinned, imported with or without the heads, with or without the feet and with or without the other offal’s attached. Where carcases are imported without the heads, the latter must have been separated from the carcase at the atloidooccipital joint. When imported without the feet, the latter must have been cut off at the carpo-metacarpal or tarso-metatarsal joints;\n\n      (b) ‘half-carcases’, for the purposes of subheadings 0204 10, 0204 21, 0204 30, 0204 41, and codes 0204 50 11 and 0204 50 51: the product resulting from the symmetrical division of the whole carcase through the centre of each cervical, dorsal, lumbar and sacral vertebra and through the centre of the sternum and of the ischiopubic symphysis;\n\n      (c) ‘short-forequarters’, for the purposes of codes 0204 22 10, 0204 42 10, 0204 50 13 and 0204 50 53: the anterior part of the carcase, with or without the breast, including all the bones and the shoulders, scrag and middle neck, cut at right angles to the backbone, with a minimum of five and a maximum of seven pairs of whole or cut ribs;\n\n      (d) ‘short-forequarters’, for the purposes of codes 0204 22 10, 0204 42 10, 0204 50 13 and 0204 50 53: the anterior part of the half-carcase, with or without the breast, including all the bones and the shoulder, scrag and middle neck, cut at right angles to the backbone, with a minimum of five and a maximum of seven whole or cut ribs;\n\n      (e) ‘chines and/or best ends’, for the purposes of codes 0204 22 30, 0204 42 30, 0204 50 15 and 0204 50 55: the remaining part of the carcase after the legs and short-forequarters have been removed, with or without the kidneys; the chines, when separated from the best ends, must include a minimum of five lumbar vertebrae; the best ends, when separated from the chines, must include a minimum of five pairs of whole or cut ribs;\n\n      (f) ‘chine and/or best end’, for the purposes of codes 0204 22 30, 0204 42 30, 0204 50 15 and 0204 50 55: the remaining part of the half-carcase after the legs and short-forequarters have been removed, with or without the kidney; the chine, when separated from the best end, must include a minimum of five lumbar vertebrae; the best end, when separated from the chine, must include a minimum of five whole or cut ribs;\n\n      (g) ‘legs’, for the purposes of codes 0204 22 50, 0204 42 50, 0204 50 19 and 0204 50 59: the rear part of the carcase, comprising all the bones and the legs and cut at right angles to the backbone at the sixth lumbar vertebra just under the ilium or at the fourth sacral vertebra through the ilium anterior to the ischiopubic symphysis;\n\n      (h) ‘legs’, for the purposes of codes 0204 22 50, 0204 42 50, 0204 50 19 and 0204 50 59: the rear part of the half-carcase comprising all the bones and the leg cut at right angles to the backbone at the sixth lumbar vertebra just under the ilium or at the fourth sacral vertebra through the ilium anterior to the ischio-pubic symphysis.\n\n   B. In determining the number of whole or cut ribs referred to in paragraph 3 A, only those attached to the backbone are to be taken into consideration.\n\n4. The following expressions have the meanings hereby assigned to them:\n\n   (a) ‘poultry cuts, with bone in’, for the purposes of codes 0207 13 20 to 0207 13 60, 0207 14 20 to 0207 14 60, 0207 26 20 to 0207 26 70, 0207 27 20 to 0207 27 70, 0207 44 21 to 0207 44 61, 0207 45 21 to 0207 45 61, 0207 54 21 to 0207 54 61, 0207 55 21 to 0207 55 61 and 0207 60 21 to 0207 60 61: the cuts specified therein, including all bones. Poultry cuts as referred to in (a) which have been partly boned fall in codes 0207 13 70, 0207 14 70, 0207 26 80, 0207 27 80, 0207 44 71, 0207 44 81, 0207 45 71, 0207 45 81, 0207 54 71, 0207 54 81, 0207 55 71, 0207 55 81 and 0207 60 81;\n\n   (b) ‘halves’, for the purposes of codes 0207 13 20, 0207 14 20, 0207 26 20, 0207 27 20, 0207 44 21, 0207 45 21, 0207 54 21, 0207 55 21 and 0207 60 21: halves of poultry carcases, obtained by a longitudinal cut in a plane along the sternum and the backbone;\n\n   (c) ‘quarters’, for the purposes of codes 0207 13 20, 0207 14 20, 0207 26 20, 0207 27 20, 0207 44 21, 0207 45 21, 0207 54 21, 0207 55 21 and 0207 60 21: leg quarters or breast quarters, obtained by a transversal cut of a half;\n\n   (d) ‘whole wings, with or without tips’, for the purposes of codes 0207 13 30, 0207 14 30, 0207 26 30, 0207 27 30, 0207 44 31, 0207 45 31, 0207 54 31, 0207 55 31 and 0207 60 31: poultry cuts, consisting of the humerus, radius and ulna, together with the surrounding musculature. The tip, including the carpal bones, may or may not have been removed. The cuts must have been made at the joints;\n\n   (e) ‘breasts’, for the purposes of codes 0207 13 50, 0207 14 50, 0207 26 50, 0207 27 50, 0207 44 51, 0207 45 51, 0207 54 51, 0207 55 51 and 0207 60 51: poultry cuts, consisting of the sternum and the ribs distributed on both sides of it, together with the surrounding musculature;\n\n   (f) ‘legs’, for the purposes of codes 0207 13 60, 0207 14 60, 0207 44 61, 0207 45 61, 0207 54 61, 0207 55 61 and 0207 60 61: poultry cuts consisting of the femur, tibia and fibula, together with the surrounding musculature. The two cuts must have been made at the joints;\n\n   (g) ‘turkey drumsticks’, for the purposes of codes 0207 26 60 and 0207 27 60: turkey cuts, consisting of the tibia and fibula, together with the surrounding musculature. The two cuts must have been made at the joints;\n\n   (h) ‘turkey legs, other than drumsticks’, for the purposes of codes 0207 26 70 and 0207 27 70: turkey cuts, consisting of the femur together with the surrounding musculature or of the femur, tibia and fibula, together with the surrounding musculature. The two cuts must have been made at the joints;\n\n   (ij) ‘duck or goose paletots’, for the purposes of codes 0207 44 71, 0207 45 71, 0207 54 71 and 0207 55 71: ducks or geese, plucked and completely drawn, without heads or feet, with carcase bones (breastbone, ribs, backbone and sacrum) removed, but with the femurs, tibias and humeri.\n\n5.   \n\n   (a) Uncooked seasoned meats fall in Chapter 16. ‘Seasoned meat’ is uncooked meat that has been seasoned, either in depth or over the whole surface of the product, with seasoning either visible to the naked eye or clearly distinguishable by taste.\n\n   (b) Products falling in heading 0210 to which seasoning has been added during the process of preparation remain classified therein, provided that the addition of seasoning has not changed their character.\n\n6. For the purposes of subheadings 0210 11 to 0210 93, the term ‘meat and edible meat offal, salted or in brine’ means meat and edible meat offal deeply and homogeneously impregnated with salt in all parts and having a total salt content by weight of 1.2% or more, provided that it is the salting which ensures the long-term preservation. For the purposes of subheading 0210 99, the term ‘meat and edible meat offal, salted or in brine’ means meat and edible meat offal deeply and homogeneously impregnated with salt in all parts and having a total salt content by weight of 1.2% or more.\n\n7. The duty rate applicable to mixtures falling in Chapter 2 can be found in the current version of the “Tariff of the United Kingdom”, Part Four “Rules for calculation of import duties”, General Rule 1, see Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK', note_length: 18476 },
  { chapter_number: 3, chapter_code: '03', description: 'FISH AND CRUSTACEANS, MOLLUSCS AND OTHER AQUATIC INVERTEBRATES', chapter_note: '1. This chapter does not cover:\n\n   - (a) mammals of heading 0106;\n\n   - (b) meat of mammals of heading 0106 (heading 0208 or 0210);\n\n   - (c) fish (including livers, roes and milt thereof) or crustaceans, molluscs or other aquatic invertebrates, dead and unfit or unsuitable for human consumption by reason of either their species or their condition (Chapter 5); flours, meals or pellets of fish or of crustaceans, molluscs or other aquatic invertebrates, unfit for human consumption (heading 2301); or\n\n   - (d) caviar or caviar substitutes prepared from fish eggs (heading 1604).\n\n2. In this chapter, the term ‘pellets’ means products which have been agglomerated either directly by compression or by the addition of a small quantity of binder.\n\n3. Headings 0305 to 0308 do not cover flours, meals and pellets, fit for human consumption (heading 0309)\n\n### Additional chapter notes\n\n1. For the purposes of codes 0305 32 11 and 0305 32 19, cod fillets (Gadus morhua, Gadus ogac, Gadus macrocephalus) having a total salt content by weight of 12% or more which are fit for human consumption without further industrial processing, are considered to be salted fish. \n\n   However, frozen cod fillets which have a total salt content by weight of less than 12% are to be classified under codes 0304 71 10 and 0304 71 90, in so far as the actual and lasting preservation depends essentially upon freezing.\n\n2. For the purposes of the subheadings referred to in the third paragraph, the term ‘fillets’ includes ‘loins’, i.e. the strips of meat constituting the upper or lower, right or left, side of a fish insofar as the head, guts, fins (dorsal, anal, caudal, ventral, pectoral) and bones (spinal column or main backbone, ventral or costal bones, branchial bone or stapes, etc.) have been removed. \n\n   The classification of such products as fillets is unaffected by cutting them into pieces, provided that these pieces can be identified as having been obtained from fillets.\n\n   The provisions of the first two paragraphs apply to the following fish:\n\n   - (a) tuna, of the genus Thunnus, of codes 0304 49 90 and 0304 87 00;\n\n   - (b) swordfish (Xiphias gladius) of codes 0304 45 00 and 0304 84 00;\n\n   - (c) marlin, sailfish and spearfish, of the family Istiophoridae, of codes 0304 49 90 and 0304 89 90;\n\n   - (d) oceanic sharks (Hexanchus griseus, Cetorhinus maximus, Rhincodon typus, or of the families Alopiidae, Carcharhinidae, Sphyrnidae and Isuridae) of codes 0304 47 90 and 0304 88 22 and 0304 88 29 .', note_length: 2538 },
  { chapter_number: 4, chapter_code: '04', description: 'DAIRY PRODUCE; BIRDS\' EGGS; NATURAL HONEY; EDIBLE PRODUCTS OF ANIMAL ORIGIN, NOT ELSEWHERE SPECIFIED OR INCLUDED', chapter_note: '1. The expression ‘milk’ means full-cream milk or partially or completely skimmed milk.\n\n2. For the purposes of heading 0403, yogurt may be concentrated or flavoured and may contain added sugar or other sweetening matter, fruit, nuts, cocoa, chocolate, spices, coffee or coffee extracts, plants, parts of plants, cereals or bakers’ wares, provided that any added substance is not used for the purpose of replacing, in whole or in part, any milk constituent, and the product retains the essential character of yogurt.\n\n3. For the purposes of heading 0405:\n\n    - (a) the term ‘butter’ means natural butter, whey butter or recombined butter (fresh, salted or rancid, including canned butter) derived exclusively from milk, with a milkfat content of 80 % or more but not more than 95 % by weight, a maximum milk solids-not-fat content of 2 % by weight and a maximum water content of 16 % by weight. Butter does not contain added emulsifiers, but may contain sodium chloride, food colours, neutralising salts and cultures of harmless lactic-acid-producing bacteria;\n\n    - (b) the expression ‘dairy spreads’ means a spreadable emulsion of the water-in-oil type, containing milkfat as the only fat in the product, with a milkfat content of 39 % or more but less than 80 % by weight.\n\n4. Products obtained by the concentration of whey and with the addition of milk or milkfat are to be classified as cheese in heading 0406 provided that they have the three following characteristics:\n\n   - (a) a milkfat content, by weight of the dry matter, of 5 % or more;\n\n   - (b) a dry matter content, by weight, of at least 70 % but not exceeding 85 %; and\n\n   - (c) they are moulded or capable of being moulded.\n\n5. This chapter does not cover:\n\n    - (a) non-living insects, unfit for human consumption (heading 0511);\n\n    - (b) products obtained from whey, containing by weight more than 95 % lactose, expressed as anhydrous lactose calculated on the dry matter (heading 1702);\n\n    - (c) products obtained from milk by replacing one or more of its natural constituents (for example, butyric fats) by another substance (for example, oleic fats) (heading 1901 or 2106); or\n\n    - (d) albumins (including concentrates of two or more whey proteins, containing by weight more than 80 % whey proteins, calculated on the dry matter) (heading 3502) or globulins (heading 3504).\n\n6. For the purposes of heading 0410, the term “insects” means edible non-living insects, whole or in parts, fresh, chilled, frozen, dried, smoked, salted or in brine, as well as flours and meals of insects, fit for human consumption. However, it does not cover edible non-living insects otherwise prepared or preserved (generally Section IV). \n\n### Subheading notes\n\n1. For the purposes of subheading 0404 10, the expression ‘modified whey’ means products consisting of whey constituents, that is, whey from which all or part of the lactose, proteins or minerals have been removed, whey to which natural whey constituents have been added, and products obtained by mixing natural whey constituents.\n\n2. For the purposes of subheading 0405 10, the term ‘butter’ does not include dehydrated butter or ghee (subheading 0405 90).\n\n### Additional chapter notes\n\n1. For the purposes of subheadings 0408 11 and 0408 19, the following applies:\n\n    the expression ‘otherwise preserved’ applies also to egg yolks with limited amounts of salt (in general, an amount of up to around 12 % by weight) or minor amounts of chemicals added for preservation purposes, provided that both of the following conditions are fulfilled:\n\n    (i) the products retain the character of egg yolks of subheadings 0408 11 and 0408 19;\n\n    (ii) salt or chemicals are not used at a level higher than is necessary for the purposes of preservation.\n\n2. Dairy produce of Chapter 4 includes dairy permeates, which are milk products characterised by a high content of lactose and obtained by removing milk fats and milk proteins from milk, whey, cream and/or sweet buttermilk, and/or from similar raw material by ultrafiltration or other processing techniques.\n\n3. For the purposes of subheadings 0404 10 and 0404 90 the following applies:\n\n    Milk permeate and whey permeate can be analytically distinguished by the presence of substances (e.g. lactic acid, lactates and glycomacropeptides) which are associated with whey production. Subheading 0404 10 includes ‘whey permeate’ which is a product with generally a slightly sour smell, obtained from whey or mixtures of natural whey constituents by ultrafiltration or other processing techniques.\n\n    The presence of substances associated with whey production (e.g. lactic acid, lactates and glycomacropeptides) is a condition for the classification of whey permeates into that subheading. Subheading 0404 90 includes ‘milk permeate’ which is a product with generally a milky smell obtained from milk by ultrafiltration or other processing techniques. The quantitatively limited level or absence of lactic acid and lactates (lower than 0.1 % by weight, in milk permeates in powder form, or lower than 0.015% by weight in milk permeates in liquid form) as well as the absence of glycomacropeptides, are the conditions for the classification of milk permeates into subheading 0404 90. The method to be used for the detection of lactates shall be the ISO 8069:2005 method and the method to detect rennet whey (i.e. the presence of caseinomacropeptides such as glycomacropeptides) shall be the UK equivalent method to that set out in Appendix II to Commission Implementing Regulation (EU) 2018/150).\n\n4. The term “unfit for human consumption” as regards codes 0408 11 20, 0408 19 20, 0408 91 20 and 0408 99 20 applies when:\n\n   - the goods are homogeneously mixed with one of the denaturants shown in column 1 of the table below in the quantities indicated in column 2 and\n\n   - separation of the goods and the denaturant is not economically viable.\n\n    |  Denaturant   |   Minimum quantity to be used (in g) per 100 kg of denatured product\n    |  ------------------------  | ---------------------------------------------------------------------------  |\n    (1)   |   (2)\n    Spirit of turpentine  |  500\n    Essence of lavender  |  100\n    Oil of rosemary  |  150\n    Birch oil  |  100 \n\n5. The duty rate applicable to mixtures falling in heading 0401 to 0406 can be found in Part Four, General Rule 1 of this document.', note_length: 6460 },
  { chapter_number: 5, chapter_code: '05', description: 'PRODUCTS OF ANIMAL ORIGIN, NOT ELSEWHERE SPECIFIED OR INCLUDED', chapter_note: '1. This chapter does not cover:\n\n   - (a) edible products (other than guts, bladders and stomachs of animals, whole and pieces thereof, and animal blood, liquid or dried);\n\n   - (b) hides or skins (including fur skins), other than goods of heading 0505 and parings and similar waste of raw hides or skins of heading 0511 (Chapter 41 or 43);\n\n   - (c) animal textile materials, other than horsehair and horsehair waste (Section XI); or\n\n   - (d) prepared knots or tufts for broom or brush making (heading 9603).\n\n2. For the purposes of heading 0501, the sorting of hair by length (provided the root ends and tip ends respectively are not arranged together) shall be deemed not to constitute working.\n\n3. Throughout the nomenclature, elephant, hippopotamus, walrus, narwhal and wild boar tusks, rhinoceros horns and the teeth of all animals are regarded as ‘ivory’.\n\n4. Throughout the nomenclature, the expression ‘horsehair’ means hair of the manes or tails of equine or bovine animals. Heading 0511 covers, inter alia, horsehair and horsehair waste, whether or not put up as a layer with or without supporting material.', note_length: 1133 },
  { chapter_number: 6, chapter_code: '06', description: 'LIVE TREES AND OTHER PLANTS; BULBS, ROOTS AND THE LIKE; CUT FLOWERS AND ORNAMENTAL FOLIAGE', chapter_note: '1. Subject to the second part of heading 0601, this chapter covers only live trees and goods (including seedling vegetables) of a kind commonly supplied by nursery gardeners or florists for planting or for ornamental use; nevertheless, it does not include potatoes, onions, shallots, garlic or other products of Chapter 7.\n\n2. Any reference in heading 0603 or 0604 to goods of any kind shall be construed as including a reference to bouquets, floral baskets, wreaths and similar articles made wholly or partly of goods of that kind, account not being taken of accessories of other materials. However, these headings do not include collages or similar decorative plaques of heading 9701.', note_length: 688 },
  { chapter_number: 7, chapter_code: '07', description: 'EDIBLE VEGETABLES AND CERTAIN ROOTS AND TUBERS', chapter_note: '1. This chapter does not cover forage products of heading 1214.\n\n2. In heading 0709 to 0712 the word \'vegetables\' includes edible mushrooms, truffles, olives, capers, marrows, pumpkins, aubergines, sweet-corn (Zea mays var. saccharata), fruits of the genus Capsicum or of the genus Pimenta, fennel, parsley, chervil, tarragon, cress and sweet marjoram (Marjorana hortensis or Origanum majorana).\n\n3. Heading 0712 covers all dried vegetables of the kinds falling in heading 0701 to 0711, other than:\n\n   - (a) dried leguminous vegetables, shelled (heading 0713);\n   - (b) sweet-corn in the forms specified in heading 1102 to 1104;\n   - (c) flour, meal, powder, flakes, granules and pellets of potatoes (heading 1105);\n   - (d) flour, meal and powder of dried leguminous vegetables of heading 0713 (heading 1106).\n\n4. However, dried or crushed or ground fruits of the genus Capsicum or of the genus Pimenta are excluded from this chapter (heading 0904).\n\n5. Heading 0711 applies to vegetables which have been treated solely to ensure their provisional preservation during transport or storage prior to use (for example, by sulphur dioxide gas, in brine, in sulphur water or in other preservative solutions), provided they remain unsuitable for immediate consumption in that state.\n\n### Additional chapter notes\n\n1. Seed potatoes shall be classified in subheading 0701 10 00 provided that the goods comply with The Seed Potatoes Regulations 1991.\n\n2. Sweetcorn hybrids shall be classified in code 0712 90 11 as for sowing provided that:\n\n   - the goods comply with the Cereal Seeds Regulation 1974 or\n\n   - it is established that the goods are actually intended for sowing.\n\n3. Sweet potatoes shall be deemed to be for human consumption within the meaning of code 0714 20 10 if they are fresh, whole and put up in immediate packings at the time of release for free circulation.', note_length: 1899 },
  { chapter_number: 8, chapter_code: '08', description: 'EDIBLE FRUIT AND NUTS; PEEL OF CITRUS FRUIT OR MELONS', chapter_note: '1. This chapter does not cover inedible nuts or fruits.\n\n2. Chilled fruits and nuts are to be classified in the same headings as the corresponding fresh fruits and nuts.\n\n3. Dried fruit or dried nuts of this chapter may be partially rehydrated, or treated for the following purposes:\n\n   - (a) for additional preservation or stabilisation (for example, by moderate heat treatment, sulphuring, the addition of sorbic acid or potassium sorbate),\n\n   - (b) to improve or maintain their appearance (for example, by the addition of vegetable oil or small quantities of glucose syrup), provided that they retain the character of dried fruit or dried nuts.\n\n4. Heading 0812 applies to fruit and nuts which have been treated solely to ensure their provisional preservation during transport or storage prior to use (for example, by sulphur dioxide gas, in brine, in sulphur water or in other preservative solutions), provided they remain unsuitable for immediate consumption in that state. \n\n### Additional chapter notes\n\n1. The content of various sugars expressed as sucrose (sugar content) of the products classified in this chapter corresponds to the figure indicated by a refractometer at a temperature of 20C and multiplied by the factor 0.95.\n\n2. For the purposes of codes 0811 90 11, 0811 90 31 and 0811 90 85 \'tropical fruit\' means guavas, mangoes, mangosteens, papaws (papayas), tamarinds, cashew apples, lychees, jackfruit, sapodillo plums, passion fruit, carambola and pitahaya.\n\n3. For the purposes of codes 0811 90 11, 0811 90 31, 0811 90 85, 0812 90 70 and 0813 50 31 \'tropical nuts\' means coconuts, cashew nuts, Brazil nuts, areca (or betel), cola and macadamia nuts.', note_length: 1691 },
  { chapter_number: 9, chapter_code: '09', description: 'COFFEE, TEA, MATÉ AND SPICES', chapter_note: '1. Mixtures of the products of heading 0904 to 0910 are to be classified as follows:\n\n   - (a) mixtures of two or more of the products of the same heading are to be classified in that heading;\n\n   - (b) mixtures of two or more of the products of different headings are to be classified in heading 0910.\n\n    The addition of other substances to the products of heading 0904 to 0910 (or to the mixtures referred to in paragraph (a) or (b) above) shall not affect their classification provided that the resulting mixtures retain the essential character of the goods of those headings. Otherwise such mixtures are not classified in this chapter; those constituting mixed condiments or mixed seasonings are classified in heading 2103.\n\n2. This chapter does not cover cubeb pepper (Piper cubeba) or other products of heading 1211.\n\n### Additional chapter notes\n\n1. The duty rate applicable to mixtures falling in heading 0904 to 0910 can be found in the current version of the “Tariff of the United Kingdom”, Part Four “Rules for calculation of import duties”, General Rule 1, see Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK', note_length: 1180 },
  { chapter_number: 10, chapter_code: '10', description: 'CEREALS', chapter_note: '1. (A) The products specified in the headings of this chapter are to be classified in those headings only if grains are present, whether or not in the ear or on the stalk.\n\n   (B) The chapter does not cover grains which have been hulled or otherwise worked. However, rice, husked, milled, polished, glazed, parboiled or broken remains classified in heading 1006.\n\n   Similarly, quinoa from which the pericarp has been wholly or partly removed in order to separate the saponin, but which has not undergone any other processes, remains classified in heading 1008.\n\n2. Heading 1005 does not cover sweetcorn (Chapter 7).\n\n### Subheading note\n\n1. The term \'durum wheat\' means wheat of the species Triticum durum and the hybrids derived from the inter-specific crossing of Triticum durum which have the same number (28) of chromosomes as that species.\n\n### Additional chapter notes\n\n1. The following terms have the meanings hereunder assigned to them:\n\n   - (a) ‘round grain rice’ (codes 1006 10 30, 1006 20 11, 1006 20 92, 1006 30 21, 1006 30 42, 1006 30 61 and 1006 30 92): rice, the grains of which are of a length not exceeding 5.2 mm and of a length/width ratio of less than 2;\n\n   - (b) ‘medium grain rice’ (codes 1006 10 50, 1006 20 13, 1006 20 94, 1006 30 23, 1006 30 44, 1006 30 63 and 1006 30 94): rice, the grains of which are of a length exceeding 5.2 mm but not exceeding 6.0 mm and of a length/width ratio of less than 3;\n\n   - (c) ‘long grain rice’ (codes 1006 10 71, 1006 10 79, 1006 20 15, 1006 20 17, 1006 20 96, 1006 20 98, 1006 30 25, 1006 30 27, 1006 30 46, 1006 30 48, 1006 30 65, 1006 30 67, 1006 30 96 and 1006 30 98): rice, the grains of which are of a length exceeding 6.0 mm;\n\n   - (d) ‘paddy rice’ (codes 1006 10 30, 1006 10 50, 1006 10 71, 1006 10 79 and 1006 10 90): rice which has retained its husk after threshing;\n\n   - (e) ‘husked rice’ (codes 1006 20 11, 1006 20 13, 1006 20 15, 1006 20 17, 1006 20 19, 1006 20 92, 1006 20 94, 1006 20 96, 1006 20 98 and 1006 20 99): rice from which only the husk has been removed. Examples of rice falling within this definition are those with the commercial descriptions ‘brown rice’, ‘cargo rice’, ‘loonzain’ and ‘riso sbramato’;\n\n   - (f) ‘semi-milled rice’ (codes 1006 30 21, 1006 30 23, 1006 30 25, 1006 30 27, 1006 30 29, 1006 30 42, 1006 30 44, 1006 30 46, 1006 30 48 and 1006 30 49): rice from which the husk, part of the germ and the whole or part of the outer layers of the pericarp, but not the inner layers, have been removed;\n\n   - (g) ‘wholly milled rice’ (codes 1006 30 61, 1006 30 63, 1006 30 65, 1006 30 67, 1006 30 69, 1006 30 92, 1006 30 94, 1006 30 96, 1006 30 98 and 1006 30 99): rice from which the husk, the whole of the outer and inner layers of the pericarp, the whole of the germ in the case of long or medium grain rice, and at least part thereof in the case of round grain rice, have been removed, but in which longitudinal white striations may remain on not more than 10 % of the grains;\n\n   - (h) ‘broken rice’ (subheading 1006 40): grain fragments, the length of which does not exceed three-quarters of the average length of the whole grain.\n\n2. Spelt, hybrid maize, rice and hybrid sorghum shall be classified in the appropriate subheadings for sowing\nprovided that:\n\n   - the goods comply with the Cereal Seeds Regulations 1974 or\n\n   - it is established that the goods are actually intended for sowing\n\n3. The duty rate applicable to mixtures falling in Chapter 10 can be found in the current version of the “Tariff of the United Kingdom”, Part Four “Rules for calculation of import duties”, General Rule 1, see Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK', note_length: 3741 },
  { chapter_number: 11, chapter_code: '11', description: 'PRODUCTS OF THE MILLING INDUSTRY; MALT; STARCHES; INULIN; WHEAT GLUTEN', chapter_note: '1. This chapter does not cover:\n\n   - a. roasted malt put up as coffee substitutes (heading 0901 or 2101);\n   - b. prepared flours, groats, meals or starches of heading 1901;\n   - c. corn flakes and other products of heading 1904;\n   - d. vegetables, prepared or preserved, of heading 2001, 2004 or 2005;\n   - e. pharmaceutical products (Chapter 30); or\n   - f. starches having the character of perfumery, cosmetic or toilet preparations (Chapter 33).\n\n2. (A). Products from the milling of the cereals listed in the table below fall in this chapter if they have, by weight on the dry product:\n\n      - a. a starch content (determined by the modified Ewers polarimetric method) exceeding that indicated in column 2; and\n      - b. an ash content (after deduction of any added minerals) not exceeding that indicated in column 3.\n\n   Otherwise, they fall in heading 2302.\n\n   However, germ of cereals, whole, rolled, flaked or ground, is always classified in heading 1104.\n\n   (B). Products falling in this chapter under the above provisions shall be classified in heading 1101 or 1102 if the percentage passing through a woven metal wire cloth sieve with the aperture indicated in Column 4 or 5 is not less, by weight, than that shown against the cereal concerned.\n\n   Otherwise, they fall in heading 1103 or 1104.\n\n   | Cereal | Starch content | Ash content | Rate of passage through a sieve with an aperture of 315 micrometres (microns) | Rate of passage through a sieve with an aperture of 500 micrometres (microns) |\n   |-|-|-|-|-|\n   | (1) | (2) | (3) | (4) | (5) |\n   | Wheat and rye | 45 % | 2.5% | 80% | - |\n   | Barley | 45% | 3% | 80% | - |\n   | Oats | 45% | 5% | 80% | - |\n   | Maize (corn) and grain sorghum | 45% | 2% | - | 90% |\n   | Rice | 45% | 1.6% | 80% | - |\n   | Buckwheat | 45% | 4% | 80% | - |\n   | Other cereals | 45% | 2% | 50% | - |\n\n3. For the purposes of heading 1103, the terms \'groats\' and \'meal\' mean products obtained by the fragmentation of cereal grains, of which:\n\n   - a. in the case of maize (corn) products, at least 95% by weight passes through a woven metal wire cloth sieve with an aperture of 2mm;\n   - b. in the case of other cereal products, at least 95% by weight passes through a woven metal wire cloth sieve with an aperture of 1.25mm.\n\n### Additional chapter notes\n\n1. For the purposes of heading 1106, the terms \'flour\', \'meal\', and \'powder\' mean products (other than shredded desiccated coconut), obtained by milling or some other fragmentation process from dried leguminous vegetables of heading 0713, from sago or roots or tubers of heading 0714 or from products of Chapter 8, of which:\n\n   - a. in the case of dried leguminous vegetables, sago, roots, tubers and products of Chapter 8 (excluding nuts of heading 0801 and 0802), at least 95% by weight passes through a woven metal wire cloth sieve with an aperture of 2 mm;\n\n   - b. in the case of nuts of heading 0801 and 0802 at least 50% by weight passes through a woven metal wire cloth sieve with an aperture of 2.5 mm.\n\n2. The term “denatured” as regards code 1106 20 10 applies when:\n\n   - the goods are homogeneously mixed with one of the denaturants shown in column 1 of the table below in the quantities indicated in column 2 and\n\n   - separation of the goods and the denaturant is not economically viable.\n\n\n   | Denaturant | Minimum quantity to be used (in g) per 100kg of denatured product |\n   | - | - |\n   | (1) | (2) |\n   | Fish oil or fish liver oil, filtered but not deodorised or decolourised, with no additives | 1,000 |\n   | Fish meal of code 2301 20 00, having a characteristic odour and containing by weight in the dry matter at least: 62.5 % crude protein and 6 % crude lipids (fatty matter) | 5,000 |\n\n3. The duty rate applicable to mixtures falling in Chapter 11 can be found in the current version of the “Tariff of the United Kingdom”, Part Four “Rules for calculation of import duties”, General Rule 1, see Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK', note_length: 4087 },
  { chapter_number: 12, chapter_code: '12', description: 'OIL SEEDS AND OLEAGINOUS FRUITS; MISCELLANEOUS GRAINS, SEEDS AND FRUIT; INDUSTRIAL OR MEDICINAL PLANTS; STRAW AND FODDER', chapter_note: '1. Heading 1207 applies inter alia, to palm nuts and kernels, cotton seeds, castor oil seeds, sesamum seeds, mustard seeds, safflower seeds, poppy seeds and shea nuts (karite nuts). It does not apply to products of heading 0801 or 0802 or to olives (Chapter 7 or 20).\n\n2. Heading 1208 applies not only to non-defatted flours and meals but also to flours and meals which have been partially defatted or defatted and wholly or partially refatted with their original oils. It does not, however, apply to residues of heading 2304 to 2306.\n\n3. For the purposes of heading 1209, beet seeds, grass and other herbage seeds, seeds of ornamental flowers, vegetable seeds, seeds of forest trees, seeds of fruit trees, seeds of vetches (other than those of the species Vicia faba) or of lupines are to be regarded as \'seeds of a kind used for sowing\'.\n\n    Heading 1209 does not, however, apply to the following even if for sowing:\n\n    - a) leguminous vegetables or sweetcorn (Chapter 7);\n\n    - b) spices or other products of Chapter 9;\n\n    - c) cereals (Chapter 10); or\n\n    - d) products of heading 1201 to 1207 or 1211.\n\n4. Heading 1211 applies inter alia to the following plants or parts thereof: basil, borage, ginseng, hyssop, liquorice, all species of mint, rosemary, rue, sage and wormwood.\n\n    Heading 1211 does not, however apply to:\n\n    - a) medicaments of Chapter 30;\n    - b) perfumery, cosmetic or toilet preparations of Chapter 33; or\n    - c) insecticides, fungicides, herbicides, disinfectants or similar products of heading 3808.\n\n5. For the purposes of heading 1212, the term \'seaweeds and other algae\' does not include:\n\n   - a) dead single-cell micro-organisms of heading 2102;\n   - b) cultures of micro-organisms of heading 3002; or\n   - c) fertilisers of heading 3101 or 3105.\n\n### Subheading note\n\n1. For the purposes of subheading 1205 10, the expression \'low erucic acid rape or colza seeds\' means rape or colza seeds yielding a fixed oil which has an erucic acid content of less than 2% by weight and yielding a solid component which contains less than 30 micromoles of glucosinolates per gram.\n\n### Additional chapter note\n\n1. Oil seeds and oleaginous fruits shall be classified in the appropriate subheadings for seed or for sowing provided that:\n\n   - the goods comply with The Oil and Fibre Plant Seeds Regulations 1993 or\n   - it is established that the goods are actually intended for sowing.', note_length: 2457 },
  { chapter_number: 13, chapter_code: '13', description: 'LAC; GUMS, RESINS AND OTHER VEGETABLE SAPS AND EXTRACTS', chapter_note: '1. Heading 1302 applies, inter alia, to liquorice extract and extract of pyrethrum, extract of hops, extract of aloes and opium.\n\n    The heading does not apply to:\n\n    - a. liquorice extract containing more than 10% by weight of sucrose or put up as confectionery (heading 1704);\n    - b. malt extract (heading 1901);\n    - c. extracts of coffee, tea or mate (heading 2101);\n    - d. vegetable saps or extracts constituting alcoholic beverages (Chapter 22);\n    - e. camphor, glycyrrhizin or other products of heading 2914 or 2938;\n    - f. concentrates of poppy straw containing not less than 50% by weight of alkaloids (heading 2939);\n    - g. medicaments of heading 3003 or 3004 or blood-grouping reagents (heading 3822);\n    - h. tanning or dyeing extracts (heading 3201 or 3203);\n    - ij. essential oils, concretes, absolutes, resinoids, extracted oleoresins, aqueous distillates or aqueous solutions of essential oils or preparations based on odoriferous substances of a kind used for the manufacture of beverages (Chapter 33); or\n    - k. natural rubber, balata, gutta-percha, guayule, chicle or similar natural gums (heading 4001).\n\n### Additional chapter notes\n\n1. Mixtures of pectic substances and sugar with a sugar content exceeding 90% by weight, calculated on the dry matter, are excluded from classification under subheading 1302 20 and are in principle to be classified in Chapter 17, since the character of the product is deemed to be determined by the sugar.', note_length: 1496 },
  { chapter_number: 14, chapter_code: '14', description: 'VEGETABLE PLAITING MATERIALS; VEGETABLE PRODUCTS NOT ELSEWHERE SPECIFIED OR INCLUDED', chapter_note: '1. This chapter does not cover the following products which are to be classified within Section XI: vegetable materials or fibres of vegetable materials of a kind used primarily in the manufacture of textiles, however prepared, or other vegetable materials which have undergone treatment so as to render them suitable for use only as textile materials.\n\n2. Heading 1401 applies, inter alia, to bamboos (whether or not split, sawn lengthwise, cut to length, rounded at the ends, bleached, rendered non-inflammable, polished or dyed), split osier, reeds and the like, to rattan cores and to drawn or split rattans. The heading does not apply to chipwood (heading 4404).\n\n3. Heading 1404 does not apply to wood wool (heading 4405) and prepared knots or tufts for broom or brush making (heading 9603).', note_length: 801 },
  { chapter_number: 15, chapter_code: '15', description: 'ANIMAL, VEGETABLE OR MICROBIAL FATS AND OILS AND THEIR CLEAVAGE PRODUCTS; PREPARED EDIBLE FATS; ANIMAL OR VEGETABLE WAXES', chapter_note: '1. This chapter does not cover:\n\n    - a. pig fat or poultry fat of heading 0209;\n    - b. cocoa butter, fat and oil (heading 1804);\n    - c. edible preparations containing by weight more than 15% of the products of heading 0405 (generally Chapter 21);\n    - d. greaves (heading 2301) and residues of heading 2304 to 2306;\n    - e. fatty acids, prepared waxes, medicaments, paints, varnishes, soap, perfumery, cosmetic or toilet preparations, sulphonated oils or other goods of Section VI; or\n    - f. factice derived from oils (heading 4002).\n\n2. Heading 1509 does not apply to oils obtained from olives by solvent extraction (heading 1510).\n\n3. Heading 1518 does not cover fats or oils or their fractions merely denatured, which are to be classified in the heading appropriate to the corresponding undenatured fats and oils and their fractions.\n\n4. Soap-stocks, oil foots and dregs, stearin pitch, glycerol pitch and wool grease residues fall in heading 1522.\n\n### Subheading notes\n\n1. For the purposes of subheading 1509 30, virgin olive oil has a free acidity expressed as oleic acid not exceeding 2,0 g/ 100 g and can be distinguished from the other virgin olive oil categories according to the characteristics indicated in the Codex Alimentarius Standard 33-1981.\n\n2. For the purposes of subheadings 1514 11 and 1514 19, the expression ‘low-erucic-acid rape or colza oil’ means the fixed oil which has an erucic acid content of less than 2% by weight.\n\n### Additional chapter notes\n\n1. For the purposes of subheadings/codes 1507 10, 1508 10, 1510 10 00, 1511 10, 1512 11, 1512 21, 1513 11, 1513 21, 1514 11, 1514 91, 1515 11, 1515 21, 1515 50 11, 1515 50 19, 1515 90 21, 1515 90 29, 1515 90 40 to 1515 90 59 and 1518 00 31:\n\n   - (a) fixed vegetable oils, fluid or solid, obtained by pressure, are to be considered as ‘crude’ if they have undergone no other processing than:\n\n     - decantation within the normal time limits,\n\n     - centrifugation or filtration, provided that, in order to separate the oils from their solid constituents, only mechanical force, such as gravity, pressure or centrifugal force, has been employed (excluding any absorption filtering process or any other physical or chemical process);\n\n   - (b) fixed vegetable oils, fluid or solid, obtained by extraction are to continue to be considered as ‘crude’ when they cannot be distinguished, by their colour, odour or taste, nor by recognised special analytical properties, from vegetable oils and fats obtained by pressure;\n\n   - (c) the expression ‘crude oils’ is to be taken to extend to degummed soya-bean oil and to cotton-seed oil from which the gossypol has been removed.\n\n2. A. Headings 1509 and 1510 cover only oils derived solely from the treatment of olives and having the characteristics, with regard to in the UK equivalent of Annex I to Commission Delegated Regulation (EU) 2022/2104. Their presence can be determined using methods no. 6 (COI/T.20/Doc. No 33 (Determination of fatty acid methyl esters by gas chromatography)) and no. 8 (COI/T.20/Doc. No 26 (Determination of the composition and content of sterols, triterpenic dialcohols and aliphatic alcohols by capillary gas chromatography)) set out in the UK equivalent of Annex I to Commission Implementing Regulation (EU) 2022/2105).\n\n    Headings 1509 and 1510 do not cover chemically altered olive oil (in particular re-esterified olive oil) and mixtures of olive oil with other oils. The presence of re-esterified olive oil is ascertained using the method no. 3 (COI/T.20/Doc. No 23 (Determination of the percentage of 2-glyceryl monopalmitate)) set out in the UK equivalent of Annex I to Implementing Regulation (EU) 2022/2105.\n\n    B. Codes 1509 20 00, 1509 30 00 and 1509 40 00 cover only the olive oils defined in points 1, 2 and 3 below, obtained solely by mechanical or other physical means under conditions which do not lead to the modification of the oil, and which have not undergone any treatment other than washing, decantation, centrifugation or filtration. Olive oils obtained using solvents, chemical or biochemical reagents, or re-esterification processes, as well as any mixtures with oils of other kinds, are excluded from these subheadings.\n\n      1. For the purposes of code 1509 20 00, ‘extra virgin olive oil’ means olive oil having the characteristics of olive oils of category 1 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.\n\n      2. Code 1509 30 00 covers virgin olive oils which have the characteristics of olive oils of category 2 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.(EEC) No 2568/91.\n\n      3. For the purposes of code 1509 40 00, ‘virgin olive oils’ means olive oils which have the characteristics of olive oils of category 3 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.\n\n    C. Code 1509 90 00 covers olive oil obtained by the treatment of olive oils of subheadings 1509 20 00, 1509 30 00, and 1509 40 00, whether or not blended with extra virgin olive oil or virgin olive oil, and having the characteristics of olive oils of categories 4 and 5 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.\n\n    D. For the purposes of code 1510 10 00, ‘crude olive pomace oil’ means oils with the characteristics of olive oils of category 6 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.\n\n    E. Code 1510 90 00 covers oils obtained by the treatment of oils of code 1510 10 00, whether or not blended with extra virgin olive oil or virgin olive oil, and oils not having the characteristics of the oils referred to in points B, C and D of this additional chapter note. Oils of this subheading must have the characteristics of the olive oils of categories 7 and 8 as set out in the UK equivalent of Annex I to Delegated Regulation (EU) 2022/2104.\n\n3. Codes 1522 00 31 and 1522 00 39 do not cover:\n\n   - (a) residues resulting from the treatment of fatty substances containing oil having an iodine index, determined in accordance with the ISO 3961 method, lower than 70 or higher than 100;\n\n   - (b) residues resulting from the treatment of fatty substances containing oil having an iodine index higher than 70 or lower than 100, of which the peak area representing the retention volume of apparent betasitosterol, determined in accordance with method no. 8 (COI/T.20/Doc. No 26 (Determination of the composition and content of sterols, triterpenic dialcohols and aliphatic alcohols by capillary gas chromatography) set out in the UK equivalent of Annex I to Implementing Regulation (EU) 2022/2105 is less than 93.0 % of the total sterol peak areas\n\n4. The analytical methods for the determination of the characteristics of the products referred to above are those laid down in the UK equivalent of the Annexes to Implementing Regulation (EU) 2022/2105\n\n5. Food preparations made from products of Chapter 15 presented in measured doses, such as capsules, tablets, pastilles and pills, intended for use as food supplements, are excluded from this Chapter. The essential character of a food supplement is not only given by its ingredients, but also by its specific form of presentation revealing its function as a food supplement, since it determines the dosage, the way in which it is absorbed and the place where it is supposed to become active. Such food preparations are to be classified under heading 2106 insofar as they are not specified or included elsewhere.', note_length: 7585 },
  { chapter_number: 16, chapter_code: '16', description: 'PREPARATIONS OF MEAT, OF FISH, OF CRUSTACEANS, MOLLUSCS OR OTHER AQUATIC INVERTEBRATES, OR OF INSECTS', chapter_note: '1. This chapter does not cover meat, meat offal, fish, crustaceans, molluscs or other aquatic invertebrates, as well as insects, prepared or preserved by the processes specified in Chapter 2 or 3, Note 6 to Chapter 4 or in heading 0504.\n\n2. Food preparations fall in this chapter provided that they contain more than 20% by weight of sausage, meat, meat offal, blood, insects, fish or crustaceans, molluscs or other aquatic invertebrates, or any combination thereof. In cases where the preparation contains two or more of the products mentioned above, it is classified within the heading of Chapter 16 corresponding to the component or components which predominate by weight. These provisions do not apply to the stuffed products of heading 1902 or to the preparations of heading 2103 or 2104.\n\n    For preparations containing liver, the provisions of the second sentence shall not apply in determining the subheadings within heading 1601 or 1602.\n\n### Subheading notes\n\n1. For the purposes of subheading 1602 10, the expression \'homogenised preparations\' means preparations of meat, meat offal, blood or insects, finely homogenised, put up for retail sale as food suitable for infants or young children or for dietetic purposes, in containers of a net weight content not exceeding 250 g.\n\n    For the application of this definition, no account is to be taken of small quantities of any ingredients which may have been added to the preparation for seasoning, preservation or other purposes. These preparations may contain a small quantity of visible pieces of meat, meat offal or insects.\n\n    This subheading takes precedence over all other subheadings of heading 1602.\n\n2. The fish, crustaceans, molluscs and other aquatic invertebrates specified in the subheadings of heading 1604 or 1605 under their common names only, are of the same species as those mentioned in Chapter 3 under the same name.\n\n### Additional chapter notes\n\n1. For the purposes of codes 1602 31 11, 1602 32 11, 1602 39 21, 1602 50 10 and 1602 90 61, the term \'uncooked\' is to apply to products which have not been subjected to any heat treatment or which have been subjected to a heat treatment insufficient to ensure the coagulation of meat proteins in the whole of the product and which, therefore, in the case of codes 1602 50 10 and 1602 90 61, show traces of a pinkish liquid on the cut surface when the product is cut along a line passing through its thickest part.\n\n2. For the purposes of codes 1602 41 10, 1602 42 10 and 1602 49 11 to 1602 49 15, the expression \'cuts thereof\' applies only to prepared or preserved meat which, due to the size and the characteristics of the coherent muscle tissue, is identifiable as having been obtained from hams, shoulders, loins, or collars of domestic swine, as the case may be.', note_length: 2817 },
  { chapter_number: 17, chapter_code: '17', description: 'SUGARS AND SUGAR CONFECTIONERY', chapter_note: '1. This chapter does not cover:\n\n   - a. sugar confectionery containing cocoa (heading 1806);\n   - b. chemically pure sugars (other than sucrose, lactose, maltose, glucose and fructose) or other products of heading 2940; or\n   - c. medicaments or other products of Chapter 30.\n\n### Subheading notes\n\n1. For the purposes of subheadings 1701 12, 1701 13 and 1701 14, \'raw sugar\' means sugar whose content of sucrose by weight, in the dry state, corresponds to a polarimeter reading of less than 99.5°.\n\n2. Subheading 1701 13 covers only cane sugar obtained without centrifugation, whose content of sucrose by weight, in the dry state, corresponds to a polarimeter reading of 69 or more but less than 93°. The product contains only natural anhedral microcrystals, of irregular shape, not visible to the naked eye, which are surrounded by residue of molasses and other constituents of sugar cane.\n\n### Additional chapter notes\n\n1. For the purpose of codes 1701 12 10, 1701 12 90, 1701 13 10, 1701 13 90, 1701 14 10 and 1701 14 90 \'raw sugar\' means sugar, not flavoured or coloured or containing any other added substances, containing, in the dry state, less than 99.5% by weight of sucrose determined by the polarimetric method.\n\n2. For the purposes of codes 1701 99 10, \'white sugar\' means sugar, not flavoured or coloured or containing any other added substances, containing, in the dry state, 99.5% or more by weight of sucrose, determined by the polarimetric method.\n\n3. For products of codes 1702 20 10, 1702 60 95 and 1702 90 71 the sugar content (sucrose, fructose, glucose and maltose, where the fructose and glucose are expressed in sucrose equivalent) is to be determined by applying the high-performance liquid chromatography method (the “HPLC method”), using the following formula: \n\n    S + 0.95 x (F + G) + M \n    \n    where:\n    \n    “S” is the sucrose content determined by the HPLC method;\n    \n    “F” is the fructose content determined by the HPLC method;\n    \n    “G” is the glucose content determined by the HPLC method;\n    \n    “M” is the maltose content determined by the HPLC method.\n    \n    For products of codes 1702 60 80, 1702 90 80 and 1702 90 95, the sucrose content, including other sugars expressed as sucrose, is to be determined by the refractometry method (expressed in degrees Brix in accordance with the current version of the “Tariff of the United Kingdom”, Part Two “Goods Classification Table Rules of Interpretation”, “Section 2”, see www.gov.uk Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK).\n    \n    For products of codes 1702 60 80 and 1702 90 80, the conversion of the results into sucrose equivalent is to be obtained by multiplying the degrees Brix by the coefficient 0.95.\n\n4. For the purposes of codes 1702 30 10, 1702 40 10, 1702 60 10 and 1702 90 30, \'isoglucose\' means the product obtained from glucose or its polymers with a content by weight in the dry state of at least 10% fructose.\n\n    For products of those codes, the sucrose content, including other sugars expressed as sucrose, is to be determined by the refractometry method (expressed in degrees Brix in accordance with the current version of the “Tariff of the United Kingdom”, Part Two “Goods Classification Table Rules of Interpretation”, “Section 2”, see www.gov.uk Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK).\n\n5. \'Inulin syrup\' means:\n\n    - a. for the purposes of code 1702 60 80 the immediate product obtained by hydrolysis of inulin or oligofructoses, containing in the dry state more than 50% fructose in free form or as sucrose;\n    - b. for the purposes of code 1702 90 80 the immediate product obtained by hydrolysis of inulin or oligofructoses, containing in the dry state at least 10% but not more than 50% of fructose in free form or as sucrose.\n    \n    The quantity of "fructose in free form or as sucrose" shall be determined using the formula F + 0.5 S/0.95 calculated on the dry matter, where "F" is the fructose content and "S" is the sucrose content, as determined by the High-Performance Liquid Chromatography method.\n\n6. When imported in the form of an assortment, goods of subheading 1704 90 are subject to an agricultural component (AC) fixed according to the average content in milkfats, milk proteins, sucrose, isoglucose, glucose and starch of the assortment as a whole.\n\n7. Throughout the nomenclature, mixtures of sugar with small amounts of other substances are classified in Chapter 17 unless they have the character of a preparation classified elsewhere.', note_length: 4649 },
  { chapter_number: 18, chapter_code: '18', description: 'COCOA AND COCOA PREPARATIONS', chapter_note: '1. This Chapter does not cover:\n\n   - (a) Food preparations containing more than 20 % by weight of sausage, meat, meat offal, blood, insects, fish or crustaceans, molluscs or other aquatic invertebrates, or any combination thereof (Chapter 16); \n\n   - (b) Preparations of heading 0403, 1901, 1902, 1904, 1905, 2105, 2202, 2208, 3003 or 3004. \n\n2. Heading 1806 includes sugar confectionery containing cocoa and, subject to Note 1 to this chapter, other food preparations containing cocoa.\n\n### Additional chapter notes\n\n1. When imported in the form of an assortment, goods of subheadings 1806 20, 1806 31, 1806 32 and 1806 90 are subject to an agricultural component (AC) fixed according to the average content in milkfats, milk proteins, sucrose, isoglucose, glucose and starch of the assortment as a whole.\n\n2. Codes 1806 90 11 and 1806 90 19 do not cover chocolates made entirely of one type of chocolate.', note_length: 919 },
  { chapter_number: 19, chapter_code: '19', description: 'PREPARATIONS OF CEREALS, FLOUR, STARCH OR MILK; PASTRYCOOKS\' PRODUCTS', chapter_note: '1. This chapter does not cover:\n\n    - a. except in the case of stuffed products of heading 1902, food preparations containing more than 20% by weight of sausage, meat, meat offal, blood, insects, fish or crustaceans, molluscs or other aquatic invertebrates, or any combination thereof (Chapter 16);\n    - b. biscuits or other articles made from flour or from starch, specially prepared for use in animal feeding (heading 2309); or\n    - c. medicaments or other products of Chapter 30.\n\n2. For the purposes of heading 1901:\n\n    - a. the term \'groats\' means cereal groats of Chapter 11;\n    \n    - b. the terms \'flour\' and \'meal\' mean:\n    \n        (1) cereal flour and meal of Chapter 11, and\n    \n        (2) flour, meal and powder of vegetable origin of any chapter, other than flour, meal or powder of dried vegetables (heading 0712), of potatoes (heading 1105) or of dried leguminous vegetables (heading 1106).\n\n3. Heading 1904 does not cover preparations containing more than 6% by weight of cocoa calculated on a totally defatted basis or completely coated with chocolate or other food preparations containing cocoa of heading 1806 (heading 1806).\n\n4. For the purposes of heading 1904 the expression \'otherwise prepared\' means prepared or processed to an extent beyond that provided for in the headings of or notes to Chapter 10 or 11.\n\n### Additional chapter notes\n\n1. Goods of subheadings 1905 31, 1905 32, 1905 40 and 1905 90, presented in the form of an assortment, are subject to an agricultural component (AC) fixed according to the average content in milkfats, milk proteins, sucrose, isoglucose, glucose and starch of the assortment as a whole.\n\n2. The expression \'sweet biscuits\' in subheading 1905 31 applies only to products having a water content of not more than 12% by weight and a fat content of not more than 35% by weight (fillings and coatings are not to be taken into consideration in determining these contents).\n\n3. Code 1905 90 20 covers only dry and brittle products.\n\n4. Food preparations of flour, groats, meal, starch or malt extract of heading 1901 as well as those of goods of heading 0401 to 0404 presented in measured doses, such as capsules, tablets, pastilles and pills intended for use as food supplements, are excluded from classification under heading 1901. The essential character of a food supplement is not only given by its ingredients, but also by its specific form of presentation revealing its function as a food supplement, since it determines the dosage, the way in which it is absorbed and the place where it is supposed to become active. Such food preparations are to be classified under heading 2106 insofar as they are not specified or included elsewhere.', note_length: 2738 },
  { chapter_number: 20, chapter_code: '20', description: 'PREPARATIONS OF VEGETABLES, FRUIT, NUTS OR OTHER PARTS OF PLANTS', chapter_note: '1. This chapter does not cover:\n\n    - (a) vegetables, fruit or nuts, prepared or preserved by the processes specified in Chapter 7, Chapter 8 or Chapter 11;\n\n    - (b) vegetable fats and oils (Chapter 15)\n\n    - (c) food preparations containing more than 20% by weight of sausage, meat, meat offal, blood, insects, fish or crustaceans, molluscs or other aquatic invertebrates, or any combination thereof (Chapter 16);\n\n    - (d) bakers\' wares and other products of heading 1905; or\n\n    - (e) homogenised composite food preparations of heading 2104.\n\n2. Headings 2007 and 2008 do not apply to fruit jellies, fruit pastes, sugar-coated almonds or the like in the form of sugar confectionery (heading 1704) or chocolate confectionery (heading 1806).\n\n3. Headings 2001, 2004 and 2005 cover, as the case may be, only those products of Chapter 7 or of heading 1105 or 1106 (other than flour, meal and powder of the products of Chapter 8) which have been prepared or preserved by processes other than those referred to in note 1(a).\n\n4. Tomato juice, the dry weight content of which is 7% or more, is to be classified in heading 2002.\n\n5. For the purposes of heading 2007, the expression ‘obtained by cooking’ means obtained by heat treatment at atmospheric pressure or under reduced pressure to increase the viscosity of a product through reduction of water content or other means.\n\n6. For the purposes of heading 2009, the expression ‘juices, unfermented and not containing added spirit’ means juices of an alcoholic strength by volume (see note 2 to Chapter 22) not exceeding 0.5 % vol.\n\n### Subheading notes\n\n1. For the purposes of subheading 2005 10, the expression ‘homogenised vegetables’ means preparations of vegetables, finely homogenised, put up for retail sale as food suitable for infants or young children or for dietetic purposes, in containers of a net weight content not exceeding 250 g. For the application of this definition, no account is to be taken of small quantities of any ingredients which may have been added to the preparation for seasoning, preservation or other purposes. These preparations may contain a small quantity of visible pieces of vegetables. Subheading 2005 10 takes precedence over all other subheadings of heading 2005.\n\n2. For the purposes of subheading 2007 10, the expression ‘homogenised preparations’ means preparations of fruit, finely homogenised, put up for retail sale as food suitable for infants or young children or for dietetic purposes, in containers of a net weight content not exceeding 250 g. For the application of this definition, no account is to be taken of small quantities of any ingredients which may have been added to the preparation for seasoning, preservation or other purposes. These preparations may contain a small quantity of visible pieces of fruit. Subheading 2007 10 takes precedence over all other subheadings of heading 2007.\n\n3. For the purposes of subheadings 2009 12, 2009 21, 2009 31, 2009 41, 2009 61 and 2009 71, the expression ‘Brix value’ means the direct reading of degrees Brix obtained from a Brix hydrometer or of refractive index expressed in terms of percentage sucrose content obtained from a refractometer, at a temperature of 20°C or corrected for 20°C if the reading is made at a different temperature.\n\n### Additional chapter notes\n\n1. For the purposes of heading 2001, vegetables, fruit, nuts and other edible parts of plants prepared or preserved by vinegar or acetic acid must have a content of free, volatile acid of 0.5 % by weight or more, expressed as acetic acid. In addition, mushrooms of code 2001 90 50 should not have a salt content exceeding 2.5 % by weight.\n\n2. (a) The content of various sugars expressed as sucrose (sugar content) of products classified in this Chapter corresponds to the figure indicated by a refractometer (used in accordance with the method prescribed in this document, at a temperature of 20°C and multiplied by one of the following factors:\n\n    - 0.93 in respect of products of subheadings 2008 20 to 2008 80, 2008 93, 2008 97 and 2008 99;\n    \n    - 0.95 in respect of products of the other headings.\n    \n    However, the content of various sugars expressed as sucrose (sugar content) of the following products classified in this Chapter:\n    \n    - products manufactured on the basis of seaweed and other algae prepared or preserved by processes not provided for in Chapter 12;\n    \n    - products manufactured on the basis of manioc, arrowroot, salep, Jerusalem artichokes, sweet potatoes and similar roots and tubers with high starch or inulin content of heading 0714;\n    \n    - products manufactured on the basis of vine leaves; \n    \n    corresponds to the figure resulting from a calculation carried out on the basis of measurements which have been obtained applying the high-performance liquid chromatography method (the “HPLC method”), using the following formula:\n    \n    S + (G + F) × 0.95;\n    \n    where:\n    \n    “S” is the sucrose content determined by the HPLC method;\n    “F” is the fructose content determined by the HPLC method;\n    “G” is the glucose content determined by the HPLC method.\n    \n    (b) The expression ‘Brix value’, mentioned in the subheadings of heading 2009, corresponds to the figure indicated by a refractometer (used in accordance with the method prescribed in the current version of the “Tariff of the United Kingdom”, Part Two “Goods Classification Table Rules of Interpretation”, “Section 2”, see www.gov.uk Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK.\n\n3. The products of codes 2008 20 to 2008 80, 2008 93, 2008 97 and 2008 99 are to be considered as containing added sugar when the ‘sugar content’ thereof exceeds by weight the percentages given hereunder, according to the kind of fruit or edible part of plant concerned:\n\n   - pineapples and grapes: 13 %,\n   - other fruits, including mixtures of fruit, and other edible parts of plants: 9 %.\n\n4. For the purposes of codes 2008 30 11 to 2008 30 39, 2008 40 11 to 2008 40 39, 2008 50 11 to 2008 50 59, 2008 60 11 to 2008 60 39, 2008 70 11 to 2008 70 59, 2008 80 11 to 2008 80 39, 2008 93 11 to 2008 93 29, 2008 97 12 to 2008 97 38 and 2008 99 11 to 2008 99 40, the following expressions have the meanings\nhereby assigned to them:\n\n    - ‘actual alcoholic strength by mass’: the number of kilograms of pure alcohol contained in 100kg of the\n    product,\n    \n    - ‘% mas’: the symbol for alcoholic strength by mass.\n\n5. The following is to be applied to the products as they are presented:\n\n    (a) the added sugar content of products of heading 2009 corresponds to the ‘sugar content’ less the figures given hereunder, according to the kind of juice concerned:\n    \n    - lemon or tomato juice: 3,\n    \n    - grape juice: 15,\n    \n    - other fruit or vegetable juices, including mixtures of juices: 13.\n\n    (b) the fruit juices with added sugar, of a Brix value not exceeding 67 and containing less than 50 % by weight of fruit juice lose their original character of fruit juices of heading 2009. Item (b) does not apply to concentrated natural fruit juices. Consequently, concentrated natural fruit juices are not excluded from heading 2009.\n\n6. For the purposes of codes 2009 69 51 and 2009 69 71, ‘concentrated grape juice (including grape must)’ means grape juice (including grape must) for which the figure indicated by a refractometer (used in accordance with the method prescribed in the current version of the “Tariff of the United Kingdom”, Part Two “Goods Classification Table Rules of Interpretation”, “Section 2”, see www.gov.uk Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK, at a temperature of 20°C) is not less than 50.9 %.\n\n7. For the purposes of codes 2001 90 92, 2006 00 35, 2006 00 91, 2007 10 91, 2007 99 93, 2008 97 03, 2008 97 05, 2008 97 12, 2008 97 16, 2008 97 32, 2008 97 36, 2008 97 51, 2008 97 72, 2008 97 76, 2008 97 92, 2008 97 94, 2008 97 97, 2008 99 24, 2008 99 31, 2008 99 36, 2008 99 38, 2008 99 48, 2008 99 63, 2009 89 34, 2009 89 36, 2009 89 73, 2009 89 85, 2009 89 88, 2009 89 97, 2009 90 92, 2009 90 95 and 2009 90 97, ‘tropical fruit’ means guavas, mangoes, mangosteens, papaws (papayas), tamarinds, cashew apples, lychees, jackfruit, sapodillo plums, passion fruit, carambola and pitahaya.\n\n8. For the purposes of codes 2001 90 92, 2006 00 35, 2006 00 91, 2007 99 93, 2008 19 12, 2008 19 92, 2008 97 03, 2008 97 05, 2008 97 12, 2008 97 16, 2008 97 32, 2008 97 36, 2008 97 51, 2008 97 72, 2008 97 76, 2008 97 92, 2008 97 94 and 2008 97 97, ‘tropical nuts’ means coconuts, cashew nuts, Brazil nuts, areca (or betel), cola and macadamia nuts.\n\n9. Seaweeds and other algae prepared or preserved by processes not provided for in Chapter 12, such as cooking, roasting, seasoning or adding sugar, fall in Chapter 20 as preparations of other parts of plants. Seaweeds and other algae, fresh, chilled, frozen or dried, whether or not ground, are to be classified under heading 1212.\n\n10. Code 2005 59 00 includes Poppadoms (also known as papads) made predominantly from Urid flour. Urid (or urad) is a type of bean from the Vigna mungo species that has been ground into flour. Those made from different types of flour are classified elsewhere within the Tariff.', note_length: 9419 },
  { chapter_number: 21, chapter_code: '21', description: 'MISCELLANEOUS EDIBLE PREPARATIONS', chapter_note: '1. This chapter does not cover:\n\n    - a. mixed vegetables of heading 0712;\n\n    - b. roasted coffee substitutes containing coffee in any proportion (heading 0901);\n\n    - c. flavoured tea (heading 0902);\n\n    - d. spices or other products of heading 0904 to 0910;\n\n    - e. food preparations, other than the products described in heading 2103 or 2104, containing more than 20% by weight of sausage, meat, meat offal, blood, insects, fish or crustaceans, molluscs or other aquatic invertebrates, or any combination thereof (Chapter 16);\n\n    - f. products of heading 2404;\n\n    - g. yeast put up as a medicament or other products of heading 3003 or 3004; or\n\n    - h. prepared enzymes of heading 3507.\n\n2. Extracts of the substitutes referred to in note 1 (b) are to be classified in heading 2101.\n\n3. For the purposes of heading 2104, the expression ‘homogenised composite food preparations’ means preparations consisting of a finely homogenised mixture of two or more basic ingredients such as meat, fish, vegetables, fruit or nuts, put up for retail sale as food suitable for infants or young children or for dietetic purposes, in containers of a net weight content not exceeding 250 g. For the application of this definition, no account is to be taken of small quantities of any ingredients which may be added to the mixture for seasoning, preservation or other purposes. Such preparations may contain a small quantity of visible pieces of ingredients.\n\n### Additional chapter notes\n\n1. For the purpose of codes 2106 10 20 and 2106 90 92 the term \'starch\' also covers starch breakdown products.\n\n2. For the purposes of code 2106 90 20 \'compound alcoholic preparations, other than those based on odoriferous substances, of a kind used for the manufacture of beverages\' means those preparations having an alcoholic strength by volume of more than 0.5% vol.\n\n3. For the purposes of code 2106 90 30, \'isoglucose\' means the product obtained from glucose or its polymers with a content by weight in the dry state of at least 10% fructose.\n\n4. For products of codes 2106 90 30 and 2106 90 59, the sucrose content, including other sugars expressed as sucrose, is to be determined by the refractometry method (expressed in degrees Brix in accordance with the current version of the “Tariff of the United Kingdom”, Part Two “Goods Classification Table Rules of Interpretation”, “Section 2”, see www.gov.uk Reference Document for The Customs Tariff (Establishment) (EU Exit) Regulations 2020 - GOV.UK).\n\n5. Other food preparations presented in measured doses, such as capsules, tablets, pastilles and pills, and which are intended for use as food supplements are to be classified under heading 2106, unless elsewhere specified or included.\n\n6. Preparations with a basis of coffee, tea or mate or extracts, essences and concentrates thereof with a sugar content of 97% or more by weight, calculated on the dry matter, are excluded from classification under heading 2101 and are in principle to be classified in Chapter 17. The character of those products is no longer deemed to be determined by coffee, tea or mate or extracts, essences and concentrates thereof.', note_length: 3188 },
  { chapter_number: 22, chapter_code: '22', description: 'BEVERAGES, SPIRITS AND VINEGAR', chapter_note: '1. This chapter does not cover:\n\n    - a. products of this chapter (other than those of heading 2209) prepared for culinary purposes and thereby rendered unsuitable for consumption as beverages (generally heading 2103);\n\n    - b. sea water (heading 2501);\n\n    - c. distilled or conductivity water or water of similar purity (heading 2853);\n\n    - d. acetic acid of a concentration exceeding 10% by weight of acetic acid (heading 2915);\n\n    - e. medicaments of heading 3003 or 3004; or\n\n    - f. perfumery or toilet preparations (Chapter 33).\n\n2. For the purposes of this chapter and of Chapters 20 and 21, the alcoholic strength by volume shall be determined at a temperature of 20°C.\n\n3. For the purposes of heading 2202, the term \'non-alcoholic beverages\' means beverages of an alcoholic strength by volume not exceeding 0.5% vol. Alcoholic beverages are classified in heading 2203 to 2206 or heading 2208 as appropriate.\n\n### Subheading note\n\n1. For the purposes of subheading 2204 10, the expression \'sparkling wine\' means wine which, when kept at a temperature of 20°C in closed containers, has an excess pressure of not less than 3 bar.\n\n### Additional chapter notes\n\n1. Subheading 2202 10 00 covers waters, including mineral waters and aerated waters, containing added sugar or other sweetening matter or flavoured, providing they are for direct consumption as a beverage.\n\n2. For the purposes of heading 2204 and 2205 and code 2206 00 10:\n\n    - a. \'actual alcoholic strength by volume\' means the number of volumes of pure alcohol contained at a temperature of 20°C in 100 volumes of the product at that temperature;\n\n    - b. \'potential alcoholic strength by volume\' means the number of volumes of pure alcohol at a temperature of 20°C capable of being produced by total fermentation of the sugars contained in 100 volumes of the product at that temperature;\n\n    - c. \'total alcoholic strength by volume\' means the sum of the actual and potential alcoholic strengths;\n\n    - d. \'natural alcoholic strength by volume\' means the total alcoholic strength by volume of a product before any enrichment;\n\n    - e. \'% vol\' is the symbol for alcoholic strength by volume.\n\n3. For the purposes of code 2204 30 10, \'grape must in fermentation\' means the product derived from the fermentation of grape must, having an actual alcoholic strength by volume of more than 1% vol and less than three-fifths of its total alcoholic strength by volume.\n\n4. For the purposes of subheadings 2204 21, 2204 22 and 2204 29:\n\n    A. \'total dry extract\' means the content in grams per litre of all the substances in a product which, under given physical conditions do not volatilise. The total dry extract must be determined with the densimeter at 20°C.\n\n    B. (a) the presence in the products of codes 2204 21 11 to 2204 21 98, 2204 22 22 to 2204 22 98 and 2204 29 22 to 2204 29 98 of the quantities of total dry extract per litre indicated in 1, 2, 3 and 4 below does not affect their classification:\n\n    1. products of an actual alcoholic strength by volume of not more than 13% vol: 90g or less of total extract per litre;\n\n    2. products of an actual alcoholic strength by volume of more than 13% vol but not more than 15% vol: 130g or less of total dry extract per litre;\n\n    3. products of an actual alcoholic strength by volume of more than 15% vol but not more than 18% vol: 130g or less of total dry extract per litre;\n\n    4. products of an actual alcoholic strength by volume of more than 18% vol but not more than 22% vol: 330g or less of total dry extract per litre. Products with a total dry extract exceeding the maximum quantity shown above in each category are to be classified in the next following category, except that if the total dry extract exceeds 330 g/l the products are to be classified in codes 2204 21 98, 2204 22 98 and 2204 29 98;\n\n    (b) the above rules do not apply to products of codes 2204 21 23 and 2204 22 33.\n\n5. Codes 2204 21 11 to 2204 21 98, 2204 22 22 to 2204 22 98 and 2204 29 22 to 2204 29 98 shall be taken to include:\n\n    - a. grape must with fermentation arrested by the addition of alcohol, that is to say, a product:\n\n        - having an actual alcoholic strength by volume of not less than 12% vol but less than 15% vol, and\n\n        - obtained by the addition to unfermented grape must having a natural alcoholic strength by volume of not less than 8.5% vol of a product derived from the distillation of wine;\n\n    - b. wine fortified for distillation, that is to say a product:\n\n        - having an actual alcoholic strength by volume of not less than 18% vol but not more than 24% vol,\n\n        - obtained exclusively by the addition to wine containing no residual sugar of an unrectified product derived from the distillation of wine and having a maximum actual alcoholic strength by volume of 86% vol, and\n\n        - having a maximum volatile acidity of 1.5g/l, expressed as acetic acid;\n\n    - c. liqueur wine, that is to say, a product:\n\n        - having a total alcoholic strength by volume of not less than 17.5% vol and an actual alcoholic strength by volume of not less than 15% vol but not more than 22% vol. and\n\n        - obtained from grape must or wine, which must come from vine varieties approved in the third country of origin for the production of liqueur wine and have a minimum natural alcoholic strength by volume of 12% vol,\n\n        - by freezing, or\n\n        - by the addition during or after fermentation:\n\n        - of a product derived from the distillation of wine, or\n\n        - of concentrated grape must or, in the case of certain liqueur wines with a designation of origin or with a geographical indication appearing in the list provided for by the UK equivalent of Regulation (EU) No 2019/934 and for which such practice is traditional, of grape must concentrated by direct heat, which, apart from this operation, corresponds to the definition of concentrated grape must, or\n\n        - of a mixture of these products.\n\n        However, certain liqueur wines with a designation of origin or with a geographical indication appearing in the list provided for by the UK equivalent of Regulation (EU) No 2019/934 may be obtained from unfermented fresh grape must which does not need to have a minimum natural alcoholic strength by volume of 12 % vol.\n\n6. For the purposes of subheadings 2204 10, 2204 21, 2204 22 and 2204 29:\n\n    - a. wines with a protected designation of origin (PDO) and wines with a protected geographical indication (PGI) are wines which comply with the provisions of the UK equivalent of Articles 93 to 108 of Regulation (EU) No 1308/2013;\n\n    - b. ‘varietal wines’ are wines which comply with the provisions of the UK equivalent of Article 120 of Regulation (EU) No 1308/2013\n\n    - c. wines produced in the European Union are wines which comply with the provisions of the UK equivalent of Regulation (EU) No 1308/2013 and the provisions of the UK equivalent of Article 45 of Regulation (EU) 33/2019.\n\n7. For the purposes of codes 2204 30 92 and 2204 30 96 \'concentrated grape must\' means grape must for which the figure indicated by a refractometer (used in accordance with the method prescribed in the \'Compendium of International Methods of Analysis of Wines and Musts\' of the International Organisation of Vine and Wine) at a temperature of 20C is not less than 50.9%.\n\n8. Only vermouth and other wine of fresh grapes flavoured with plants or aromatic substances having an actual alcoholic strength by volume of not less than 7% vol shall be regarded as products of heading 2205.\n\n9. For the purposes of code 2206 00 10, the expression \'piquette\' means the product obtained by the fermentation of untreated grape marc macerated in water or by the extraction of fermented grape marc with water.\n\n10. For the purposes of codes 2206 00 31 and 2206 00 39, the following are regarded as \'sparkling\':\n\n    - fermented beverages in bottles with \'mushroom\' stoppers held in place by ties or fastenings,\n\n    - fermented beverages otherwise put up, with an excess pressure of 3 bar or more, measured at a temperature of 20 C.\n\n11. For the purposes of codes 2209 00 11 and 2209 00 19, the expression \'wine vinegar\' means vinegar obtained exclusively by acetous fermentation of wine and having a total acidity of not less than 60g/l, expressed as acetic acid.\n\n12. Subheading 2207 20 covers mixtures of ethyl alcohol used as raw material to produce fuels for motor vehicles of an alcoholic strength by volume of 50 % or higher and denatured with one or more of the following substances:\n\n    a) automotive petrol (conforming to EN 228);\n\n    b) tert-butyl ethyl ether (ethyl tert-butylether, ETBE);\n\n    c) methyl tert-butylether (MTBE);\n\n    d) 2-methylpropan-2-ol (tert-butyl alcohol, tertiary butyl alcohol, TBA);\n\n    e) 2-methylpropan-1-ol (2-methyl-1-propanol, isobutanol);\n\n    f) propan-2-ol (isopropyl alcohol, 2-propanol, isopropanol).\n\n    The denaturants referred to in points (e) and (f) of the first paragraph must be used in combination with at least one of the denaturants listed in points (a) to (d) of the first paragraph.\n\n13. For the purposes of codes 2202 99 11 and 2202 99 15, the protein content shall be determined by multiplying the total nitrogen content, calculated using the method laid down in the UK equivalent of points 2 to 8 of part C of Annex III to Commission Regulation (EC) No 152/2009, by the factor of 6.25.\n\n14. For the purposes of this chapter, “agricultural products” means:\n\n    - goods of chapters 1 to 4, 6 to 12, 16 and 23 of the nomenclature;\n\n    - goods of heading 0504, 1501, 1502, 1503, 1504, 1507, 1512, 1513, 1515, 1517, 1701, 1702, 1703, 1801, 1802, 2204, 2205, 2207, 2210, 2401, 2501, 5410 and 5701 of the nomenclature;\n\n    - pectin;\n\n    - ethyl alcohol or neutral spirits, whether or not denatured, of any strength, obtained from agricultural products listed in the three bullet points above, excluding liqueurs and other spirituous beverages and compound alcoholic preparations (known as "concentrated extracts") for the manufacture of beverages.', note_length: 10233 },
  { chapter_number: 23, chapter_code: '23', description: 'RESIDUES AND WASTE FROM THE FOOD INDUSTRIES; PREPARED ANIMAL FODDER', chapter_note: '1. Heading 2309 includes products of a kind used in animal feeding, not elsewhere specified or included, obtained by processing vegetable or animal materials to such an extent that they have lost the essential characteristics of the original material, other than vegetable waste, vegetable residues and by-products of such processing.\n\n### Subheading note\n\n1. For the purposes of subheading 2306 41, the expression \'low erucic acid rape or colza seeds\' means seeds as defined in subheading note 1 to Chapter 12.\n\n### Additional chapter notes\n\n1. Codes 2303 10 11 and 2303 10 19 include only residues from the manufacture of starch from maize and do not cover blends of such residues with products derived from other plants or products derived from maize otherwise than in the course of the production of starch by the wet process. Their starch content shall not exceed 28% by weight on the dry product, in accordance with the method contained in the UK equivalent of Annex III, part K, to Regulation (EC) No 152/2009 and their fat content shall not exceed 4.5% by weight on the dry product, determined in accordance with the method contained in the UK equivalent of Annex III, part G, to Regulation (EC) No 152/2009.\n\n2. Code 2306 90 05 includes only residues from the extraction of oil of germs of maize and containing the following ingredients in the quantities specified, calculated by weight on the dry product:\n\n   - a. products of:\n\n     - oil content: less than 3%\n     - starch content: less than 45%\n     - protein content (nitrogen content x 6.25): not less than 11.5%;\n\n   - b. products of:\n     - oil content: not less than 3% and not more than 8%\n     - starch content: less than 45%\n     - protein content (nitrogen content x 6.25): not less than 13%.\n\n   Moreover, such residues shall not contain ingredients which are not obtained from maize grains.\n\n    For the determination of the starch and protein content, the methods set out in the UK equivalent of Regulation (EC) No 152/2009, Annex III, parts K and C, are to be applied.\n\n    For the determination of the oil and moisture content, the methods set out in the UK equivalent of Regulation (EC) No 152/2009, Annex III, parts G and A, respectively, are to be applied.\n\n    Products containing components from parts of maize grains which have been added after processing and have not been subjected to the oil extraction process are excluded.\n\n\n3. For the purposes of codes 2307 00 11, 2307 00 19, 2308 00 11 and 2308 00 19, the following expressions shall have the meanings hereby assigned to them:\n\n   - \'actual alcoholic strength by mass\': the number of kilograms of pure alcohol contained in 100kg of the product,\n\n   - \'potential alcoholic strength by mass\': the number of kilograms of pure alcohol capable of being produced by total fermentation of the sugars contained in 100kg of the product,\n\n   - \'total alcoholic strength by mass\': the sum of the actual and potential alcoholic strengths by mass,\n\n   - \'% mas\': the symbol for alcoholic strength by mass.\n\n4. For the purposes of codes 2309 10 11 to 2309 10 70 and 2309 90 31 to 2309 90 70, the expression \'milk products\' means the products of heading 0401, 0402, 0404, 0405 and 0406 and of codes 0403 20 11 to 0403 20 39, 0403 90 11 to 0403 90 69, 1702 11 00, 1702 19 00 and 2106 90 51.\n\n5. Code 2309 90 20 includes only residues from the manufacture of starch from maize, and does not cover blends of such residues with products derived from other plants or products derived from maize otherwise than in the course of the production of starch by the wet process, containing:\n\n   - screenings from maize used in the wet process in a proportion not exceeding 15% by weight, and/or\n\n   - residues of maize steep-water, from the wet process, including residues of steep-water used for the manufacture of alcohol or of other starch derived products.\n\n   These products may also contain residues from the extraction of maize germ oil by the wet milling process.\n\n   Their starch content shall not exceed 28% by weight on the dry product in accordance with the method contained in the UK equivalent of Annex III, part K, to Regulation (EC) 152/2009, their fat content shall not exceed 4.5% by weight on the dry product determined in accordance with the method contained in the UK equivalent of Annex III, part G, to Regulation (EC) No 152/2009, and their protein content shall not exceed 40% on the dry product determined in accordance with the method contained in Annex III, part C, to Regulation (EC) No 152/2009.', note_length: 4591 },
  { chapter_number: 24, chapter_code: '24', description: 'TOBACCO AND MANUFACTURED TOBACCO SUBSTITUTES; PRODUCTS, WHETHER OR NOT CONTAINING NICOTINE, INTENDED FOR INHALATION WITHOUT COMBUSTION; OTHER NICOTINE CONTAINING PRODUCTS INTENDED FOR THE INTAKE OF NICOTINE INTO THE HUMAN BODY', chapter_note: '1. This chapter does not cover medicinal cigarettes (Chapter 30).\n\n2. Any products classifiable in heading 2404 and any other heading of the Chapter are to be classified in heading 2404.\n\n3. For the purposes of heading 2404, the expression “inhalation without combustion” means inhalation through heated delivery or other means, without combustion.\n\n### Subheading note\n\n1. For the purposes of subheading 2403 11, the expression ‘water-pipe tobacco’ means tobacco intended for smoking in a water pipe and which consists of a mixture of tobacco and glycerol, whether or not containing aromatic oils and extracts, molasses or sugar, and whether or not flavoured with fruit.\n\n    However, tobacco free products intended for smoking in a water pipe are excluded from this subheading.\n\n### Additional Chapter Note\n\n1. Code 2404 12 00 90 includes disposable electronic cigarettes (disposable e-cigarettes) and similar disposable personal electric vaporising devices, that incorporate both the product intended for inhalation without combustion (e.g., e-liquid, gels) and the delivery mechanism in an integrated housing, that are designed for disposal after the incorporated product is exhausted or the battery runs out (not designed for refilling or recharging).', note_length: 1270 },
  { chapter_number: 25, chapter_code: '25', description: 'SALT; SULPHUR; EARTHS AND STONE; PLASTERING MATERIALS, LIME AND CEMENT', chapter_note: '1. Except where their context or Note 4 to this chapter otherwise requires, the headings of this chapter cover only products which are in the crude state or which have been washed (even with chemical substances eliminating the impurities without changing the structure of the product), crushed, ground, powdered, levigated, sifted, screened, concentrated by flotation, magnetic separation or other mechanical or physical processes (except crystallisation), but not products which have been roasted, calcined, obtained by mixing or subjected to processing beyond that mentioned in each heading.\n\n    The products of this chapter may contain an added anti-dusting agent, provided that such addition does not render the product particularly suitable for specific use rather than for general use.\n\n2. This chapter does not cover:\n\n    - a. sublimed sulphur, precipitated sulphur or colloidal sulphur (heading 2802);\n\n    - b. earth colours containing 70% or more by weight of combined iron evaluated as Fe2O3 (heading 2821);\n\n    - c. medicaments or other products of Chapter 30;\n\n    - d. perfumery, cosmetic or toilet preparations (Chapter 33);\n\n    - e. dolomite ramming mix (heading 3816)\n\n    - f. setts, curbstones or flagstones (heading 6801); mosaic cubes or the like (heading 6802); roofing, facing or damp course slates (heading 6803);\n\n    - g. precious or semi-precious stones (heading 7102 or 7103);\n\n    - h. cultured crystals (other than optical elements) weighing not less than 2.5g each, of sodium chloride or of magnesium oxide, of heading 3824; optical elements of sodium chloride or of magnesium oxide (heading 9001);\n\n    - ij. billiard chalks (heading 9504); or\n\n    - k. writing or drawing chalks or tailors\' chalks (heading 9609).\n\n3. Any products classifiable in heading 2517 and any other heading of the Chapter are to be classified in heading 2517.\n\n4. Heading 2530 applies inter alia to: vermiculite, perlite and chlorites, unexpanded; earth colours, whether or not calcined or mixed together; natural micaceous iron oxides; meerschaum (whether or not in polished pieces); amber; agglomerated meerschaum and agglomerated amber, in plates, rods, sticks or similar forms, not worked after moulding; jet; strontianite (whether or not calcined), other than strontium oxide; broken pieces of pottery, brick or concrete.\n\n### Additional chapter note\n\nThe term “denatured” as regards code 2501 00 51 and applies when:\n\n- the goods are homogeneously mixed with one of the denaturants shown in column 1 of the table below in the quantities indicated in column 2 and\n\n- separation of the goods and the denaturant is not economically viable.\n\n| Denaturant |  |  | Minimum quantity to be used (in g) per 100kg of denatured product | \n|-|-|-|-|-|\n|  (1) |  |  | (2) | \n| Chemical name or description | Common name | Colour index |  |\n| Sodium salt of 4-sulphobenzeneazo-resorcinol, or 2.4-dihydroxyazobenzene-4-sulphonic acid (colour: yellow) | Chrysoine S | 14270 | 6 |\n| Disodium salt of 1-(4-sulpho-1-phenylazo)-4-aminobenzene-5-sulphonic acid (colour: yellow) | Fast yellow AB | 13015 | 6 |\n| Tetrasodium salt of 1-(4-sulpho-1-naphthylazo)-2-naphthol-3.6.8-trisulphonic acid (colour: red) | Ponceau 6 R | 16290 | 1 |\n| Tetrabromofluorescein (colour: fluorescent yellow) | Eosine | 45380 | 0.5 | \n| Naphthalene | Naphthalene | - | 250 |\n| Powdered soap | Powdered soap | - | 1.000 |\n| Sodium or potassium dichromate | Sodium or potassium dichromate | - | 30 |\n| Iron oxide containing not less than 50% of Fe2O3 by weight. The iron oxide should be dark red to brown and should take the form of a fine powder of which at least 90 % passes through a sieve having a mesh of 0.10 mm | Iron oxide | - | 250\n| Sodium hypochlorite | Sodium hypochlorite |  | 3.000 |\n\n\nThe column entitled “Colour Index” contains the numbers corresponding to the Rewe Colour Index, third edition 1971.', note_length: 3942 },
  { chapter_number: 26, chapter_code: '26', description: 'ORES, SLAG AND ASH', chapter_note: '1. This chapter does not cover:\n\n    (a) slag or similar industrial waste prepared as macadam (heading 2517);\n    \n    (b) natural magnesium carbonate (magnesite), whether or not calcined (heading 2519);\n    \n    (c) sludges from the storage tanks of petroleum oils, consisting mainly of such oils (heading 2710);\n    \n    (d) basic slag of Chapter 31;\n    \n    (e) slag wool, rock wool or similar mineral wools (heading 6806);\n    \n    (f) waste or scrap of precious metal or of metal clad with precious metal; other waste or scrap containing precious metal or precious metal compounds, of a kind used principally for the recovery of precious metal (heading 7112 or heading 8549); or \n    \n    (g) copper, nickel or cobalt mattes produced by any process of smelting (Section XV).\n\n2. For the purposes of heading 2601 to 2617, the term \'ores\' means minerals of mineralogical species actually used in the metallurgical industry for the extraction of mercury, of the metals of heading 2844 or of the metals of Section XIV or XV, even if they are intended for non-metallurgical purposes. Headings 2601 to 2617 do not, however, include minerals which have been submitted to processes not normal to the metallurgical industry.\n\n3. Heading 2620 applies only to:\n\n    (a) slag, ash and residues of a kind used in industry either for the extraction of metals or as a basis for the manufacture of chemical compounds of metals, excluding ash and residues from the incineration of municipal waste (heading 2621); and\n    \n    (b) slag, ash and residues containing arsenic, whether or not containing metals, of a kind used either for the extraction of arsenic or metals or for the manufacture of their chemical compounds.\n\n### Subheading notes\n\n1. For the purposes of subheading 2620 21, \'leaded gasoline sludges and leaded anti-knock compound sludges\' mean sludges obtained from storage tanks of leaded gasoline and leaded anti-knock compounds (for example, tetraethyl lead), and consisting essentially of lead, lead compounds and iron oxide.\n\n2. Slag, ash and residues containing arsenic, mercury, thallium or their mixtures, of a kind used for the extraction of arsenic or those metals or for the manufacture of their chemical compounds, are to be classified in subheading 2620 60.', note_length: 2300 },
  { chapter_number: 27, chapter_code: '27', description: 'MINERAL FUELS, MINERAL OILS AND PRODUCTS OF THEIR DISTILLATION; BITUMINOUS SUBSTANCES; MINERAL WAXES', chapter_note: '1. This chapter does not cover:\n\n    - a. separate chemically defined organic compounds, other than pure methane and propane which are to be classified in heading 2711;\n    \n    - b. medicaments of heading 3003 or 3004; or\n    \n    - c. mixed unsaturated hydrocarbons of heading 3301, 3302 or 3805.\n\n2. References in heading 2710 to \'petroleum oils and oils obtained from bituminous minerals\' include not only petroleum oils and oils obtained from bituminous minerals but also similar oils, as well as those consisting mainly of mixed unsaturated hydrocarbons, obtained by any process, provided that the weight of the non-aromatic constituents exceeds that of the aromatic constituents. However, the references do not include liquid synthetic polyolefins of which less than 60% by volume distils at 300°C, after conversion to 1,013 millibars when a reduced-pressure distillation method is used (Chapter 39).\n\n3. For the purposes of heading 2710, \'waste oils\' means waste containing mainly petroleum oils and oils obtained from bituminous minerals (as described in note 2 to this chapter), whether or not mixed with water. These include:\n\n    - a. such oils no longer fit for use as primary products (for example, used lubricating oils, used hydraulic oils and used transformer oils);\n    \n    - b. sludge oils from the storage tanks of petroleum oils, mainly containing such oils and a high concentration of additives (for example, chemicals) used in the manufacture of the primary products; and\n    \n    - c. such oils in the form of emulsions in water or mixtures with water, such as those resulting from oil spills, storage tank washings, or from the use of cutting oils for machining operations.\n\n### Subheading notes\n\n1. For the purposes of subheading 2701 11, \'anthracite\' means coal having a volatile matter limit (on a dry, mineral-matter-free basis) not exceeding 14%.\n\n2. For the purposes of subheading 2701 12, \'bituminous coal\' means coal having a volatile matter limit (on a dry, mineral-matter-free basis) exceeding 14% and a calorific value limit (on a moist, mineral-matter-free basis) equal to or greater than 5.833 Kcal/kg.\n\n3. For the purposes of subheadings 2707 10, 2707 20, 2707 30 and 2707 40, the terms \'benzol (benzene)\', \'toluol (toluene)\', \'xylol (xylenes)\' and \'naphthalene\' apply to products which contain more than 50% by weight of benzene, toluene, xylenes or naphthalene, respectively.\n\n4. For the purposes of subheading 2710 12, \'light oils and preparations\' are those of which 90% or more by volume (including losses) distil at 210°C (equivalent to the ASTM D 86 method).\n\n5. For the purposes of the subheadings of heading 2710, the term \'biodiesel\' means mono-alkyl esters of fatty acids of a kind used as a fuel, derived from animal or vegetable fats and oils whether or not used.\n\n### Additional chapter notes\n\n1. For the purposes of code 2707 99 80 the term \'phenols\' applies to products which contain more than 50% by weight of phenols.\n\n2. For the purposes of heading 2710:\n\n    - a. \'special spirits\' (codes 2710 12 21 and 2710 12 25) means light oils as defined in subheading note 4 to this chapter, not containing any anti-knock preparations, and with a difference of not more than 60°C between the temperatures at which 5% and 90% by volume (including losses) distil;\n    \n    - b. \'white spirit\' (code 2710 12 21) means special spirits as defined in paragraph (a) above with a flash-point higher than 21°C by the EN ISO 13736 method\n    \n    - c. \'medium oils\' (codes 2710 19 11 to 2710 19 29) means oils and preparations of which less than 90% by volume (including losses) distils at 210°C and 65% or more by volume (including losses) distils at 250°C ISO 3405 method equivalent to the ASTM D 86 method);\n    \n    - d. \'heavy oils\' (codes 2710 19 31 to 2710 19 99 and 2710 20 11 to 2710 20 90) means oils and preparations of which less than 65% by volume (including losses) distils at 250°C by the ISO 3405 method (equivalent to the ASTM D 86 method) or of which the distillation percentage at 250°C cannot be determined by that method;\n    \n    - e. \'gas oils\' (codes 2710 19 31 to 2710 19 48 and 2710 20 11 to 2710 20 19) mean heavy oils as defined in paragraph (d) above of which 85% or more by volume (including losses) distils at 350°C ISO 3405 method (equivalent to the ASTM D 86 method);\n    \n    - f. \'fuel oils\' (codes 2710 19 51 to 2710 19 67 and 2710 20 32 to 2710 20 38 mean heavy oils as defined in paragraph (d) above (other than gas oils as defined in paragraph (e) above) which, for a corresponding diluted colour C, have a viscosity V:\n    \n        - not exceeding that shown in line I of the following table when the sulphated ashes content is less than 1% by the ISO 3987 method and the saponification index is less than 4 by the ISO 6293-1 or ISO 6293-2 method, (except where the product contains one or more bio-components, in which case the requirement in this indent for the saponification number to be less than 4 does not apply).\n            \n        - exceeding that shown in line II when the pour point is not less than 10°C by the ISO 3016 method.\n            \n        - exceeding that shown in line I but not exceeding that shown in line II when 25% or more by volume distils at 300°C by the ISO 3405 method (equivalent to the ASTM D 86 method) or, if less than 25% by volume distils at 300°C, when the pour point is higher than 10°C below zero by the ISO 3016 method. These provisions apply only to oils having a diluted colour C of less than 2.\n\n        <!-- trunk-ignore(markdownlint/MD036) -->\n        **Diluted colour C / Viscosity V concordance table**\n\n\n        | Colour (C) |  | 0 | 0.5 | 1 | 1.5 | 2 | 2.5 | 3 | 3.5 | 4 | 4.5 | 5 | 5.5 | 6 | 6.5 | 7 | 7.5 and above |\n        | - | - | - | - | - | - | - | - | - | - | - | - | - | - | - | - | - | - |\n        | Viscosity (V) | I | 4 | 4 | 4 | 5.4 | 9 | 15.1 | 25.3 | 42.4 | 71.1 | 119 | 200 | 335 | 562 | 943 | 1580 | 2650 |\n        |  | II | 7 | 7 | 7 | 7 | 9 | 15.1 | 25.3 | 42.4 | 71.1 | 119 | 200 | 335 | 562 | 943 | 1580 | 2650 |\n\n        The term \'viscosity V\' means the \'kinematic viscosity\' at 50°C expressed in 10-6 m<sup>2</sup> s-1 by the EN ISO 3104 method.\n        \n        The term ‘diluted colour C’ means the colour of a product, as determined by the ISO 2049 method (equivalent to the ASTM D 1 500 method), after one part of the product has been made up to 100 parts by volume with xylene, toluene or another suitable solvent. The colour must be determined immediately after dilution.\n        \n        The term “bio-components” means animal or vegetable fats, animal or vegetable oils, or mono-alkyl esters of fatty acids (FAMAE).\n        \n        Codes 2710 19 51 to 2710 19 67 and 2710 20 32 to 2710 20 38 cover only fuel oils of natural colour.\n\n        These subheadings do not cover heavy oils defined in paragraph (d) above for which it is not possible to determine:\n        \n        - the distillation percentage at 250°C by the ISO 3405 method (equivalent to the ASTM D 186 method)(zero shall be deemed to be a percentage)\n        \n        - the kinematic viscosity at 50°C by the EN ISO 3104 method;\n        \n        - or the diluted colour C by the ISO 2049 method (equivalent to the ASTM D 1500 method).\n        \n        Such products fall in codes 2710 19 71 to 2710 19 99.\n    \n    - g. \'containing biodiesel\' means that the products of subheading 2710 20 have a minimum content of biodiesel, i.e. mono-alkyl esters of fatty acids (FAMAE) of a kind used as a fuel, of 0.5% by volume (determination by the EN 14078 method).\n\n3. For the purposes of heading 2712 the expression \'crude petroleum jelly\' (code 2712 10 10) is to be taken to apply to petroleum jelly of a natural colour higher than 4.5 by the ISO 2049 method (equivalent to the ASTM D 1500 method).\n\n4. For the purposes of codes 2712 90 31 to 2712 90 39, the term \'crude\' is to be taken to apply to products:\n\n    - a. with an oil content of 3.5% or higher, if their viscosity at 100°C is lower than 9x10-6 m<sup>2</sup> s-1 by the EN ISO 3104 method; or\n    \n    - b. of a natural colour higher than 3 by the ISO 2049 method (equivalent to the ASTM D 1500 method), if their viscosity at 100°C is 9x10-6 m<sup>2</sup> s-1 or higher by the EN ISO 3104 method.\n\n5. For the purposes of heading 2710, 2711 and 2712, the term \'specific process\' is to be taken to apply to the following operations:\n\n    - a. vacuum distillation;\n    \n    - b. redistillation by a very thorough fractionation process;\n    \n    - c. cracking;\n    \n    - d. reforming;\n    \n    - e. extraction by means of selective solvents;\n    \n    - f. the process comprising all the following operations: processing with concentrated sulphuric acid, oleum or sulphuric anhydride; neutralisation with alkaline agents; decolourisation and purification with naturally active earth, activated earth, activated charcoal or bauxite;\n    \n    - g. polymerisation;\n    \n    - h. alkylation;\n    \n    - ij. isomerisation;\n    \n    - k. (in respect of products of codes 2710 19 31 to 2710 19 99 only) desulphurisation with hydrogen resulting in a reduction of at least 85% of the sulphur content of the products processed (EN ISO 20846, EN ISO 20884, or EN ISO 14596 or EN ISO 24260, EN ISO 20847 and EN ISO 8754 methods);\n    \n    - l. (in respect of products of heading 2710 only) deparaffining by a process other than filtering;\n    \n    - m. (in respect of products of codes 2710 19 31 to 2710 19 99 only) treatment with hydrogen at a pressure of more than 20 bar and a temperature of more than 250°C with the use of a catalyst, other than to effect desulphurisation, when the hydrogen constitutes an active element in a chemical reaction. The further treatment with hydrogen of lubricating oils of subheadings 2710 19 71 to 2710 19 99 (e.g. hydrofinishing or decolourisation) in order, more especially, to improve colour or stability shall not, however, be deemed to be a specific process;\n    \n    - n. (in respect of products of codes 2710 19 51 to 2710 19 67 only) atmospheric distillation, on condition that less than 30% of these products distils, by volume, including losses, at 300°C by the ISO 3405 method (equivalent to the ASTM D 86 method);\n    \n    - o. (in respect of products of codes 2710 19 71 to 2710 19 99 only) treatment by means of a high frequency electrical brush-discharge;\n    \n    - p. solely for products under code 2712 9031: de-oiling by fractional crystallisation.', note_length: 10595 },
  { chapter_number: 28, chapter_code: '28', description: 'INORGANIC CHEMICALS; ORGANIC OR INORGANIC COMPOUNDS OF PRECIOUS METALS, OF RARE-EARTH METALS, OF RADIOACTIVE ELEMENTS OR OF ISOTOPES', chapter_note: '1. Except where the context otherwise requires, the headings of this chapter apply only to:\n\n    (a) separate chemical elements and separate chemically defined compounds, whether or not containing impurities;\n    \n    (b) the products mentioned in (a) above dissolved in water;\n    \n    (c) the products mentioned in (a) above dissolved in other solvents provided that the solution constitutes a normal and necessary method of putting up these products adopted solely for reasons of safety or for transport and that the solvent does not render the product particularly suitable for specific use rather than for general use;\n    \n    (d) the products mentioned in (a), (b) or (c) above with an added stabiliser (including an anti-caking agent)\n    necessary for their preservation or transport;\n    \n    (e) the products mentioned in (a), (b), (c) or (d) above with an added anti-dusting agent or a colouring substance added to facilitate their identification or for safety reasons, provided that the additions do not render the product particularly suitable for specific use rather than for general use.\n\n2. In addition to dithionites and sulphoxylates, stabilised with organic substances (heading 2831), carbonates and peroxocarbonates of inorganic bases (heading 2836), cyanides, cyanide oxides and complex cyanides of inorganic bases (heading 2837), fulminates, cyanates and thiocyanates, of inorganic bases (heading 2842), organic products included in heading 2843 to 2846 and 2852 and carbides (heading 2849), only the following compounds of carbon are to be classified in this chapter:\n\n    a. oxides of carbon, hydrogen cyanide and fulminic, isocyanic, thiocyanic and other simple or complex cyanogen acids (heading 2811);\n    \n    b. halide oxides of carbon (heading 2812);\n    \n    c. carbon disulphide (heading 2813);\n    \n    d. thiocarbonates, selenocarbonates, tellurocarbonates, selenocyanates, tellurocyanates, tetrathiocyanatodiamminochromates (reineckates) and other complex cyanates, of inorganic bases (heading 2842);\n    \n    e. hydrogen peroxide, solidified with urea (heading 2847), carbon oxysulphide, thiocarbonyl halides, cyanogen, cyanogen halides and cyanamide and its metal derivatives (heading 2853) other than calcium cyanamide, whether or not pure (Chapter 31).\n\n3. Subject to the provisions of note 1 to Section VI, this chapter does not cover:\n\n    (a) sodium chloride or magnesium oxide, whether or not pure, or other products of Section V;\n    \n    (b) organo-inorganic compounds other than those mentioned in note 2 above;\n    \n    (c) products mentioned in note 2, 3, 4 or 5 to Chapter 31;\n    \n    (d) inorganic products of a kind used as luminophores, of heading 3206; glass frit and other glass in the form of powder, granules or flakes, of heading 3207;\n    \n    (e) artificial graphite (heading 3801); products put up as charges for fire-extinguishers or put up in fire extinguishing grenades, of heading 3813; ink removers put up in packings for retail sale, of heading 3824; cultured crystals (other than optical elements) weighing not less than 2.5 g each, of the halides of the alkali or alkaline-earth metals, of heading 3824;\n    \n    (f) precious or semi-precious stones (natural, synthetic or reconstructed) or dust or powder of such stones (heading 7102 to 7105), or precious metals or precious-metal alloys of Chapter 71;\n    \n    (g) the metals, whether or not pure, metal alloys or cermets, including sintered metal carbides (metal carbides sintered with a metal), of Section XV; or\n    \n    (h) optical elements, for example, of the halides of the alkali or alkaline-earth metals (heading 9001).\n\n4. Chemically defined complex acids consisting of a non-metal acid of sub-chapter II and a metal acid of sub-chapter IV are to be classified in heading 2811.\n\n5. Headings 2826 to 2842 apply only to metal or ammonium salts or peroxysalts. Except where the context otherwise requires, double or complex salts are to be classified in heading 2842.\n\n6. Heading 2844 applies only to:\n\n    (a) technetium (atomic No 43), promethium (atomic No 61), polonium (atomic No 84) and all elements with an atomic number greater than 84;\n    \n    (b) natural or artificial radioactive isotopes (including those of the precious metals or of the base metals of Sections XIV and XV), whether or not mixed together;\n    \n    (c) compounds, inorganic or organic, of these elements or isotopes, whether or not chemically defined, whether or not mixed together;\n    \n    (d) alloys, dispersions (including cermets), ceramic products and mixtures containing these elements or isotopes or inorganic or organic compounds thereof and having a specific radioactivity exceeding 74 Bq/g (0.002 μCi/g);\n    \n    (e) spent (irradiated) fuel elements (cartridges) of nuclear reactors;\n    \n    (f) radioactive residues whether or not usable. The term ‘isotopes’, for the purposes of this note and of the wording of heading 2844 and 2845, refers to:\n    \n    -  individual nuclides, excluding, however, those existing in nature in the monoisotopic state,\n    \n    - mixtures of isotopes of one and the same element, enriched in one or several of the said isotopes, that is, elements of which the natural isotopic composition has been artificially modified.\n\n7. Heading 2853 includes copper phosphide (phosphor copper) containing more than 15 % by weight of phosphorus.\n\n8. Chemical elements (for example, silicon and selenium) doped for use in electronics are to be classified in this chapter, provided that they are in forms unworked as drawn, or in the form of cylinders or rods. When cut in the form of discs, wafers or similar forms, they fall in heading 3818.\n\n### Subheading note\n1. For the purposes of subheading 2852 10, the expression ‘chemically defined’ means all organic or inorganic compounds of mercury meeting the requirements of paragraphs (a) to (e) of note 1 to Chapter 28 or paragraphs (a) to (h) of note 1 to Chapter 29.\n\n### Additional chapter note\n1. Unless provided otherwise, the salts specified in subheadings include acid salts and basic salts.', note_length: 6161 },
  { chapter_number: 29, chapter_code: '29', description: 'ORGANIC CHEMICALS', chapter_note: '1. Except where the context otherwise requires, the headings of this chapter apply only to:\n\n    a. separate chemically defined organic compounds, whether or not containing impurities;\n    \n    b. mixtures of two or more isomers of the same organic compound (whether or not containing impurities), except mixtures of acyclic hydrocarbon isomers (other than stereoisomers), whether or not saturated (Chapter 27);\n    \n    c. the products of heading 2936 to 2939 or the sugar ethers, sugar acetals and sugar esters, and their salts, of heading 2940, or the products of heading 2941, whether or not chemically defined;\n    \n    d. the products mentioned in (a), (b) or (c) above dissolved in water;\n    \n    e. the products mentioned in (a), (b) or (c) above dissolved in other solvents provided that the solution constitutes a normal and necessary method of putting up these products adopted solely for reasons of safety or for transport and that the solvent does not render the product particularly suitable for a specific use rather than for general use;\n    \n    f. the products mentioned in (a), (b), (c), (d) or (e) above with an added stabiliser (including an anticaking agent) necessary for their preservation or transport;\n    \n    g. the products mentioned in (a), (b), (c), (d), (e) or (f) above with an added anti-dusting agent or a colouring or odoriferous substance or an emetic added to facilitate their identification or for safety reasons, provided that the additions do not render the product particularly suitable for a specific use rather than for general use;\n    \n    h. the following products, diluted to standard strengths, for the production of azo dyes: diazonium salts, couplers for these salts and diazotisable amines and their salts.\n\n2. This chapter does not cover:\n\n    a. goods of heading 1504 or crude glycerol of heading 1520;\n    \n    b. ethyl alcohol (heading 2207 or 2208);\n    \n    c. methane or propane (heading 2711);\n    \n    d. the compounds of carbon mentioned in note 2 to Chapter 28;\n    \n    e. immunological products of heading 3002;\n    \n    f. urea (heading 3102 or 3105);\n    \n    g. colouring matter of vegetable or animal origin (heading 3203), synthetic organic colouring matter, synthetic organic products of a kind used as fluorescent brightening agents or as luminophores (heading 3204) or dyes or other colouring matter put up in forms or packings for retail sale (heading 3212);\n    \n    h. enzymes (heading 3507);\n    \n    ij. metaldehyde, hexamethylenetetramine or similar substances, put up in forms (for example, tablets, sticksor similar forms) for use as fuels, or liquid or liquefied-gas fuels in containers of a kind used for filling or refilling cigarette or similar lighters and of a capacity not exceeding 300 cm<sup>3</sup> (heading 3606);\n    \n    k. products put up as charges for fire-extinguishers or put up in fire-extinguishing grenades, of heading 3813; ink removers put up in packings for retail sale, of heading 3824; or\n    \n    l. optical elements, for example, of ethylenediamine tartrate (heading 9001)\n\n3. Goods which could be included in two or more of the headings of this chapter are to be classified in that one of those headings which occurs last in numerical order.\n\n4. In heading 2904 to 2906, 2908 to 2911 and 2913 to 2920, any reference to halogenated, sulphonated, nitrated or nitrosated derivatives includes a reference to compound derivatives, such as sulphohalogenated, nitrohalogenated, nitrosulphonated or nitrosulphohalogenated derivatives.\n\n    Nitro or nitroso groups are not to be taken as \'nitrogen-functions\' for the purposes of heading 2929.\n\n    For the purposes of heading 2911, 2912, 2914, 2918 and 2922, \'oxygen-function\', the characteristic organic oxygen-containing group  of those respective headings, is restricted to the oxygen-functions referred to in heading 2905 to 2920.\n\n5. (A) The esters of acid-function organic compounds of sub-chapters I to VII with organic compounds of these sub-chapters are to be classified with that compound which is classified in the heading which occurs last in numerical order in these sub-chapters.\n\n    (B) Esters of ethyl alcohol with acid-function organic compounds of sub-chapters I to VII are to be classified in the same heading as the corresponding acid-function compounds.\n\n    (C) Subject to Note 1 to Section VI and Note 2 to Chapter 28:\n\n    1. inorganic salts of organic compounds such as acid-, phenol- or enol-function compounds or organic bases, of sub-chapters I to X or heading 2942 are to be classified in the heading appropriate to the organic compound;\n\n    2. salts formed between organic compounds of sub-chapters I to X or heading 2942 are to be classified in the heading appropriate to the base or to the acid (including phenol-or enol-function compounds) from which they are formed, whichever occurs last in numerical order in the chapter; and\n\n    3. co-ordination compounds, other than products classifiable in sub-chapter XI or heading 2941, are to be classified in the heading which occurs last in numerical order in Chapter 29, among those appropriate to the fragments formed by \'cleaving\' of all metal bonds, other than metal-carbon bonds.\n\n    (D) metal alcoholates are to be classified in the same heading as the corresponding alcohols except in the case of ethanol (heading 2905);\n\n    (E) Halides of carboxylic acids are to be classified in the same heading as the corresponding acids.\n\n6. The compounds of heading 2930 and 2931 are organic compounds the molecules of which contain, in addition to atoms of hydrogen, oxygen or nitrogen, atoms of other non-metals or of metals (such as sulphur, arsenic or lead) directly linked to carbon atoms. Heading 2930 (organo-sulphur compounds) and heading 2931 (other organo-inorganic compounds) do not include sulphonated or halogenated derivatives (including compound derivatives) which, apart from hydrogen, oxygen and nitrogen, only have directly linked to carbon the atoms of sulphur or of a halogen which give them their nature of sulphonated or halogenated derivatives (or compound derivatives).\n\n7. Headings 2932, 2933 and 2934 do not include epoxides with a three-membered ring, ketone peroxides, cyclic polymers of aldehydes or of thioaldehydes, anhydrides of polybasic carboxylic acids, cyclic esters of polyhydric alcohols or phenols with polybasic acids, or imides of polybasic acids. These provisions apply only when the ring-position hetero-atoms are those resulting solely from the cyclising function or functions here listed.\n\n8. For the purposes of heading 2937:\n\n    a. the term \'hormones\' includes hormone-releasing or hormone-stimulating factors, hormone inhibitors and hormone antagonists (anti-hormones);\n\n    b. the expression \'used primarily as hormones\' applies not only to hormone derivatives and structural analogues used primarily for their hormonal effect, but also to those derivatives and structural analogues used primarily as intermediates in the synthesis of products of this heading.\n\n### Subheading notes\n\n1. Within any one heading of this chapter, derivatives of a chemical compound (or group of chemical compounds) are to be classified in the same subheading as that compound (or group of compounds), provided that they are not more specifically covered by any other subheading and that there is no residual subheading named \'Other\' in the series of subheadings concerned.\n\n2. Note 3 to chapter 29 does not apply to the subheadings of this chapter.', note_length: 7589 },
  { chapter_number: 30, chapter_code: '30', description: 'PHARMACEUTICAL PRODUCTS', chapter_note: '1. This chapter does not cover:\n\n    (a) foods or beverages (such as dietetic, diabetic or fortified foods, food supplements, tonic beverages and mineral waters), other than nutritional preparations for intravenous administration (Section IV);\n    \n    (b) products, such as tablets, chewing gum or patches (transdermal systems), containing nicotine and intended to assist tobacco use cessation (heading 2404);\n    \n    (c) plasters specially calcined or finely ground for use in dentistry (heading 2520);\n    \n    (d) aqueous distillates or aqueous solutions of essential oils, suitable for medicinal uses (heading 3301);\n    \n    (e) preparations of heading 3303 to 3307, even if they have therapeutic or prophylactic properties;\n    \n    (f) soap or other products of heading 3401 containing added medicaments;\n    \n    (g) preparations with a basis of plaster for use in dentistry (heading 3407); or\n    \n    (h) blood albumin not prepared for therapeutic or prophylactic uses (heading 3502).\n\n    (ij) diagnostic reagents of heading 3822.\n\n2. For the purposes of heading 3002, the expression ‘immunological products’ applies to peptides and proteins (other than goods of heading 2937) which are directly involved in the regulation of immunological processes, such as monoclonal antibodies (MAB), antibody fragments, antibody conjugates and antibody fragment conjugates, interleukins, interferons (IFN), chemokines and certain tumour-necrosis factors (TNF), growth factors (GF), hematopoietins and colony-stimulating factors (CSF).\n\n3. For the purposes of heading 3003 and 3004 and of note 4(d) to this chapter, the following are to be treated:\n\n   - (a) as unmixed products:\n    \n     - (1) unmixed products dissolved in water;\n\n     - (2) all goods of Chapter 28 or 29; and\n\n     - (3) simple vegetable extracts of heading 1302, merely standardised or dissolved in any solvent;\n    \n   - (b) as products which have been mixed:\n    \n     - (1) colloidal solutions and suspensions (other than colloidal sulphur);\n\n     - (2) vegetable extracts obtained by the treatment of mixtures of vegetable materials; and\n\n     - (3) salts and concentrates obtained by evaporating natural mineral waters.\n\n4. Heading 3006 applies only to the following, which are to be classified in that heading and in no other heading of the nomenclature:\n\n    (a) sterile surgical catgut, similar sterile suture materials (including sterile absorbable surgical or dental yarns) and sterile tissue adhesives for surgical wound closure;\n    \n    (b) sterile laminaria and sterile laminaria tents;\n    \n    (c) sterile absorbable surgical or dental haemostatics; sterile surgical or dental adhesion barriers, whether or not absorbable;\n    \n    (d) opacifying preparations for X-ray examinations and diagnostic reagents designed to be administered to the patient, being unmixed products put up in measured doses or products consisting of two or more ingredients which have been mixed together for such uses;\n    \n    (e) placebos and blinded (or double-blinded) clinical trial kits for use in recognised clinical trials, put up in measured doses, even if they might contain active medicaments;\n    \n    (f) dental cements and other dental fillings; bone reconstruction cements;\n    \n    (g) first-aid boxes and kits;\n    \n    (h) chemical contraceptive preparations based on hormones, on other products of heading 2937 or on spermicides;\n    \n    (ij) gel preparations designed to be used in human or veterinary medicine as a lubricant for parts of the body for surgical operations or physical examinations or as a coupling agent between the body and medical instruments;\n    \n    (k) waste pharmaceuticals, that is, pharmaceutical products which are unfit for their original intended purpose due to, for example, expiry of shelf life; and\n    \n    (l) appliances identifiable for ostomy use, that is, colostomy, ileostomy and urostomy pouches cut to shape and their adhesive wafers or faceplates.\n\n### Subheading notes\n\n1. For the purposes of subheadings 3002 13 and 3002 14, the following are to be treated:\n\n    - (a) as unmixed products, pure products, whether or not containing impurities;\n    \n    - (b) as products which have been mixed:\n    \n        - (1) the products mentioned in (a) above dissolved in water or in other solvents;\n        \n        - (2) the products mentioned in (a) and (b) (1) above with an added stabiliser necessary for their preservation or transport; and\n        \n        - (3) The products mentioned in (a), (b) (1) and (b) (2) above with any other additive.\n\n2. Subheadings 3003 60 and 3004 60 cover medicaments containing artemisinin (INN) for oral ingestion combined with other pharmaceutical active ingredients, or containing any of the following active principles, whether or not combined with other pharmaceutical active ingredients: amodiaquine (INN); artelinic acid or its salts; artenimol (INN); artemotil (INN); artemether (INN); artesunate (INN); chloroquine (INN); dihydroartemisinin (INN); lumefantrine (INN); mefloquine (INN); piperaquine (INN); pyrimethamine (INN) or sulfadoxine (INN).\n\n### Additional chapter note\n\n1. Heading 3004 includes herbal medicinal preparations and preparations based on the following active substances: vitamins, minerals, essential amino-acids or fatty acids, in packings for retail sale. These preparations are classified in heading 3004 if they bear on the label, packaging or on the accompanying user directions the following statements of:\n\n    (a) the specific diseases, ailments or their symptoms for which the product is to be used;\n    \n    (b) the concentration of active substance or substances contained therein;\n    \n    (c) dosage; and\n    \n    (d) mode of application.\n    \n    This heading includes homeopathic medicinal preparations when they meet the conditions of (a), (c) and (d) mentioned above. In the case of preparations based on vitamins, minerals, essential amino-acids or fatty acids, the level of one of these substances per recommended daily dose indicated on the label must be significantly higher than the recommended daily allowance to maintain general health or well-being.', note_length: 6250 },
  { chapter_number: 31, chapter_code: '31', description: 'FERTILISERS', chapter_note: '1. This chapter does not cover:\n\n    a. animal blood of heading 0511;\n    \n    b. separate chemically defined compounds (other than those answering to the descriptions in note 2(a), 3(a), 4(a) or 5 below); or\n    \n    c. cultured potassium chloride crystals (other than optical elements) weighing not less than 2.5g each, of heading 3824; optical elements of potassium chloride (heading 9001).\n\n2. Heading 3102 applies only to the following goods, provided that they are not put up in the forms or packages described in heading 3105:\n\n    a. goods which answer to one or other of the descriptions given below:\n    \n    (1) sodium nitrate, whether or not pure;\n    \n    (2) ammonium nitrate, whether or not pure;\n    \n    (3) double salts, whether or not pure, of ammonium sulphate and ammonium nitrate;\n    \n    (4) ammonium sulphate, whether or not pure;\n    \n    (5) double salts (whether or not pure) or mixtures of calcium nitrate and ammonium nitrate;\n    \n    (6) double salts (whether or not pure) or mixtures of calcium nitrate and magnesium nitrate;\n    \n    (7) calcium cyanamide, whether or not pure or treated with oil;\n    \n    (8) urea, whether or not pure;\n    \n    b. fertilisers consisting of any of the goods described in (a) above mixed together;\n    \n    c. fertilisers consisting of ammonium chloride or of any of the goods described in (a) or (b) above mixed with chalk, gypsum or other inorganic non-fertilising substances;\n    \n    d. liquid fertilisers consisting of the goods of subparagraph (a)(2) or (8) above, or of mixtures of those goods, in an aqueous or ammoniacal solution.\n\n3. Heading 3103 applies only to the following goods, provided that they are not put up in the forms or packages described in heading 3105:\n\n    a. goods which answer to one or other of the descriptions given below:\n    \n    (1) basic slag;\n    \n    (2) natural phosphates of heading 2510, calcined or further heat-treated than for the removal of impurities;\n    \n    (3) superphosphates (single, double or triple);\n    \n    (4) calcium hydrogenorthophosphate containing not less than 0.2% by weight of fluorine calculated on the dry anhydrous product;\n    \n    (b) fertilisers consisting of any of the goods described in (a) above mixed together, but with no account being taken of the fluorine content limit;\n    \n    (c) fertilisers consisting of any of the goods described in (a) or (b) above, but with no account being taken of the fluorine content limit, mixed with chalk, gypsum or other inorganic non-fertilising substances.\n\n4. Heading 3104 applies only to the following goods, provided that they are not put up in the forms or packages described in heading 3105:\n\n    a. goods which answer to one or other of the descriptions given below:\n    \n    (1) crude natural potassium salts (for example, carnallite, kainite and sylvite);\n    \n    (2) potassium chloride, whether or not pure, except as provided in note 1(c) above;\n    \n    (3) potassium sulphate, whether or not pure;\n    \n    (4) magnesium potassium sulphate, whether or not pure;\n    \n    b. fertilisers consisting of any of the goods described in (a) above mixed together.\n\n5. Ammonium dihydrogenorthophosphate (monoammonium phosphate) and diammonium hydrogenorthophosphate (diammonium phosphate), whether or not pure, and intermixtures thereof, are to be classified in heading 3105.\n\n6. For the purposes of heading 3105, the term `other fertilisers\' applies only to products of a kind used as fertilisers and containing, as an essential constituent, at least one of the fertilising elements nitrogen, phosphorus or potassium.', note_length: 3672 },
  { chapter_number: 32, chapter_code: '32', description: 'TANNING OR DYEING EXTRACTS; TANNINS AND THEIR DERIVATIVES; DYES, PIGMENTS AND OTHER COLOURING MATTER; PAINTS AND VARNISHES; PUTTY AND OTHER MASTICS; INKS', chapter_note: '1. This chapter does not cover:\n\n    - a. separate chemically defined elements or compounds (except those of heading 3203 or 3204, inorganic products of a kind used as luminophores (heading 3206), glass obtained from fused quartz or other fused silica in the forms provided for in heading 3207, and also dyes and other colouring matter put up in forms or packings for retail sale of heading 3212);\n    \n    - b. tannates or other tannin derivatives of products of heading 2936 to 2939, 2941 or 3501 to 3504; or\n    \n    - c. mastics of asphalt or other bituminous mastics (heading 2715)\n\n2. Heading 3204 includes mixtures of stabilised diazonium salts and couplers for the production of azo dyes.\n\n3. Headings 3203, 3204, 3205 and 3206 apply also to preparations based on colouring matter (including, in the case of heading 3206, colouring pigments of heading 2530 or Chapter 28, metal flakes and metal powders), of a kind used for colouring any material or used as ingredients in the manufacture of colouring preparations. \n\n    The headings do not apply, however, to pigments dispersed in non-aqueous media, in liquid or paste form, of a kind used in the manufacture of paints, including enamels (heading 3212), or to other preparations of heading 3207, 3208, 3209, 3210, 3212, 3213 and 3215.\n\n4. Heading 3208 includes solutions (other than collodions) consisting of any of the products specified in heading 3901 to 3913 in volatile organic solvents when the weight of the solvent exceeds 50% of the weight of the solution.\n\n5. The expression \'colouring matter\' in this Chapter does not include products of a kind used as extenders in oil paints, whether or not they are also suitable for colouring distempers.\n\n6. The expression \'stamping foils\' in heading 3212 applies only to thin sheets of a kind used for printing, for example book covers or hat bands, and consisting of:\n\n    - a. metallic powder (including powder of precious metal) or pigment, agglomerated with glue, gelatin or other binder; or\n    - b. metal (including precious metal) or pigment, deposited on a supporting sheet of any material.', note_length: 2129 },
  { chapter_number: 33, chapter_code: '33', description: 'ESSENTIAL OILS AND RESINOIDS; PERFUMERY, COSMETIC OR TOILET PREPARATIONS', chapter_note: '1. This chapter does not cover:\n\n    a. natural oleoresins or vegetable extracts of heading 1301 or 1302;\n    \n    b. soap or other products of heading 3401; or\n    \n    c. gum, wood or sulphate turpentine or other products of heading 3805.\n\n2. The expression \'odoriferous substances\' in heading 3302 refers only to the substances of heading 3301, to odoriferous constituents isolated from those substances or to synthetic aromatics.\n\n3. Headings 3303 to 3307 apply, inter alia, to products, whether or not mixed (other than aqueous distillates and aqueous solutions of essential oils), suitable for use as goods of these headings and put up in packings of a kind sold by retail for such use.\n\n4. The expression \'perfumery, cosmetic or toilet preparations\' in heading 3307 applies, inter alia, to the following products: scented sachets; odoriferous preparations which operate by burning; perfumed papers and papers impregnated or coated with cosmetics; contact lens or artificial eye solutions; wadding, felt and nonwovens, impregnated, coated or covered with perfume or cosmetics; animal toilet preparations.', note_length: 1122 },
  { chapter_number: 34, chapter_code: '34', description: 'SOAP, ORGANIC SURFACE-ACTIVE AGENTS, WASHING PREPARATIONS, LUBRICATING PREPARATIONS, ARTIFICIAL WAXES, PREPARED WAXES, POLISHING OR SCOURING PREPARATIONS, CANDLES AND SIMILAR ARTICLES, MODELLING PASTES, \'DENTAL WAXES\' AND DENTAL PREPARATIONS WITH A BASIS OF PLASTER', chapter_note: '1. This chapter does not cover:\n\n    - a. edible mixtures or preparations of animal, vegetable or microbial fats or oils of a kind used as mould-release preparations (heading 1517);\n    \n    - b. separate chemically defined compounds; or\n    \n    - c. shampoos, dentifrices, shaving creams and foams, or bath preparations, containing soap or other organic surface-active agents (heading 3305, 3306 or 3307).\n\n2. For the purposes of heading 3401, the expression \'soap\' applies only to soap soluble in water. Soap and the other products of heading 3401 may contain added substances (for example, disinfectants, abrasive powders, fillers or medicaments). \n\n    Products containing abrasive powders remain classified in heading 3401 only if in the form of bars, cakes or moulded pieces or shapes. In other forms, they are to be classified in heading 3405 as \'scouring powders and similar preparations\'.\n\n3. For the purposes of heading 3402, \'organic surface-active agents\' are products which, when mixed with water at a concentration of 0.5% at 20°C and left to stand for one hour at the same temperature:\n\n    - a. give a transparent or translucent liquid or stable emulsion without separation of insoluble matter; and\n    \n    - b. reduce the surface tension of water to 4.5 x 10-2 N/m (45 dyn/cm) or less.\n\n4. In heading 3403, the expression \'petroleum oils and oils obtained from bituminous minerals\' applies to the products defined in Note 2 to Chapter 27.\n\n5. In heading 3404, subject to the exclusions provided below, the expression \'artificial waxes and prepared waxes\' applies only to:\n\n    - a. chemically produced organic products of a waxy character, whether or not water soluble;\n    \n    - b. products obtained by mixing different waxes;\n    \n    - c. products of a waxy character with a basis of one or more waxes and containing fats, resins, mineral substances or other materials.\n    \n    The heading does not apply to:\n\n    - (a) products of heading 1516, 3402 or 3823, even if having a waxy character;\n    \n    - (b) unmixed animal waxes or unmixed vegetable waxes, whether or not refined or coloured, of heading 1521;\n    \n    - (c) mineral waxes or similar products of heading 2712, whether or not intermixed or merely coloured; or\n    \n    - (d) waxes mixed with, dispersed in or dissolved in a liquid medium (heading 3405, 3809, etc.).', note_length: 2390 },
  { chapter_number: 35, chapter_code: '35', description: 'ALBUMINOIDAL SUBSTANCES; MODIFIED STARCHES; GLUES; ENZYMES', chapter_note: '1. This chapter does not cover:\n\n    a. yeasts (heading 2102);\n\n    b. blood fractions (other than blood albumin not prepared for therapeutic or prophylactic uses), medicaments or other products of Chapter 30;\n\n    c. enzymatic preparations for pre-tanning (heading 3202);\n\n    d. enzymatic soaking or washing preparations and other products of Chapter 34;\n\n    e. hardened proteins (heading 3913); or\n\n    f. gelatin products of the printing industry (Chapter 49).\n\n2. For the purposes of heading 3505, the term \'dextrins\' means starch degradation products with a reducing sugar content, expressed as dextrose on the dry substance, not exceeding 10%. Such products with a reducing sugar content exceeding 10% fall in heading 1702.\n\n### Additional chapter note\n\n1. Code 3504 00 10 covers concentrated milk proteins with a protein content of more than 85% by weight, calculated on the dry matter.\n\n2. The term “unfit for human consumption” as regards codes 3502 11 10, 3502 19 10, 3502 20 10 and 3502 90 20 applies when:\n\n    - the goods are homogeneously mixed with one of the denaturants shown in column 1 of the table below in the quantities indicated in column 2 and\n\n    - separation of the goods and the denaturant is not economically viable.\n\n\n    | Denaturant | Minimum quantity to be used (in g) per 100kg of denatured product |\n    | - | - |\n    | (1) | (2) |\n    | Oil of rosemary (for liquid albumins only) | 150 |\n    | Crude oil of camphor (for liquid and solid albumins) | 2.000 |\n    | White oil of camphor (for liquid and solid albumins) | 2.000 |\n    | Sodium azide (for liquid and solid albumins) | 100 |\n    | Diethanolamine (for solid albumins only) | 6.000 |', note_length: 1713 },
  { chapter_number: 36, chapter_code: '36', description: 'EXPLOSIVES; PYROTECHNIC PRODUCTS; MATCHES; PYROPHORIC ALLOYS; CERTAIN COMBUSTIBLE PREPARATIONS', chapter_note: '1. This chapter does not cover separate chemically defined compounds other than those described in Note 2(a) or (b) below.\n\n2. The expression \'articles of combustible materials\' in heading 3606 applies only to:\n\n    a. metaldehyde, hexamethylenetetramine and similar substances, put up in forms (for example, tablets, sticks or similar forms) for use as fuels; fuels with a basis of alcohol, and similar prepared fuels, in solid or semi-solid form;\n\n    b. liquid or liquefied-gas fuels in containers of a kind used for filling or refilling cigarette or similar lighters and of a capacity not exceeding 300 cm<sup>3</sup>; and\n\n    c. resin torches, firelighters and the like.', note_length: 684 },
  { chapter_number: 37, chapter_code: '37', description: 'PHOTOGRAPHIC OR CINEMATOGRAPHIC GOODS', chapter_note: '1. This chapter does not cover waste or scrap.\n\n2. In this chapter, the word \'photographic\' relates to the process by which visible images are formed, directly or indirectly, by the action of light or other forms of radiation on photosensitive, including thermosensitive, surfaces.\n\n### Additional chapter notes\n\n1. In the case of sound films imported in two bands (the band bearing only the images and the band used for recording the sound), each band is to be classified in its appropriate heading.\n\n2. The expression \'newsreels\' (code 3706 90 52) is to be taken to apply to films of length of less than 330m, and depicting current events of a political, sporting, military, scientific, literary, folkloric, touristic, society, etc., nature.', note_length: 751 },
  { chapter_number: 38, chapter_code: '38', description: 'MISCELLANEOUS CHEMICAL PRODUCTS', chapter_note: '1. This chapter does not cover:\n\n    - a. separate chemically defined elements or compounds with the exception of the following:\n\n      (1) artificial graphite (heading 3801);\n\n      (2) insecticides, rodenticides, fungicides, herbicides, anti-sprouting products and plant-growth regulators, disinfectants and similar products, put up as described in heading 3808;\n\n      (3) products put up as charges for fire-extinguishers or put up in fire-extinguishing grenades (heading 3813);\n\n      (4) certified reference materials specified in note 2 below;\n\n      (5) products specified in note 3(a) or 3(c) below;\n\n    - b. mixtures of chemicals with foodstuffs or other substances with nutritive value, of a kind used in the preparation of human foodstuffs (generally, heading 2106).\n\n    - c. products of heading 2404\n\n    - d. slag, ash and residues (including sludges, other than sewage sludge), containing metals, arsenic or their mixtures and meeting the requirements of note 3 (a) or 3(b) to Chapter 26 (heading 2620);\n\n    - e. medicaments (heading 3003 or 3004); or\n\n    - f. spent catalysts of a kind used for the extraction of base metals or for the manufacture of chemical compounds of base metals (heading 2620), spent catalysts of a kind used principally for the recovery of precious metal (heading 7112) or catalysts consisting of metals or metal alloys in the form of, for example, finely divided powder or woven gauze (Section XIV or XV).\n\n\n2. (A) For the purpose of heading 3822, the expression \'certified reference materials\' means reference materials which are accompanied by a certificate which indicates the values of the certified properties, the methods used to determine these values and the degree of certainty associated with each value and which are suitable for analytical, calibrating or referencing purposes.\n\n    (B) With the exception of the products of Chapter 28 or 29, for the nomenclature of certified reference materials, heading 3822 shall take precedence over any other heading in the nomenclature.\n\n3. Heading 3824 includes the following goods which are not to be classified in any other heading of the nomenclature:\n\n    a. cultured crystals (other than optical elements) weighing not less than 2.5g each, of magnesium oxide or of the halides of the alkali or alkaline-earth metals;\n\n    b. fusel oil; Dippel\'s oil;\n\n    c. ink removers put up in packings for retail sale;\n\n    d. stencil correctors, other correcting fluids and correction tapes (other than those of heading 9612), put up in packings for retail sale; and\n\n    e. ceramic firing testers, fusible (e.g. Seger cones).\n\n4. Throughout the nomenclature, \'municipal waste\' means waste of a kind collected from households, hotels, restaurants, hospitals, shops, offices, etc., road and pavement sweepings, as well as construction and demolition waste. Municipal waste generally contains a large variety of materials such as plastics, rubber, wood, paper, textiles, glass, metals, food materials, broken furniture and other damaged or discarded articles.\n\n    The term \'municipal waste\', however, does not cover:\n\n    a. individual materials or articles segregated from the waste, for example wastes of plastics, rubber, wood, paper, textiles, glass or metals, electrical and electronic waste and scrap (including spent batteries) which fall in their appropriate headings of the nomenclature;\n\n    b. industrial waste;\n\n    c. waste pharmaceuticals, as defined in note 4(k) to Chapter 30; or\n\n    d. clinical waste, as defined in note 6 (a) below.\n\n5. For the purposes of heading 3825, \'sewage sludge\' means sludge arising from urban effluent treatment plant and includes pre-treatment waste, scourings and unstabilised sludge. Stabilised sludge when suitable for use as fertiliser is excluded (Chapter 31).\n\n6. For the purposes of heading 3825, the expression \'other wastes\' applies to:\n\n    a. clinical waste, that is, contaminated waste arising from medical research, diagnosis, treatment or other medical, surgical, dental or veterinary procedures, which often contain pathogens and pharmaceutical substances and require special disposal procedures (eg, soiled dressings, used gloves and used syringes);\n\n    b. waste organic solvents;\n\n    c. wastes of metal pickling liquors, hydraulic fluids, brake fluids and anti-freezing fluids; and\n\n    d. other wastes from chemical or allied industries.\n\n    The expression \'other wastes\' does not, however, cover wastes which contain mainly petroleum oils or oils obtained from bituminous minerals (heading 2710).\n\n7. For the purposes of heading 3826, the term “biodiesel” means mono-alkyl esters of fatty acids of a kind used as a fuel, derived from animal, vegetable or microbial fats and oils whether or not used. \n\n### Subheading notes\n\n1. Subheadings 3808 52 and 3808 59 cover only goods of heading 3808, containing one or more of the following substances: alachlor (ISO); aldicarb (ISO); aldrin (ISO); azinphos-methyl (ISO); binapacryl (ISO); camphechlor (ISO) (toxaphene); captafol (ISO); carbofuran (ISO); chlordane (ISO); chlordimeform (ISO); chlorobenzilate (ISO); DDT (ISO) (clofenotane (INN), 1,1,1-trichloro-2,2-bis(p-chlorophenyl)ethane); dieldrin (ISO, INN); 4,6-dinitro-o-cresol (DNOC (ISO)) or its salts; dinoseb (ISO), its salts or its esters; endosulfan (ISO); ethylene dibromide (ISO) (1,2-dibromoethane); ethylene dichloride (ISO) (1,2-dichloroethane); fluoroacetamide (ISO); heptachlor (ISO); hexachlorobenzene (ISO); 1,2,3,4,5,6-hexachlorocyclohexane (HCH (ISO)), including lindane (ISO, INN); mercury compounds; methamidophos (ISO); monocrotophos (ISO); oxirane (ethylene oxide); parathion (ISO); parathion-methyl (ISO) (methyl-parathion); pentachlorophenol (ISO), its salts or its esters; perfluorooctane sulphonic acid and its salts; perfluorooctane sulphonamides; perfluorooctane sulphonyl fluoride; phosphamidon (ISO); 2,4,5-T (ISO) (2,4,5-trichlorophenoxyacetic acid), its salts or its esters; tributyltin compounds; trichlorfon (ISO).\n\n2. Subheadings 3808 61 to 3808 69 cover only goods of heading 3808, containing alpha-cypermethrin (ISO), bendiocarb (ISO), bifenthrin (ISO), chlorfenapyr (ISO), cyfluthrin (ISO), deltamethrin (INN, ISO), etofenprox (INN), fenitrothion (ISO), lambda-cyhalothrin (ISO), malathion (ISO), pirimiphos-methyl (ISO) or propoxur (ISO).\n\n3. Subheadings 3824 81 to 3824 89 cover only mixtures and preparations containing one or more of the following substances: oxirane (ethylene oxide), polybrominated biphenyls (PBBs), polychlorinated biphenyls (PCBs), polychlorinated terphenyls (PCTs), tris(2,3-dibromopropyl) phosphate, aldrin (ISO), camphechlor (ISO) (toxaphene), chlordane (ISO), chlordecone (ISO), DDT (ISO) (clofenotane (INN), 1,1,1-trichloro-2,2-bis(p-chlorophenyl)ethane), dieldrin (ISO, INN), endosulfan (ISO), endrin (ISO), heptachlor (ISO), mirex (ISO), 1,2,3,4,5,6-hexachlorocyclohexane (HCH (ISO)), including lindane (ISO, INN), pentachlorobenzene (ISO), hexachlorobenzene (ISO), perfluorooctane sulphonic acid, its salts, perfluorooctane sulphonamides, perfluorooctane sulphonyl fluoride or tetra-, penta-, hexa-, hepta- or octabromodiphenyl ethers; short-chain chlorinated paraffins.\n\n    Short-chain chlorinated paraffins are mixtures of compounds, with a chlorination degree of more than 48 % by weight, with the following molecular formula : CxH(2x-y+2)Cly, where x=10 - 13 and y= 1 – 13 \n\n4. For the purposes of subheadings 3825 41 and 3825 49, \'waste organic solvents\' are wastes containing mainly organic solvents, not fit for further use as presented as primary products, whether or not intended for recovery of the solvents.\n\n# Additional chapter note\n\n1. For the purposes of this chapter, “agricultural products” means:\n\n    - goods of chapters 1 to 4, 6 to 12, 16 and 23 of the classification;\n\n    - goods of heading 0504, 1501, 1502, 1503, 1504, 1507, 1512, 1513, 1517, 1701, 1702, 1703, 1801, 1802, 2204, 2205, 2207, 2401, 2501 and 5701 of the classification;\n\n    - pectin;\n\n    - ethyl alcohol or neutral spirits, whether or not denatured, of any strength, obtained from agricultural products listed in the three bullet points above, excluding liqueurs and other spirituous beverages and compound alcoholic preparations (known as "concentrated extracts") for the manufacture of beverages.', note_length: 8410 },
  { chapter_number: 39, chapter_code: '39', description: 'PLASTICS AND ARTICLES THEREOF', chapter_note: '1. Throughout the nomenclature, the expression ‘plastics’ means those materials of heading 3901 to 3914 which are or have been capable, either at the moment of polymerisation or at some subsequent stage, of being formed under external influence (usually heat and pressure, if necessary, with a solvent or plasticiser) by moulding, casting, extruding, rolling or other process into shapes which are retained on the removal of the external influence.\n\n    Throughout the nomenclature, any reference to ‘plastics’ also includes vulcanised fibre. The expression, however, does not apply to materials regarded as textile materials of Section XI.\n\n2. This chapter does not cover:\n\n    (a) lubricating preparations of heading 2710 or 3403;\n\n    (b) waxes of heading 2712 or 3404;\n\n    (c) separate chemically defined organic compounds (Chapter 29);\n\n    (d) heparin or its salts (heading 3001);\n\n    (e) solutions (other than collodions) consisting of any of the products specified in heading 3901 to 3913 in volatile organic solvents when the weight of the solvent exceeds 50 % of the weight of the solution (heading 3208); stamping foils of heading 3212;\n\n    (f) organic surface-active agents or preparations of heading 3402;\n\n    (g) run gums or ester gums (heading 3806);\n\n    (h) prepared additives for mineral oils (including gasoline) or for other liquids used for the same purposes as mineral oils (heading 3811);\n\n    (ij) prepared hydraulic fluids based on polyglycols, silicones or other polymers of Chapter 39 (heading 3819);\n\n    (k) diagnostic or laboratory reagents on a backing of plastics (heading 3822);\n\n    (l) synthetic rubber, as defined for the purposes of Chapter 40, or articles thereof;\n\n    (m) saddlery or harness (heading 4201) or trunks, suitcases, handbags or other containers of heading 4202;\n\n    (n) plaits, wickerwork or other articles of Chapter 46;\n\n    (o) wallcoverings of heading 4814;\n\n    (p) goods of Section XI (textiles and textile articles);\n\n    (q) articles of Section XII (for example, footwear, headgear, umbrellas, sun umbrellas, walking sticks, whips, riding-crops or parts thereof);\n\n    (r) imitation jewellery of heading 7117;\n\n    (s) articles of Section XVI (machines and mechanical or electrical appliances);\n\n    (t) parts of aircraft or vehicles of Section XVII;\n\n    (u) articles of Chapter 90 (for example, optical elements, spectacle frames, drawing instruments);\n\n    (v) articles of Chapter 91 (for example, clock or watch cases);\n\n    (w) articles of Chapter 92 (for example, musical instruments or parts thereof);\n\n    (x) articles of Chapter 94 (for example, furniture, luminaires and lighting fittings, illuminated signs, prefabricated buildings);\n\n    (y) articles of Chapter 95 (for example, toys, games, sports requisites); or\n\n    (z) articles of Chapter 96 (for example, brushes, buttons, slide fasteners, combs, mouthpieces or stems for smoking pipes, cigarette- holders or the like, parts of vacuum flasks or the like, pens, propelling pencils, and monopods, bipods, tripods and similar articles).\n\n3. Headings 3901 to 3911 apply only to goods of a kind produced by chemical synthesis, falling in the following categories:\n\n    (a) liquid synthetic polyolefins of which less than 60 % by volume distils at 300 °C, after conversion to 1013 mbar when a reduced- pressure distillation method is used (heading 3901 and 3902);\n\n    (b) resins, not highly polymerised, of the coumarone-indene type (heading 3911);\n\n    (c) other synthetic polymers with an average of at least five monomer units;\n\n    (d) silicones (heading 3910);\n\n    (e) resols (heading 3909) and other prepolymers.\n\n4. The expression ‘copolymers’ covers all polymers in which no single monomer unit contributes 95 % or more by weight to the total polymer content.\n\n    For the purposes of this chapter, except where the context otherwise requires, copolymers (including copolycondensates, co- polyaddition products, block copolymers and graft copolymers) and polymer blends are to be classified in the heading covering polymers of that comonomer unit which predominates by weight over every other single comonomer unit. For the purposes of this note, constituent comonomer units of polymers falling in the same heading shall be taken together.\n\n    If no single comonomer unit predominates, copolymers or polymer blends, as the case may be, are to be classified in the heading which occurs last in numerical order among those which equally merit consideration.\n\n5. Chemically modified polymers, that is those in which only appendages to the main polymer chain have been changed by chemical reaction, are to be classified in the heading appropriate to the unmodified polymer.\n\n    This provision does not apply to graft copolymers.\n\n6. In heading 3901 to 3914, the expression ‘primary forms’ applies only to the following forms:\n\n    (a) liquids and pastes, including dispersions (emulsions and suspensions) and solutions;\n\n    (b) blocks of irregular shape, lumps, powders (including moulding powders), granules, flakes and similar bulk forms.\n\n7. Heading 3915 does not apply to waste, parings and scrap of a single thermoplastic material, transformed into primary forms (heading 3901 to 3914).\n\n8. For the purposes of heading 3917, the expression ‘tubes, pipes and hoses’ means hollow products, whether semi-manufactured or finished products, of a kind generally used for conveying, conducting or distributing gases or liquids (for example, ribbed garden hose, perforated tubes). \n\n    This expression also includes sausage casings and other lay-flat tubing. However, except for the last mentioned, those having an internal cross section other than round, oval, rectangular (in which the length does not exceed one-and-a-half times the width) or in the shape of a regular polygon are not to be regarded as tubes, pipes and hoses but as profile shapes.\n\n9. For the purposes of heading 3918, the expression ‘wall or ceiling coverings of plastics’ applies to products in rolls, of a width not less than 45 cm, suitable for wall or ceiling decoration, consisting of plastics fixed permanently on a backing of any material other than paper, the layer of plastics (on the face side) being grained, embossed, coloured, design-printed or otherwise decorated.\n\n10. In heading 3920 and 3921, the expression ‘plates, sheets, film, foil and strip’ applies only to plates, sheets, film, foil and strip (other than those of Chapter 54) and to blocks of regular geometric shape, whether or not printed or otherwise surface-worked, uncut or cut into rectangles (including squares) but not further worked (even if when so cut they become articles ready for use).\n\n11. Heading 3925 applies only to the following articles, not being products covered by any of the earlier headings of sub-chapter II:\n    (a) reservoirs, tanks (including septic tanks), vats and similar containers, of a capacity exceeding 300 litres;\n\n    (b) structural elements used, for example, in floors, walls or partitions, ceilings or roofs;\n\n    (c) gutters and fittings therefor;\n\n    (d) doors, windows and their frames and thresholds for doors;\n\n    (e) balconies, balustrades, fencing, gates and similar barriers;\n\n    (f) shutters, blinds (including venetian blinds) and similar articles and parts and fittings thereof;\n\n    (g) large-scale shelving for assembly and permanent installation, for example, in shops, workshops, warehouses;\n\n    (h) ornamental architectural features, for example, flutings, cupolas, dovecotes; and\n\n    (ij) fittings and mountings intended for permanent installation in or on doors, windows, staircases, walls or other parts of buildings, for example, knobs, handles, hooks, brackets, towel rails, switch-plates and other protective plates.\n\n### Subheading notes\n1. Within any one heading of this chapter, polymers (including copolymers) and chemically modified polymers are to be classified according to the following provisions:\n\n    (a) where there is a subheading named ‘Other’ in the same series:\n\n    (1) the designation in a subheading of a polymer by the prefix ‘poly’ (for example, polyethylene and polyamide-6,6) means that the constituent monomer unit or monomer units of the named polymer taken together must contribute 95 % or more by weight of the total polymer content;\n\n    (2) the copolymers named in subheadings 3901 30, 3901 40, 3903 20, 3903 30 and 3904 30 are to be classified in those subheadings, provided that the comonomer units of the named copolymers contribute 95 % or more by weight of the total polymer content;\n\n    (3) chemically modified polymers are to be classified in the subheading named ‘Other’, provided that the chemically modified polymers are not more specifically covered by another subheading;\n\n    (4) polymers not meeting (1), (2) or (3) above, are to be classified in the subheading, among the remaining subheadings in the series, covering polymers of that monomer unit which predominates by weight over every other single comonomer unit. For this purpose, constituent monomer units of polymers falling in the same subheading shall be taken together. Only the constituent comonomer units of the polymers in the series of subheadings under consideration are to be compared;\n\n    (b) where there is no subheading named ‘Other’ in the same series:\n\n    (1) polymers are to be classified in the subheading covering polymers of that monomer unit which predominates by weight over every other single comonomer unit. For this purpose, constituent monomer units of polymers falling in the same subheading shall be taken together. Only the constituent comonomer units of the polymers in the series under consideration are to be compared;\n\n    (2) chemically modified polymers are to be classified in the subheading appropriate to the unmodified polymer.\n\n    Polymer blends are to be classified in the same subheading as polymers of the same monomer units in the same proportions.\n\n2. For the purposes of subheading 3920 43, the term ‘plasticisers’ includes secondary plasticisers.\n\n### Additional chapter notes\n\n1. Where the woven, knitted or crocheted fabrics, felt or nonwovens are present merely for reinforcing purposes, gloves, mittens or mitts impregnated, coated or covered with cellular plastics belong to Chapter 39, even if they are:\n\n    - made up from woven, knitted or crocheted fabrics (other than those of heading 5903), felt or nonwovens impregnated, coated or covered with cellular plastics, or\n\n    - made up from unimpregnated, uncoated or uncovered woven, knitted or crocheted fabrics, felt or nonwovens and subsequently impregnated, coated or covered with cellular plastics.\n\n    (Note 3(c) to Chapter 56 and note 2(a)(5) to Chapter 59).\n\n2. Chapter 39 includes articles comprising a bulking agent mixed with resin.  The resin, by giving shape and rigidity, gives an article its essential character.\n\n    For example, code 3922 20 00 includes lavatory seats consisting of approximately 85% wood flour, which is a powder obtained from grinding sawdust, shavings or other wood waste, and approximately 15% phenolic resin. The article is made by compressing the wood flour and resin powder, which includes a hardener, in a mould which is then heated, curing the article and making it rigid. In curing, the resin is melted and reacts with the hardener. The lavatory seat is classified as an article of plastics within code 3922 20 00 as the resin gives the article its shape and rigidity while the wood flour acts as a filler.', note_length: 11656 },
  { chapter_number: 40, chapter_code: '40', description: 'RUBBER AND ARTICLES THEREOF', chapter_note: '1. Except where the context otherwise requires, throughout the nomenclature the expression \'rubber\' means the following products, whether or not vulcanised or hard: natural rubber, balata, gutta-percha, guayule, chicle and similar natural gums, synthetic rubber, factice derived from oils, and such substances reclaimed.\n\n2. This chapter does not cover:\n\n    a. goods of Section XI (textiles and textile articles);\n\n    b. footwear or parts thereof of Chapter 64;\n\n    c. headgear or parts thereof (including bathing caps) of Chapter 65;\n\n    d. mechanical or electrical appliances or parts thereof of Section XVI (including electrical goods of all kinds), of hard rubber;\n\n    e. articles of Chapter 90, Chapter 92, Chapter 94 or Chapter 96; or\n\n    f. articles of Chapter 95 (other than sports gloves, mittens and mitts and articles of heading 4011 to 4013).\n\n3. In heading 4001 to 4003 and 4005, the expression \'primary forms\' applies only to the following forms:\n\n    a. liquids and pastes (including latex, whether or not pre-vulcanised, and other dispersions and solutions);\n\n    b. blocks of irregular shape, lumps, bales, powders, granules, crumbs and similar bulk forms.\n\n4. In Note 1 to this chapter and in heading 4002, the expression \'synthetic rubber\' applies to:\n\n    a. unsaturated synthetic substances which can be irreversibly transformed by vulcanisation with sulphur into non-thermoplastic substances which, at a temperature between 18°C and 29°C, will not break on being extended to three times their original length and will return, after being extended to twice their original length, within a period of five minutes, to a length not greater than one and a half times their original length. For the purposes of this test, substances necessary for the cross-linking, such as vulcanising activators or accelerators, may be added; the presence of substances as provided for by Note 5 (b) (2) and (3) is also permitted. However, the presence of any substances not necessary for the crosslinking, such as extenders, plasticisers and fillers, is not permitted;\n\n    b. thioplasts (TM); and\n\n    c. natural rubber modified by grafting or mixing with plastics, depolymerised natural rubber, mixtures of unsaturated synthetic substances with saturated synthetic high polymers provided that all the abovementioned products comply with the requirements concerning vulcanisation, elongation and recovery in (a) above.\n\n5. (A) Headings 4001 and 4002 do not apply to any rubber or mixture of rubbers which has been compounded, before or after coagulation, with:\n\n    (1) vulcanising agents, accelerators, retarders or activators (other than those added for the preparation of prevulcanised rubber latex);\n\n    (2) pigments or other colouring matter, other than those added solely for the purpose of identification;\n\n    (3) plasticisers or extenders (except mineral oil in the case of oil-extended rubber), fillers, reinforcing agents, organic solvents or any other substances, except those permitted under (B);\n\n    (B) The presence of the following substances in any rubber or mixture of rubbers shall not affect its classification in heading 4001 or 4002, as the case may be, provided that such rubber or mixture of rubbers retains its essential character as a raw material:\n\n    (1) emulsifiers or anti-tack agents;\n\n    (2) small amounts of breakdown products of emulsifiers;\n\n    (3) very small amounts of the following: heat-sensitive agents (generally, for obtaining thermosensitive rubber latexes), cationic surface-active agents (generally, for obtaining electropositive rubber latexes), antioxidants, coagulants, crumbling agents, freeze-resisting agents, peptisers, preservatives, stabilisers, viscosity-control agents, or similar special-purpose additives.\n\n6. For the purposes of heading 4004, the expression \'waste, parings and scrap\' means rubber waste, parings and scrap from the manufacture or working of rubber and rubber goods definitely not usable as such because of cutting-up, wear or other reasons.\n\n7. Thread wholly of vulcanised rubber, of which any cross-sectional dimension exceeds 5mm, is to be classified as strip, rods or profile shapes, of heading 4008.\n\n8. Heading 4010 includes conveyor or transmission belts or belting of textile fabric impregnated, coated, covered or laminated with rubber or made from textile yarn or cord impregnated, coated, covered or sheathed with rubber.\n\n9. In heading 4001, 4002, 4003, 4005 and 4008, the expression \'plates\', \'sheets\' and \'strip\' apply only to plates, sheets and strip and to blocks of regular geometric shape, uncut or simply cut to rectangular (including square) shape, whether or not having the character of articles and whether or not printed or otherwise surface worked, but not otherwise cut to shape or further worked.\n\n    In heading 4008 the expressions \'rods\' and \'profile shapes\' apply only to such products, whether or not cut to length or surface-worked but not otherwise worked.\n\n### Additional chapter note\n\nWhere the woven, knitted or crocheted fabrics, felt or nonwovens are present merely for reinforcing purposes, gloves, mittens or mitts impregnated, coated or covered with cellular rubber belong to Chapter 40, even if they are:\n\n- made up from woven, knitted or crocheted fabrics (other than those of heading 5906), felt or nonwovens impregnated, coated or covered with cellular rubber, or\n\n- made up from unimpregnated, uncoated or uncovered woven, knitted or crocheted fabrics, felt or nonwovens and subsequently impregnated, coated or covered with cellular rubber.\n\n(Note 3(c) to Chapter 56 and note 5, last paragraph, to Chapter 59).', note_length: 5709 },
  { chapter_number: 41, chapter_code: '41', description: 'RAW HIDES AND SKINS (OTHER THAN FURSKINS) AND LEATHER', chapter_note: '1. This chapter does not cover:\n\n    a. parings or similar waste, of raw hides or skins (heading 0511);\n\n    b. bird skins or parts of bird skins, with their feathers or down, of heading 0505 or 6701; or\n\n    c. hides or skins, with the hair or wool on, raw, tanned or dressed (Chapter 43); the following are, however, to be classified in Chapter 41, namely, raw hides and skins with the hair or wool on, of bovine animals (including buffalo), of equine animals, of sheep or lambs (except Astrakhan, Broadtail, Caracul, Persian or similar lambs, Indian, Chinese, Mongolian or Tibetan lambs), of goats or kids (except Yemen, Mongolian or Tibetan goats and kids), of swine (including peccary), of chamois, of gazelle, of camels (including dromedaries), of reindeer, of elk, of deer, of roebucks or of dogs.\n\n2. (A) Headings 4104 to 4106 do not cover hides and skins which have undergone a tanning (including pretanning) process which is reversible (heading 4101 to 4103, as the case may be).\n\n    (B) For the purposes of heading 4104 to 4106, the term \'crust\' includes hides and skins that have been retanned, coloured or fat-liquored (stuffed) prior to drying.\n\n3. Throughout the nomenclature, the expression \'composition leather\' means only substances of the kind referred to in heading 4115.', note_length: 1304 },
  { chapter_number: 42, chapter_code: '42', description: 'ARTICLES OF LEATHER; SADDLERY AND HARNESS; TRAVEL GOODS, HANDBAGS AND SIMILAR CONTAINERS; ARTICLES OF ANIMAL GUT (OTHER THAN SILKWORM GUT)', chapter_note: '1. For the purpose of this chapter, the term \'leather\' includes chamois (including combination chamois) leather, patent leather, patent laminated leather and metallised leather.\n\n2. This chapter does not cover:\n\n    a. sterile surgical catgut or similar sterile suture materials (heading 3006);\n\n    b. articles of apparel and clothing accessories (except gloves, mittens and mitts), lined with fur skin or artificial fur or to which fur skin or artificial fur is attached on the outside except as mere trimming (heading 4303 or 4304);\n\n    c. made up articles of netting (heading 5608);\n\n    d. articles of Chapter 64;\n\n    e. headgear or parts thereof of Chapter 65;\n\n    f. whips, riding-crops or other articles of heading 6602;\n\n    g. cuff-links, bracelets or other imitation jewellery (heading 7117);\n\n    h. fittings or trimmings for harness, such as stirrups, bits, horse brasses and buckles, separately presented (generally, Section XV);\n\n    (ij) strings, skins for drums or the like, or other parts of musical instruments (heading 9209);\n\n    k. articles of Chapter 94 (for example, furniture, luminaires and lighting fittings);\n\n    l. articles of Chapter 95 (for example, toys, games, sports requisites); or\n\n    m. buttons, press-fasteners, snap-fasteners, press-studs, button moulds or other parts of these articles, button blanks, of heading 9606.\n\n3. (A) In addition to the provisions of note 2 above, heading 4202 does not cover:\n\n    - a. bags made of sheeting of plastics, whether or not printed, with handles, not designed for prolonged use (heading 3923);\n\n    - b. articles of plaiting materials (heading 4602).\n\n    (B) Articles of heading 4202 and 4203 which have parts of precious metal or metal clad with precious metal, of natural or cultured pearls, of precious or semi-precious stones (natural, synthetic or reconstructed) remain classified in those headings, even if such parts constitute more than minor fittings or minor ornamentation, provided that these parts do not give the articles their essential character. If, on the other hand, the parts give the articles their essential character, the articles are to be classified in Chapter 71.\n\n4. For the purposes of heading 4203, the expression \'articles of apparel and clothing accessories\' applies, inter alia, to gloves, mittens and mitts (including those for sport or for protection), aprons and other protective clothing, braces, belts, bandoliers and wrist straps, but excluding watch straps (heading 9113).\n\n### Additional chapter note\n\n1. For the purposes of the subheadings of heading 4202, the term \'outer surface\' is to refer to the material of the outer surface of the container being visible to the naked eye, even where this material is the outer layer of a combination of materials which makes up the outer material of the container.', note_length: 2870 },
  { chapter_number: 43, chapter_code: '43', description: 'FURSKINS AND ARTIFICIAL FUR; MANUFACTURES THEREOF', chapter_note: '1. Throughout the nomenclature, references to \'fur skins\', other than to raw fur skins of heading 4301, apply to hides or skins of all animals which have been tanned or dressed with the hair or wool on.\n\n2. This Chapter does not cover:\n\n    (a) bird skins or parts of bird skins, with their feathers or down (heading 0505 or 6701);\n\n    (b) raw hides or skins, with the hair or wool on, of Chapter 41 (see Note 1 (c) to that Chapter);\n\n    (c) gloves, mittens and mitts consisting of leather and fur skin or of leather and artificial fur (heading 4203);\n\n    (d) articles of Chapter 64;\n\n    (e) headgear or parts thereof of Chapter 65; or\n\n    (f) articles of Chapter 95 (for example, toys, games, sports requisites).\n\n3. Heading 4303 includes fur skins and parts thereof, assembled with the addition of other materials, and fur skins and parts thereof, sewn together in the form of garments or parts or accessories of garments or in the form of other articles.\n\n4. Articles of apparel and clothing accessories (except those excluded by Note 2) lined with fur skin or artificial fur or to which fur skin or artificial fur is attached on the outside except as mere trimming are to be classified, in heading 4303 or 4304, as the case may be.\n\n5. Throughout the nomenclature, the expression \'artificial fur\' means any imitation of fur skin consisting of wool, hair or other fibres gummed or sewn on to leather, woven fabric or other materials, but does not include imitation fur skins obtained by weaving or knitting (generally, heading 5801 or 6001).', note_length: 1569 },
  { chapter_number: 44, chapter_code: '44', description: 'WOOD AND ARTICLES OF WOOD; WOOD CHARCOAL', chapter_note: '1. This chapter does not cover:\n\n    a. wood, in chips, in shavings, crushed, ground or powdered, of a kind used primarily in perfumery, in pharmacy, or for insecticidal, fungicidal or similar purposes (heading 1211);\n\n    b. bamboos or other materials of a woody nature of a kind used primarily for plaiting, in the rough, whether or not split, sawn lengthwise or cut to length (heading 1401);\n\n    c. wood, in chips, in shavings, ground or powdered, of a kind used primarily in dyeing or in tanning (heading 1404);\n\n    d. activated charcoal (heading 3802);\n\n    e. articles of heading 4202;\n\n    f. goods of Chapter 46;\n\n    g. footwear or parts thereof of Chapter 64;\n\n    h. goods of Chapter 66 (for example, umbrellas and walking sticks and parts thereof);\n\n    ij. goods of heading 6808;\n\n    k. imitation jewellery of heading 7117;\n\n    l. goods of Section XVI or XVII (for example, machine parts, cases, covers, cabinets for machines and apparatus and wheelwrights\' wares);\n\n    m. goods of Section XVIII (for example, clock cases and musical instruments and parts thereof);\n\n    n. parts of firearms (heading 9305);\n\n    o. articles of Chapter 94 (for example, furniture, luminaires and lighting fittings, prefabricated buildings);\n\n    p. articles of Chapter 95 (for example, toys, games, sports requisites);\n\n    q. articles of Chapter 96 (for example, smoking pipes and parts thereof, buttons, pencils, and monopods, bipods, tripods and similar articles) excluding bodies and handles, of wood, for articles of heading 9603; or\n\n    r. articles of Chapter 97 (for example, works of art).\n\n2. In this Chapter, the expression \'densified wood\' means wood which has been subjected to chemical or physical treatment (being, in the case of layers bonded together, treatment in excess of that needed to ensure a good bond), and which has thereby acquired increased density or hardness together with improved mechanical strength or resistance to chemical or electrical agencies.\n\n3. Headings 4414 to 4421 apply to articles of the respective descriptions of particle board or similar board, fibreboard, laminated wood or densified wood as they apply to such articles of wood.\n\n4. Products of heading 4410, 4411 or 4412 may be worked to form the shapes provided for in respect of the goods of heading 4409, curved, corrugated, perforated, cut or formed to shapes other than square or rectangular or submitted to any other operation, provided it does not give them the character of articles of other headings.\n\n5. Heading 4417 does not apply to tools in which the blade, working edge, working surface or other working part is formed by any of the materials specified in note 1 to Chapter 82.\n\n6. Subject to note 1 above and except where the context otherwise requires, any reference to \'wood\' in a heading of this Chapter applies also to bamboos and other materials of a woody nature.\n\n### Subheading notes\n\n1. For the purposes of subheading 4401 31, the expression \'wood pellets\' means by-products, such as cutter shavings, sawdust or chips, of the mechanical wood-processing industry, furniture-making industry or other wood-transformation activities, which have been agglomerated either directly by compression or by the addition of a binder in a proportion not exceeding 3% by weight. Such pellets are cylindrical, with a diameter not exceeding 25mm and a length not exceeding 100mm.\n\n2. For the purposes of subheading 4401 32, the expression “wood briquettes” means by prod-ucts such as cutter shavings, saw dust or chips, of the mechanical wood processing industry, furniture making or other wood transformation activities, which have been agglomerated either directly by compression or by addition of a binder in a proportion not exceeding 3 % by weight. Such briquettes are in the form of cubiform, polyhedral or cylindrical units with the minimum cross-sectional dimension greater than 25 mm. \n\n3. For the purposes of subheading 4407 13, “S-P-F” refers to wood sourced from mixed stands of spruce, pine and fir where the proportion of each species varies and is unknown. \n\n4. For the purposes of subheading 4407 14, “Hem-fir” refers to wood sourced from mixed stands of Western hemlock and fir where the proportion of each species varies and is unknown.  \n\n### Additional chapter notes\n\n1. For the purposes of heading 4405, \'wood flour\' means wood powder of which not more than 8% by weight is retained by a sieve with an aperture of 0.63mm.\n\n2. For the purposes of codes 4414 10 10, 4418 21 10, 4419 20 10, 4420 11 10, and 4420 90 91 \'tropical wood\' means the following tropical woods: Acajou d\'Afrique, Alan, Azob, Balsa, Dark Red Meranti, Dibtou, Ilomba, Imbuia, Iroko, Jelutong, Jongkong, Kapur, Kempas, Keruing, Light Red Meranti, Limba, Mahogany (Swietenia Spp), Makor, Mansonia, Meranti Bakau, Merbau, Obeche, Okoum, palissandre de Para, palissandre de Rio, palissandre de Rose, Ramin, Sapelli, Sipo, Teak, Tiama, Virola, White Lauan, White Meranti, White Seraya and Yellow Meranti.', note_length: 5059 },
  { chapter_number: 45, chapter_code: '45', description: 'CORK AND ARTICLES OF CORK', chapter_note: '1. This chapter does not cover:\n\n    a. footwear or parts of footwear of Chapter 64;\n\n    b. headgear or parts of headgear of Chapter 65; or\n\n    c. articles of Chapter 95 (for example, toys, games, sports requisites).', note_length: 224 },
  { chapter_number: 46, chapter_code: '46', description: 'MANUFACTURES OF STRAW, OF ESPARTO OR OF OTHER PLAITING MATERIALS; BASKETWARE AND WICKERWORK', chapter_note: '1. In this chapter, the expression \'plaiting materials\' means materials in a state or form suitable for plaiting, interlacing or similar processes; it includes straw, osier or willow, bamboos, rattans, rushes, reeds, strips of wood, strips of other vegetable material (for example, strips of bark, narrow leaves and raffia or other strips obtained from broad leaves), unspun natural textile fibres, monofilament and strip and the like of plastics and strips of paper, but not strips of leather or composition leather or of felt or nonwovens, human hair, horsehair, textile rovings or yarns, or monofilament and strip and the like of Chapter 54.\n\n2. This chapter does not cover:\n\n    a. wallcoverings of heading 4814;\n\n    b. twine, cordage, ropes or cables, plaited or not (heading 5607);\n\n    c. footwear or headgear or parts thereof of Chapter 64 or 65;\n\n    d. vehicles or bodies for vehicles of basketware (Chapter 87); or\n\n    e. articles of Chapter 94 (for example, furniture, luminaires and lighting fittings).\n\n3. For the purposes of heading 4601, the expression \'plaiting materials, plaits and similar products of plaiting materials, bound together in parallel strands\' means plaiting materials, plaits and similar products of plaiting materials, placed side by side and bound together, in the form of sheets, whether or not the binding materials are of spun textile materials.', note_length: 1400 },
  { chapter_number: 47, chapter_code: '47', description: 'PULP OF WOOD OR OF OTHER FIBROUS CELLULOSIC MATERIAL; RECOVERED (WASTE AND SCRAP) PAPER OR PAPERBOARD', chapter_note: '1. For the purposes of heading 4702, the expression \'chemical wood pulp, dissolving grades\' means chemical wood pulp having by weight an insoluble fraction of 92% or more for soda or sulphate wood pulp or of 88% or more for sulphite wood pulp after one hour in a caustic soda solution containing 18% sodium hydroxide (NaOH) at 20 °C, and for sulphite wood pulp an ash content that does not exceed 0.15% by weight.', note_length: 413 },
  { chapter_number: 48, chapter_code: '48', description: 'PAPER AND PAPERBOARD; ARTICLES OF PAPER PULP, OF PAPER OR OF PAPERBOARD', chapter_note: '1. For the purposes of this chapter, except where the context otherwise requires, a reference to \'paper\' includes references to paperboard (irrespective of thickness or weight per m<sup>2</sup>).\n\n2. This chapter does not cover:\n\n    - a. articles of Chapter 30;\n\n    - b. stamping foils of heading 3212;\n\n    - c. perfumed papers or papers impregnated or coated with cosmetics (Chapter 33);\n\n    - d. paper or cellulose wadding impregnated, coated or covered with soap or detergent (heading 3401), or with polishes, creams or similar preparations (heading 3405);\n\n    - e. sensitised paper or paperboard of heading 3701 to 3704;\n\n    - f. Paper impregnated with diagnostic or laboratory reagents (heading 3822);\n\n    - g. paper-reinforced stratified sheeting of plastics, or one layer of paper or paperboard coated or covered with a layer of plastics, the latter constituting more than half the total thickness, or articles of such materials, other than wall coverings of heading 4814 (Chapter 39);\n\n    - h. articles of heading 4202 (for example, travel goods);\n\n    - ij. articles of Chapter 46 (manufactures of plaiting material);\n\n    - k. paper yarn or textile articles of paper yarn (Section XI);\n\n    - l. articles of Chapter 64 or 65;\n\n    - m. abrasive paper or paperboard (heading 6805) or paper-or paperboard-backed mica (heading 6814) (paper and paperboard coated with mica powder are, however, to be classified in this Chapter);\n\n    - n. metal foil backed with paper or paperboard (generally Section XIV or Section XV);\n\n    - o. articles of heading 9209;\n\n    - p. articles of Chapter 95 (for example, toys, games, sports requisites);\n\n    - q. articles of Chapter 96 (for example, buttons, sanitary towels (pads) and tampons, napkins (diapers) and napkin liners).\n\n3. Subject to the provisions of note 7, heading 4801 to 4805 include paper and paperboard which have been subjected to calendering, supercalendering, glazing or similar finishing, false water-marking or surface sizing, and also paper, paperboard, cellulose wadding and webs of cellulose fibres, coloured or marbled throughout the mass by any method.\n\n    Except where heading 4803 otherwise requires, these headings do not apply to paper, paperboard, cellulose wadding or webs of cellulose fibres which have been otherwise processed.\n\n4. In this Chapter, the expression \'newsprint\' means uncoated paper of a kind used for the printing of newspapers, of which not less than 50% by weight of the total fibre content consists of wood fibres obtained by a mechanical or chemi-mechanical process, unsized or very lightly sized, having a surface roughness Parker Print Surf (1 MPa) on each side exceeding 2.5 micrometres (microns), weighing not less than 40 g/m<sup>2</sup> and not more than 65 g/m<sup>2</sup> and applies only to paper: (a) in strips or rolls of a width exceeding 28 cm; or (b) in rectangular (including square) sheets with one side exceeding 28 cm and the other side exceeding 15 cm in the unfolded state\n\n5. For the purposes of heading 4802, the expressions \'paper and paperboard, of a kind used for writing, printing or other graphic purposes\' and \'non-perforated punch-cards and punch-tape paper\' mean paper and paperboard made mainly from bleached pulp or from pulp obtained by a mechanical or chemi-mechanical process and satisfying any of the following criteria:\n\n    - (A). For paper or paperboard weighing not more than 150 g/m<sup>2</sup>:\n\n        - a. containing 10% or more of fibres obtained by a mechanical or chemi-mechanical process, and\n\n            1. weighing not more than 80 g/m<sup>2</sup>; or\n\n            2. coloured throughout the mass; or\n\n        - b. containing more than 8% ash, and\n\n            1. weighing not more than 80 g/m<sup>2</sup>; or\n\n            2. coloured throughout the mass; or\n\n        - c. containing more than 3% ash and having a brightness of 60% or more; or\n\n        - d. containing more than 3% but not more than 8% ash, having a brightness less than 60%, and a burst index equal to or less than 2.5 kPa.m<sup>2</sup>/g; or\n\n        - e. containing 3% ash or less, having a brightness of 60% or more and a burst index equal to or less than 2.5 kPa.m<sup>2</sup>/g.\n\n    - (B). For paper or paperboard weighing more than 150 g/m<sup>2</sup>:\n\n        - a. coloured throughout the mass; or\n\n        - b. having a brightness of 60% or more, and\n\n            1. a calliper of 225 micrometres (microns) or less, or\n\n            2. a calliper more than 225 micrometres (microns) but not more than 508 micrometres (microns) and an ash content of more than 3%; or\n\n        - c. having a brightness of less than 60%, a calliper of 254 micrometres (microns) or less and an ash content of more than 8%.\n\n            Heading 4802 does not, however, cover filter paper or paperboard (including tea-bag paper) or felt paper or paperboard.\n\n6. In this chapter, \'kraft paper and paperboard\' means paper and paperboard of which not less than 80% by weight of the total fibre content consists of fibres obtained by the chemical sulphate or soda processes.\n\n7. Except where the terms of the headings otherwise require, paper, paperboard, cellulose wadding and webs of cellulose fibres answering to a description in two or more of the heading 4801 to 4811 are to be classified under that one of such headings which occurs last in numerical order in the nomenclature.\n\n8. Headings 4803 to 4809 apply only to paper, paperboard, cellulose wadding and webs of cellulose fibres:\n\n   - a. in strips or rolls of a width exceeding 36 cm; or\n\n   - b. in rectangular (including square) sheets with one side exceeding 36 cm and the other side exceeding 15 cm in the unfolded state.\n\n9. For the purposes of heading 4814, the expression \'wallpaper and similar wallcoverings\' applies only to:\n\n   - a. paper in rolls, of a width of not less than 45cm and not more than 160cm, suitable for wall or ceiling decoration:\n\n      1. grained, embossed, surface-coloured, design-printed or otherwise surface-decorated (for example with textile flock), whether or not coated or covered with transparent protective plastics;\n\n      2. with an uneven surface resulting from the incorporation of particles of wood, straw, etc;\n\n      3. coated or covered on the face side with plastics, the layer of plastics being grained, embossed, coloured, design-printed or otherwise decorated; or\n\n      4. covered on the face side with plaiting material, whether or not bound together in parallel strands or woven;\n\n   - b. borders and friezes, of paper, treated as above, whether or not in rolls, suitable for wall or ceiling decoration;\n\n   - c. wall coverings of paper made up of several panels, in rolls or sheets, printed so as to make up a scene, design or motif when applied to a wall.\n\n    Products on a base of paper or paperboard, suitable for use both as floor coverings and as wall coverings are to be classified in heading 4823.\n\n10. Heading 4820 does not cover loose sheets or cards, cut to size, whether or not printed, embossed or perforated.\n\n11. Heading 4823 applies, inter alia, to perforated paper or paperboard cards for jacquard or similar machines and paper lace.\n\n12. Except for the goods of heading 4814 or 4821, paper, paperboard, cellulose wadding and articles thereof, printed with motifs, characters or pictorial representations, which are not merely subsidiary to the primary use of the goods, fall in Chapter 49.\n\n\n### Subheading notes\n\n1. For the purposes of subheading 4804.11 and 4804.19, \'kraftliner\' means machine-finished or machineglazed paper and paperboard, of which not less than 80% by weight of the total fibre content consists of wood fibres obtained by the chemical sulphate or soda processes, in rolls, weighing more than 115g/ m<sup>2</sup> and having a minimum Mullen bursting strength as indicated in the following table or the linearly interpolated or extrapolated equivalent for any other weight.\n\n    | Weight (g/m2) | Minimum Mullen bursting strength (kPa) |\n    |---------------|----------------------------------------|\n    | 115           | 393                                    |\n    | 125           | 417                                    |\n    | 200           | 637                                    |\n    | 300           | 824                                    |\n    | 400           | 961                                    |\n\n2. For the purposes of subheading 4804.21 and 4804.29, ‘sack kraft paper’ means machine-finished paper, of which not less than 80% by weight of the total fibre content consists of fibres obtained by the chemical sulphate or soda processes, in rolls, weighing not less than 60 g/m<sup>2</sup> but not more than 115 g/m<sup>2</sup> and meeting one of the following sets of specifications:\n\n    (a) having a Mullen burst index of not less than 3.7kPa.m<sup>2</sup>/g and a stretch factor of more than 4.5% in the cross direction and of more than 2% in the machine direction;\n    \n    (b) having minima for tear and tensile as indicated in the following table or the linearly interpolated equivalent for any other weight:\n\n    | |Minimum tear (mN)|Minimum tear (mN)|Minimum tensile (kN/m)|Minimum tensile (kN/m)|\n    |-|-|-|-|-|\n    |Weight (g/m<sup>2</sup>)|Machine direction|Machine direction plus cross direction|Cross direction|Machine direction plus cross direction|\n    |60|700|1,510|1.9|6|\n    |70|830|1,790|2.3|7.2|\n    |80|965|2,070|2.8|8.3|\n    |100|1,230|2,635|3.7|10.6|\n    |115|1,425|3,060|4.4|12.3|\n\n3. For the purposes of subheading 4805 11, \'semi-chemical fluting paper\' means paper, in rolls, of which not less than 65% by weight of the total fibre content consists of unbleached hardwood fibres obtained by a combination of mechanical and chemical pulping processes, and having a CMT 30 (Corrugated Medium Test with 30 minutes of conditioning) crush resistance exceeding 1.8 newtons/g/m<sup>2</sup> at 50% relative humidity, at 23°C.\n\n4. Subheading 4805 12 covers paper, in rolls, made mainly of straw pulp obtained by a combination of mechanical and chemical pulping processes, weighing 130g/m<sup>2</sup> or more, and having a CMT 30 (Corrugated Medium Test with 30 minutes of conditioning) crush resistance exceeding 1.4 newtons/g/m<sup>2</sup> at 50% relative humidity, at 23°C.\n\n5. Subheadings 4805 24 and 4805 25 cover paper and paperboard made wholly or mainly of pulp of recovered (waste and scrap) paper or paperboard. Testliner may also have a surface layer of dyed paper or of paper made of bleached or unbleached non-recovered pulp. These products have a Mullen burst index of not less than 2 kPa.m<sup>2</sup>/g.\n\n6. For the purposes of subheading 4805 30, \'sulphite wrapping paper\' means machine-glazed paper, of which more than 40% by weight of the total fibre content consists of wood fibres obtained by the chemical sulphite process, having an ash content not exceeding 8% and having a Mullen burst index of not less than 1.47kPa.m<sup>2</sup>/g.\n\n7. For the purposes of subheading 4810 22, \'lightweight coated paper\' means paper, coated on both sides, of a total weight not exceeding 72g/m<sup>2</sup>, with a coating weight not exceeding 15g/m<sup>2</sup> per side, on a base of which not less than 50% by weight of the total fibre content consists of wood fibres obtained by a mechanical process.', note_length: 11459 },
  { chapter_number: 49, chapter_code: '49', description: 'PRINTED BOOKS, NEWSPAPERS, PICTURES AND OTHER PRODUCTS OF THE PRINTING INDUSTRY; MANUSCRIPTS, TYPESCRIPTS AND PLANS', chapter_note: '1. This chapter does not cover:\n\n    a. photographic negatives or positives on transparent bases (Chapter 37);\n\n    b. maps, plans or globes, in relief, whether or not printed (heading 9023);\n\n    c. playing cards or other goods of Chapter 95; or\n\n    d. original engravings. prints or lithographs (heading 9702), postage or revenue stamps, stamp-postmarks, first-day covers, postal stationery or the like of heading 9704, antiques of an age exceeding one hundred years or other articles of Chapter 97.\n\n2. For the purposes of Chapter 49, the term \'printed\' also means reproduced by means of a duplicating machine, produced under the control of an automatic data processing machine, embossed, photographed, photocopied, thermocopied or typewritten.\n\n3. Newspapers, journals and periodicals which are bound otherwise than in paper, and sets of newspapers, journals or periodicals comprising more than one number under a single cover are to be classified in heading 4901, whether or not containing advertising material.\n\n4. Heading 4901 also covers:\n\n    a. a collection of printed reproductions of, for example, works of art or drawings, with a relative text, put up with numbered pages in a form suitable for binding into one or more volumes;\n\n    b. a pictorial supplement accompanying, and subsidiary to, a bound volume; and\n\n    c. printed parts of books or booklets, in the form of assembled or separate sheets or signatures, constituting the whole or a part of a complete work and designed for binding.\n\n    However, printed pictures or illustrations not bearing a text, whether in the form of signatures or separate sheets, fall in heading 4911.\n\n5. Subject to Note 3 to this Chapter, heading 4901 does not cover publications which are essentially devoted to advertising (for example, brochures, pamphlets, leaflets, trade catalogues, yearbooks published by trade associations, tourist propaganda). Such publications are to be classified in heading 4911.\n\n6. For the purposes of heading 4903, the expression \'children\'s picture books\' means books for children in which the pictures form the principal interest and the text is subsidiary.', note_length: 2169 },
  { chapter_number: 50, chapter_code: '50', description: 'SILK', chapter_note: '', note_length: 0 },
  { chapter_number: 51, chapter_code: '51', description: 'WOOL, FINE OR COARSE ANIMAL HAIR; HORSEHAIR YARN AND WOVEN FABRIC', chapter_note: '1. Throughout the nomenclature:\n\n    a. \'wool\' means the natural fibre grown by sheep or lambs;\n\n    b. \'fine animal hair\' means the hair of alpaca, llama, vicuna, camel (including dromedary), yak, angora, Tibetan, Kashmir or similar goats (but not common goats), rabbit (including angora rabbit), hare, beaver, nutria or muskrat;\n\n    c. \'coarse animal hair\' means the hair of animals not mentioned above, excluding brush-making hair and bristles (heading 0502) and horsehair (heading 0511).', note_length: 498 },
  { chapter_number: 52, chapter_code: '52', description: 'COTTON', chapter_note: '### Subheading note\n\nFor the purposes of subheadings 5209 42 and 5211 42, the expression \'denim\' means fabrics of yarns of different colours, of 3-thread or 4-thread twill, including broken twill, warp faced, the warp yarns of which are of one and the same colour and the weft yarns of which are unbleached, bleached, dyed grey or coloured a lighter shade of the colour of the warp yarns.', note_length: 390 },
  { chapter_number: 53, chapter_code: '53', description: 'OTHER VEGETABLE TEXTILE FIBRES; PAPER YARN AND WOVEN FABRICS OF PAPER YARN', chapter_note: '## Additional chapter notes\n\n1.  \n\n    (A) For the purposes of codes 5306 10 90, 5306 20 90 and 5308 20 90, the expression \'put up for retail sale\' in relation to yarn (single, multiple or cabled) means, subject to the exceptions in paragraph (B) below, yarn put up:\n\n    - a. in balls or on cards, reels, tubes or similar supports, of a weight (including support) not exceeding 200 grams;\n\n    - b. in hanks or skeins of a weight not exceeding 125 grams;\n\n    - c. in hanks or skeins comprising several smaller hanks or skeins separated by dividing threads which render them independent one of the other, each of uniform weight not exceeding 125 grams.\n\n    (B) Exceptions\n\n    - (a) multiple or cabled yarn, unbleached, in hanks or skeins;\n\n    - (b) multiple or cabled yarn, put up:\n\n        - (1) in cross-reeled hanks or skeins; or\n\n        - (2) put up on supports or in some other manner indicating its use in the textile industry (for example, on cops, twisting mill tubes, pirns, conical bobbins or spindles, or reeled in the form of cocoons for embroidery looms).', note_length: 1093 },
  { chapter_number: 54, chapter_code: '54', description: 'MAN-MADE FILAMENTS; STRIP AND THE LIKE OF MAN-MADE TEXTILE MATERIALS', chapter_note: '1. Throughout the nomenclature, the term \'man-made fibres\' means staple fibres and filaments of organic polymers produced by manufacturing processes, either:\n\n    a. by polymerisation of organic monomers, to produce polymers such as polyamides, polyesters polyolefins or, polyurethanes, or by chemical modification of polymers produced by this process (for example, poly (vinyl alcohol) prepared by the hydrolysis of poly (vinyl acetate)); or\n\n    b. by dissolution or chemical treatment of natural organic polymers (for example, cellulose) to produce polymers such as cuprammonium rayon (cupro) or viscose rayon, or by chemical modification of natural organic polymers (for example, cellulose, casein, and other proteins or alginic acid) to produce polymers such as cellulose acetate or alginates.\n\n    The terms \'synthetic\' and \'artificial\', used in relation to fibres, mean: synthetic: fibres as defined at (a); artificial: fibres as defined at (b). Strip and the like of heading 5404 or 5405 are not considered to be man-made fibres.\n\n    The terms \'man-made\', \'synthetic\' and \'artificial\' shall have the same meanings when used in relation to \'textile materials\'.\n\n2. Headings 5402 and 5403 do not apply to synthetic or artificial filament tow of Chapter 55.', note_length: 1273 },
  { chapter_number: 55, chapter_code: '55', description: 'MAN-MADE STAPLE FIBRES', chapter_note: '1. Headings 5501 and 5502 apply only to man-made filament tow, consisting of parallel filaments of a uniform length equal to the length of the tow, meeting the following specifications:\n\n    a. length of tow exceeding 2 m;\n\n    b. twist less than 5 turns per metre;\n\n    c. measuring per filament less than 67 decitex;\n\n    d. synthetic filament tow only: the tow must be drawn, that is to say, be incapable of being stretched by more than 100% of its length;\n\n    e. total measurement of tow more than 20 000 decitex.\n\n    Tow of a length not exceeding 2 m is to be classified within heading 5503 or 5504.', note_length: 618 },
  { chapter_number: 56, chapter_code: '56', description: 'WADDING, FELT AND NONWOVENS; SPECIAL YARNS; TWINE, CORDAGE, ROPES AND CABLES AND ARTICLES THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. wadding, felt or nonwovens, impregnated, coated or covered with substances or preparations (for example, perfumes or cosmetics of Chapter 33, soaps or detergents of heading 3401, polishes, creams or similar preparations of heading 3405, fabric softeners of heading 3809), where the textile material is\n    present merely as a carrying medium;\n\n    b. textile products of heading 5811;\n\n    c. natural or artificial abrasive powder or grain, on a backing of felt or nonwovens (heading 6805);\n\n    d. agglomerated or reconstituted mica, on a backing of felt or nonwovens (heading 6814);\n\n    e. metal foil on a backing of felt or nonwovens (generally Section XIV or Section XV); \n\n    or\n\n    f. sanitary towels (pads) and tampons, napkins (diapers) and napkin liners and similar articles, of heading 9619.\n\n2. The term \'felt\' includes needleloom felt and fabrics consisting of a web of textile fibres the cohesion of which has been enhanced by a stitch-bonding process using fibres from the web itself.\n\n3. Headings 5602 and 5603 cover, respectively, felt and nonwovens, impregnated, coated, covered or laminated with plastics or rubber whatever the nature of these materials (compact or cellular).\n\n    Heading 5603 also includes nonwovens in which plastics or rubber forms the bonding substance.\n\n    Headings 5602 and 5603 do not, however, cover:\n\n    a. felt impregnated, coated, covered or laminated with plastics or rubber, containing 50% or less by weight of textile material or felt completely embedded in plastics or rubber (Chapter 39 or 40);\n\n    b. nonwovens, either completely embedded in plastics or rubber, or entirely coated or covered on both sides with such materials, provided that such coating or covering can be seen with the naked eye with no account being taken of any resulting change of colour (Chapter 39 or 40); or\n\n    c. plates, sheets or strips of cellular plastics or cellular rubber combined with felt or nonwovens, where the textile material is present merely for reinforcing purposes (Chapter 39 or 40).\n\n4. Heading 5604 does not cover textile yarn, or strip or the like of heading 5404 or 5405, in which the impregnation, coating or covering cannot be seen with the naked eye (usually Chapter 50 to Chapter 55); for the purpose of this provision, no account should be taken of any resulting change of colour.\n\n###Additional chapter note\n1. Codes 5603 14 20 and 5603 94 20 cover needle-punched sheet, of a weight not exceeding 400 g/m2, of a thickness exceeding 0,5 mm but not exceeding 1,8 mm, impregnated with binders, containing less than 10 % of glass by weight, in rolls of a diameter from 100 cm to 130 cm and of a width from 95 cm to 120 cm.', note_length: 2755 },
  { chapter_number: 57, chapter_code: '57', description: 'CARPETS AND OTHER TEXTILE FLOOR COVERINGS', chapter_note: '1. For the purposes of this chapter, the term \'carpets and other textile floor coverings\' means floor coverings in which textile materials serve as the exposed surface of the article when in use and includes articles having the characteristics of textile floor coverings but intended for use for other purposes.\n\n2. This chapter does not cover floor-covering underlays.', note_length: 371 },
  { chapter_number: 58, chapter_code: '58', description: 'SPECIAL WOVEN FABRICS; TUFTED TEXTILE FABRICS; LACE; TAPESTRIES; TRIMMINGS; EMBROIDERY', chapter_note: '1. This chapter does not apply to textile fabrics referred to in Note 1 to Chapter 59, impregnated, coated, covered or laminated, or to other goods of Chapter 59.\n\n2. Heading 5801 also includes woven weft pile fabrics which have not yet had the floats cut, at which stage they have no pile standing up.\n\n3. For the purposes of heading 5803, \'gauze\' means a fabric with a warp composed wholly or in part of standing or ground threads and crossing or doup threads which cross the standing or ground threads making a half-turn, a complete turn or more to form loops through which weft threads pass.\n\n4. Heading 5804 does not apply to knotted net fabrics of twine, cordage or rope, of heading 5608.\n\n5. For the purposes of heading 5806, the expression \'narrow woven fabrics\' means:\n\n    a. woven fabrics of a width not exceeding 30 cm, whether woven as such or cut from wider pieces, provided with selvedges (woven, gummed or otherwise made) on both edges;\n\n    b. tubular woven fabrics of a flattened width not exceeding 30 cm; and\n\n    c. bias binding with folded edges, of a width when unfolded not exceeding 30 cm.\n\n    Narrow woven fabrics with woven fringes are to be classified in heading 5808.\n\n6. In heading 5810, the expression \'embroidery\' means, inter alia, embroidery with metal or glass thread on a visible ground of textile fabric, and sewn applique work of sequins, beads or ornamental motifs of textile or other materials. The heading does not apply to needlework tapestry (heading 5805).\n\n7. In addition to the products of heading 5809, this chapter also includes articles made of metal thread and of a kind used in apparel, as furnishing fabrics or for similar purposes.', note_length: 1705 },
  { chapter_number: 59, chapter_code: '59', description: 'IMPREGNATED, COATED, COVERED OR LAMINATED TEXTILE FABRICS; TEXTILE ARTICLES OF A KIND SUITABLE FOR INDUSTRIAL USE', chapter_note: '1. Except where the context otherwise requires, for the purposes of this chapter, the expression \'textile fabrics\' applies only to the woven fabrics of Chapter 50 to Chapter 55 and heading 5803 and 5806, the braids and ornamental trimmings in the piece of heading 5808 and the knitted or crocheted fabrics of heading 6002 to 6006.\n\n2. Heading 5903 applies to:\n\n    a. textile fabrics, impregnated, coated, covered or laminated with plastics, whatever the weight per square metre and whatever the nature of the plastic material (compact or cellular), other than:\n\n    (1) fabrics in which the impregnation, coating or covering cannot be seen with the naked eye (usually, Chapter 50 to Chapter 55, Chapter 58 or Chapter 60); for the purpose of this provision, no account should be taken of any resulting change of colour;\n\n    (2) products which cannot, without fracturing, be bent manually around a cylinder of a diameter of 7 mm, at a temperature between 15 and 30°C (usually, Chapter 39);\n\n    (3) products in which the textile fabric is either completely embedded in plastics or entirely coated or covered on both sides with such material, provided that such coating or covering can be seen with the naked eye with no account being taken of any resulting change of colour (Chapter 39);\n\n    (4) fabrics partially coated or partially covered with plastics and bearing designs resulting from these treatments (usually, Chapters 50 to 55, 58 or 60);\n\n    (5) plates, sheets or strip of cellular plastics, combined with textile fabric, where the textile fabric is present merely for reinforcing purposes (Chapter 39); or\n\n    (6) textile products of heading 5811;\n\n    b. fabrics made from yarn, strip or the like, impregnated, coated, covered or sheathed with plastics, of heading 5604.\n\n3. For the purposes of heading 5903, “textile fabrics laminated with plastics” means products made by the assembly of one or more layers of fabrics with one or more sheets or film of plastics which are combined by any process that bonds the layers together, whether or not the sheets or film of plastics are visible to the naked eye in the cross-section.\n\n4. For the purposes of heading 5905, the expression \'textile wallcoverings\' applies to products in rolls, of a width of not less than 45 cm, suitable for wall or ceiling decoration, consisting of a textile surface which has been fixed on a backing or has been treated on the back (impregnated or coated to permit pasting).\n\n    This heading does not, however, apply to wallcoverings consisting of textile flock or dust fixed directly on a backing of paper (heading 4814) or on a textile backing (generally, heading 5907).\n\n5. For the purposes of heading 5906, the expression \'rubberised textile fabrics\' means:\n\n    a. textile fabrics impregnated, coated, covered or laminated with rubber:\n\n    - weighing not more than 1,500 g/m<sup>2</sup>; or\n\n    - weighing more than 1,500 g/m<sup>2</sup> and containing more than 50% by weight of textile material;\n\n    b. fabrics made from yarn, strip or the like, impregnated, coated, covered or sheathed with rubber, of heading 5604; and\n\n    c. fabrics composed of parallel textile yarns agglomerated with rubber, irrespective of their weight per square metre. This heading does not, however, apply to plates, sheets or strip of cellular rubber, combined with textile fabric, where the textile fabric is present merely for reinforcing purposes (Chapter 40), or textile products of heading 5811.\n\n6. Heading 5907 does not apply to:\n\n    a. fabrics in which the impregnation, coating or covering cannot be seen with the naked eye (usually Chapters 50 to 55, 58 or 60); for the purpose of this provision, no account should be taken of any resulting change of colour;\n\n    b. fabrics painted with designs (other than painted canvas being theatrical scenery, studio back-cloths or the like);\n\n    c. fabrics partially covered with flock, dust, powdered cork or the like and bearing designs resulting from these treatments. However, imitation pile fabrics remain classified in this heading.\n\n    d. fabrics finished with normal dressings having a basis of amylaceous or similar substances;\n\n    e. wood veneered on a backing of textile fabrics (heading 4408);\n\n    f. natural or artificial abrasive powder or grain, on a backing of textile fabrics (heading 6805);\n\n    g. agglomerated or reconstituted mica, on a backing of textile fabrics (heading 6814); \n\n    or\n\n    h. metal foil on a backing of textile fabrics (generally Section XIV or XV).\n\n7. Heading 5910 does not apply to:\n\n    a. transmission or conveyor belting, of textile material, of a thickness of less than 3 mm; or\n\n    b. transmission or conveyor belts or belting of textile fabric impregnated, coated, covered or laminated with rubber or made from textile yarn or cord impregnated, coated, covered or sheathed with rubber (heading 4010).\n\n8. Heading 5911 applies to the following goods, which do not fall in any other heading of Section XI:\n\n    a. textile products in the piece, cut to length or simply cut to rectangular (including square) shape (other than those having the character of the products of heading 5908 to 5910), the following only:\n\n    - textile fabrics, felt and felt-lined woven fabrics, coated, covered or laminated with rubber, leather or other material, of a kind used for card clothing, and similar fabrics of a kind used for other technical purposes; including narrow fabrics made of velvet impregnated with rubber, for covering weaving spindles (weaving beams);\n\n    - bolting cloth;\n\n    - filtering or straining cloth of a kind used in oil-presses or the like, of textile material or of human hair;\n\n    - flat woven textile fabrics with multiple warp or weft, whether or not felted, impregnated or coated, of a kind used in machinery or for other technical purposes;\n\n    - textile fabrics reinforced with metal, of a kind used for technical purposes;\n\n    - cords, braids and the like, whether or not coated, impregnated or reinforced with metal, of a kind used in industry as packing or lubricating materials;\n\n    b. textile articles (other than those of heading 5908 to 5910) of a kind used for technical purposes (for example, textile fabrics and felts, endless or fitted with linking devices, of a kind used in papermaking or similar machines (for example, for pulp or asbestos-cement), gaskets, washers, polishing discs and other machinery parts).\n\n### Additional chapter note\n\n1. The term “bolting cloth, not made up” as regards code 5911 20 00 applies when the goods are indelibly marked in a way identifying them as being intended for bolting or similar industrial purposes.', note_length: 6747 },
  { chapter_number: 60, chapter_code: '60', description: 'KNITTED OR CROCHETED FABRICS', chapter_note: '1. This chapter does not cover:\n\n    a. crochet lace of heading 5804;\n\n    b. labels, badges and similar articles, knitted or crocheted, of heading 5807; or\n\n    c. knitted or crocheted fabrics, impregnated, coated, covered or laminated, of Chapter 59. However, knitted\n    or crocheted pile fabrics, impregnated, coated, covered or laminated, remain classified in heading 6001.\n\n2. This chapter also includes fabrics made of metal thread and of a kind used in apparel, as furnishing fabrics or for similar purposes.\n\n3. Throughout the nomenclature, any reference to \'knitted goods\' includes a reference to stitch-bonded goods in which the chain stitches are formed of textile yarn.\n\n### Subheading note\n\nSubheading 6005 35 covers fabrics of polyethylene monofilament or of polyester multifilament, weighing not less than 30 g/m<sup>2</sup> and not more than 55 g/m<sup>2</sup>, having a mesh size of not less than 20 holes/cm<sup>2</sup> and not more than 100 holes/cm<sup>2</sup>, and impregnated or coated with alpha-cypermethrin (ISO), chlorfenapyr (ISO), deltamethrin (INN, ISO), lambda-cyhalothrin (ISO), permethrin (ISO) or pirimiphos-methyl (ISO).', note_length: 1170 },
  { chapter_number: 61, chapter_code: '61', description: 'ARTICLES OF APPAREL AND CLOTHING ACCESSORIES, KNITTED OR CROCHETED', chapter_note: '1. This chapter applies only to made up knitted or crocheted articles.\n\n2. This chapter does not cover:\n\n   - a. goods of heading 6212;\n\n   - b. worn clothing or other worn articles of heading 6309; or\n\n   - c. orthopaedic appliances, surgical belts, trusses or the like (heading 9021).\n\n3. For the purposes of heading 6103 and 6104:\n\n   - a. the term \'suit\' means a set of garments composed of two or three pieces made up, in respect of their outer surface, in identical fabric and comprising:\n\n     - one suit coat or jacket the outer shell of which, exclusive of sleeves, consists of four or more panels, designed to cover the upper part of the body, possibly with a tailored waistcoat in addition whose front is made from the same fabric as the outer surface of the other components of the set and whose back is made from the same fabric as the lining of the suit coat or jacket; and\n\n     - one garment designed to cover the lower part of the body and consisting of trousers, breeches or shorts (other than swimwear), a skirt or a divided skirt, having neither braces nor bibs.\n\n    All of the components of a \'suit\' must be of the same fabric construction, colour and composition; they must also be of the same style and of corresponding or compatible size. However, these components may have piping (a strip of fabric sewn into the seam) in a different fabric.\n\n    If several separate components to cover the lower part of the body are presented together (for example, two pairs of trousers or trousers and shorts, or a skirt or divided skirt and trousers), the constituent lower part shall be one pair of trousers or, in the case of women\'s or girls\' suits, the skirt or divided skirt, the other garments being considered separately.\n\n    The term \'suit\' includes the following sets of garments, whether or not they fulfil all the above conditions:\n\n      - morning dress, comprising a plain jacket (cutaway) with rounded tails hanging well down at the back and striped trousers;\n\n      - evening dress (tailcoat), generally made of black fabric, the jacket of which is relatively short at the front, does not close and has narrow skirts cut in at the hips and hanging down behind;\n\n      - dinner jacket suits, in which the jacket is similar in style to an ordinary jacket (though perhaps revealing more of the shirt-front), but has shiny silk or imitation silk lapels.\n\n    - b. The term \'ensemble\' means a set of garments (other than suits and articles of heading 6107, 6108 or 6109), composed of several pieces made up in identical fabric, put up for retail sale, and comprising:\n\n     - one garment designed to cover the upper part of the body, with the exception of pullovers which may form a second upper garment in the sole context of twin sets, and of waistcoats which may also form a second upper garment, and\n\n     - one or two different garments, designed to cover the lower part of the body and consisting of trousers, bib and brace overalls, breeches, shorts (other than swimwear), a skirt or a divided skirt.\n\n     All of the components of an ensemble must be of the same fabric construction, style, colour and composition; they also must be of corresponding or compatible size. The term \'ensemble\' does not apply to track suits or ski suits, of heading 6112.\n\n4. Headings 6105 and 6106 do not cover garments with pockets below the waist, with a ribbed waistband or other means of tightening at the bottom of the garment, or garments having an average of less than 10 stitches per linear centimetre in each direction counted on an area measuring at least 10cm x 10cm. Heading 6105 does not cover sleeveless garments.\n\n    “Shirts” and “shirt-blouses” are garments designed to cover the upper part of the body, having long or short sleeves and a full or partial opening starting at the neckline. “Blouses” are loose-fitting garments also designed to cover the upper part of the body but may be sleeveless and with or without an opening at the neckline. “Shirts”, “shirt-blouses” and “blouses” may also have a collar. \n\n5. Heading 6109 does not cover garments with a drawstring, ribbed waistband or other means of tightening at the bottom of the garment.\n\n6. For the purposes of heading 6111:\n\n   - a. the expression \'babies garments and clothing accessories\' means articles for young children of a body height not exceeding 86cm;\n\n   - b. articles which are prima facie, classifiable both in heading 6111 and in other headings of this Chapter are to be classified in heading 6111.\n\n7. For the purposes of heading 6112 \'ski suits\' means garments or sets of garments which, by their general appearance and texture, are identifiable as intended to be worn principally for skiing (cross country or alpine). They consist of either:\n\n   - a. a \'ski overall\', that is, a one-piece garment designed to cover the upper and the lower parts of the body; in addition to sleeves and a collar, the ski overall may have pockets or footstraps; or\n\n   - b. a \'ski ensemble\', that is, a set of garments composed of two or three pieces, put up for retail sale and comprising:\n\n     - one garment such as an anorak, windcheater, wind jacket or similar article, closed by a slide fastener (zipper), possibly with a waistcoat in addition, and\n\n     - one pair of trousers, whether or not extending above waist-level, one pair of breeches or one bib and brace overall.\n\n   The \'ski ensemble\' may also consist of an overall similar to the one mentioned in paragraph (a) above and a type of padded sleeveless jacket worn over the overall.\n\n   All the components of a \'ski ensemble\' must be made up in a fabric of the same texture, style and composition whether or not of the same colour; they also must be of corresponding or compatible size.\n\n8. Garments which are, prima facie, classifiable both in heading 6113 and in other headings of this Chapter, excluding heading 6111, are to be classified in heading 6113.\n\n9. Garments of this Chapter designed for left over right closure at the front shall be regarded as men\'s or boys\' garments, and those designed for right over left closure at the front as women\'s or girls\' garments.\n\n    These provisions do not apply where the cut of the garment clearly indicates that it is designed for one or other of the sexes.\n\n    Garments which cannot be identified as either men\'s or boys\' garments or as women\'s or girls\' garments areto be classified in the headings covering women\'s or girls\' garments.\n\n10. Articles of this chapter may be made of metal thread.\n\n### Additional chapter notes\n\n1. For the application of note 3 (b) to this chapter, the components of an ensemble must be made up entirely in a single identical fabric, subject to compliance with the other conditions laid down in the said note.\n\n    For this purpose:\n\n      - the fabric used can be unbleached, bleached, dyed, of yarns of different colours or printed.\n\n      - a pullover or waistcoat with ribbing is to be considered as a component of an ensemble, even if there is no ribbing on the component intended to cover the lower part of the body, provided that the ribbing is not sewn on but produced directly by the knitting process.\n\n    Sets of garments are not regarded as ensembles when their components are made up in different fabrics, even if the difference is due only to their respective colours.\n\n    All the components of an ensemble must be presented together for retail sale as a single unit. Individual wrapping or separate labelling of each component of such a single unit does not influence its classification as an ensemble.\n\n2. For the purposes of heading 6109, the terms \'singlets\' and \'other vests\' include garments, even if of a fancy design, worn next to the body, without collar, with or without sleeves, including those with shoulder straps.\n\n    These garments, which are intended to cover the upper part of the body, often possess many characteristics in common with those of T-shirts or with more traditional kinds of singlets and other vests of heading 6109.\n\n3. Heading 6111 and codes 6116 10 20 and 6116 10 80 include gloves, mittens and mitts, impregnated, coated or covered with plastics or rubber, even if they are:\n\n   - made up from knitted or crocheted textile fabrics impregnated, coated or covered with plastics or rubber of heading 5903 or 5906\n\n   - or made up from unimpregnated, uncoated or uncovered knitted or crocheted textile fabrics and subsequently impregnated, coated or covered with plastics or rubber.\n\n    Where knitted or crocheted textile fabrics serve only as reinforcement, gloves, mittens or mitts impregnated, coated or covered with cellular plastics or cellular rubber belong in Chapters 39 or 40, even if they are made up from unimpregnated, uncoated or uncovered knitted or crocheted textile fabrics and subsequently impregnated, coated or covered with cellular plastics or cellular rubber (note 2(a)(5) and note 5, last paragraph, to Chapter 59).', note_length: 9021 },
  { chapter_number: 62, chapter_code: '62', description: 'ARTICLES OF APPAREL AND CLOTHING ACCESSORIES, NOT KNITTED OR CROCHETED', chapter_note: '1. This chapter applies only to made-up articles of any textile fabric other than wadding, excluding knitted or crocheted articles (other than those of heading 6212).\n\n2. This chapter does not cover:\n\n    a. worn clothing or other worn articles of heading 6309; or\n\n    b. orthopaedic appliances, surgical belts, trusses or the like (heading 9021).\n\n3. For the purposes of heading 6203 and 6204:\n\n    a. the term \'suit\' means a set of garments composed of two or three pieces made up, in respect of their outer surface, in identical fabric and comprising:\n\n    - one suit coat or jacket the outer shell of which, exclusive of sleeves, consists of four or more panels, designed to cover the upper part of the body, possibly with a tailored waistcoat in addition whose front is made from the same fabric as the outer surface of the other components of the set and whose back is made from the same fabric as the lining of the suit coat or jacket; and\n\n    - one garment designed to cover the lower part of the body and consisting of trousers, breeches or shorts (other than swimwear), a skirt or a divided skirt, having neither braces nor bibs.\n\n        All of the components of a \'suit\' must be of the same fabric construction, colour and composition; they must also be of the same style and of corresponding or compatible size. However, these components may have piping (a strip of fabric sewn into the seam) in a different fabric.\n\n        If several separate components to cover the lower part of the body are presented together (for example, two pairs of trousers or trousers and shorts, or a skirt or divided skirt and trousers), the constituent lower part shall be one pair of trousers or, in the case of women\'s or girls\' suits, the skirt or divided skirt, the other garments being considered separately.\n\n    The term \'suit\' includes the following sets of garments, whether or not they fulfil all the above conditions:\n\n    - morning dress, comprising a plain jacket (cutaway) with rounded tails hanging well down at the back and striped trousers;\n\n    - evening dress (tailcoat), generally made of black fabric, the jacket of which is relatively short at the front, does not close and has narrow skirts cut in at the hips and hanging down behind;\n\n    - dinner jacket suits, in which the jacket is similar in style to an ordinary jacket (though perhaps revealing more of the shirt front), but has shiny silk or imitation silk lapels.\n\n    b. the term \'ensemble\' means a set of garments (other than suits and articles of heading 6207 or 6208) composed of several pieces made up in identical fabric, put up for retail sale, and comprising:\n\n    - one garment designed to cover the upper part of the body, with the exception of waistcoats which may also form a second upper garment, and\n\n    - one or two different garments, designed to cover the lower part of the body and consisting of trousers, bib and brace overalls, breeches, shorts (other than swimwear), a skirt or a divided skirt.\n\n    All of the components of an ensemble must be of the same fabric construction, style, colour and composition; they also must be of corresponding or compatible size. The term \'ensemble\' does not apply to track suits or ski suits, of heading 6211.\n\n4. Headings 6205 and 6206 do not cover garments with pockets below the waist, with a ribbed waistband or other means of tightening at the bottom of the garment. Heading 6205 does not cover sleeveless garments. \n\n    “Shirts” and “shirt-blouses” are garments designed to cover the upper part of the body, having long or short sleeves and a full or partial opening starting at the neckline. “Blouses” are loose-fitting garments also designed to cover the upper part of the body but may be sleeveless and with or without an opening at the neckline. “Shirts”, “shirt-blouses” and “blouses” may also have a collar.\n\n5. For the purposes of heading 6209:\n\n    a. the expression \'babies\' garments and clothing accessories\' means articles for young children of a body height not exceeding 86cm;\n\n    b. articles which are, prima facie, classifiable both in heading 6209 and in other headings of this chapter are to be classified in heading 6209.\n\n6. Garments which are, prima facie, classifiable both in heading 6210 and in other headings of this chapter, excluding heading 6209, are to be classified in heading 6210.\n\n7. For the purposes of heading 6211, \'ski suits\' means garments or sets of garments which, by their general appearance and texture, are identifiable as intended to be worn principally for skiing (cross-country or alpine). \n\n    They consist either of:\n\n    a. a \'ski overall\', that is, a one-piece garment designed to cover the upper and the lower parts of the body; in addition to sleeves and a collar, the ski overall may have pockets or footstraps; or\n\n    b. a \'ski ensemble\', that is, a set of garments composed of two or three pieces, put up for retail sale and comprising:\n\n    - one garment such as an anorak, windcheater, wind-jacket or similar article, closed by a slide fastener (zipper), possibly with a waistcoat in addition, and\n\n    - one pair of trousers, whether or not extending above waist-level, one pair of breeches or one bib and brace overall.\n\n    The \'ski ensemble\' may also consist of an overall similar to the one mentioned in paragraph (a) above and a type of padded, sleeveless jacket worn over the overall.\n\n    All the components of a \'ski-ensemble\' must be made up in a fabric of the same texture, style and composition, whether or not of the same colour; they also must be of corresponding or compatible size.\n\n8. Scarves and articles of the scarf type, square or approximately square, of which no side exceeds 60cm, are to be classified as handkerchiefs (heading 6213). \n\n    Handkerchiefs of which any side exceeds 60cm are to be classified in heading 6214.\n\n9. Garments of this Chapter designed for left over right closure at the front shall be regarded as men\'s or boys\' garments, and those designed for right over left closure at the front as women\'s or girls\' garments.\n\n    These provisions do not apply where the cut of the garment clearly indicates that it is designed for one or other of the sexes.\n\n    Garments which cannot be identified as either men\'s or boys\' garments or as women\'s or girls\' garments are to be classified in the headings covering women\'s or girls\' garments.\n\n10. Articles of this chapter may be made of metal thread.\n\n### Additional chapter notes\n\n1. For the application note 3 (b) of this chapter, the components of an ensemble must be made up entirely in a single identical fabric, subject to compliance with the other conditions laid down in the said note.\n\n    For this purpose, the fabric used can be unbleached, bleached, dyed, of yarns of different colours or printed. Sets of garments are not regarded as ensembles when their components are made up in different fabrics, even if the difference is due only to their respective colours.\n\n    All the components of an ensemble must be presented together for retail sale as a single unit. Individual wrapping or separate labelling of each component of such a single unit does not influence its classification\nas an ensemble.\n\n2. Headings 6209 and 6216 include gloves, mittens and mitts, impregnated, coated or covered with plastics or rubber, even if they are:\n\n    - made up from textile fabrics (other than knitted or crocheted) impregnated, coated or covered with plastics or rubber of heading 5903 or 5906, or\n\n    - made up from unimpregnated, uncoated or uncovered textile fabrics (other than knitted or crocheted) and subsequently impregnated, coated or covered with plastics or rubber.\n\n    Where textile fabrics (other than knitted or crocheted) serve only as reinforcement, gloves, mittens or mitts impregnated, coated or covered with cellular plastics or cellular rubber belong in Chapters 39 or 40, even if they are made up from unimpregnated, uncoated or uncovered textile fabrics (other than knitted or crocheted) and subsequently impregnated, coated or covered with cellular plastics or cellular rubber (Note 2(a)(5) and note 5, last paragraph to Chapter 59).\n\n3. Code 6212 10 90 includes knitted brassières (so-called mastectomy bras), which typically comprise adjustable broad padded shoulder straps, centrally positioned over the breasts, with shaped cups and elastication at the back part of the base. The articles are closed by means of an adjustable ‘hook and eye fastening’.\n\n    The brassières have a lining in the cups, with side openings for the insertion of padding for the enhancement of breasts (aesthetic purposes) or for the insertion of breast forms following a mastectomy.', note_length: 8774 },
  { chapter_number: 63, chapter_code: '63', description: 'OTHER MADE-UP TEXTILE ARTICLES; SETS; WORN CLOTHING AND WORN TEXTILE ARTICLES; RAGS', chapter_note: '1. Sub-Chapter I applies only to made up articles, of any textile fabric.\n\n2. Sub-Chapter I does not cover:\n\n    a. goods of Chapters 56 to 62; or\n\n    b. worn clothing or other worn articles of heading 6309.\n\n3. Heading 6309 applies only to the following goods:\n\n    a. articles of textile materials:\n\n    - clothing and clothing accessories, and parts thereof;\n\n    - blankets and travelling rugs;\n\n    - bedlinen, table linen, toilet linen and kitchen linen;\n\n    - furnishing articles, other than carpets of heading 5701 to 5705 and tapestries of heading 5805;\n\n    b. footwear and headgear of any material other than asbestos.\n\n    In order to be classified in this heading, the articles mentioned above must comply with both of the following requirements:\n\n    - they must show signs of appreciable wear, and\n\n    - they must be presented in bulk or in bales, sacks or similar packings.\n\n### Subheading note\n\n1. Subheading 6304 20 covers articles made from warp knit fabrics, impregnated or coated with alphacypermethrin (ISO), chlorfenapyr (ISO), deltamethrin (INN, ISO), lambda-cyhalothrin (ISO), permethrin (ISO) or pirimiphos-methyl (ISO).', note_length: 1179 },
  { chapter_number: 64, chapter_code: '64', description: 'FOOTWEAR, GAITERS AND THE LIKE; PARTS OF SUCH ARTICLES', chapter_note: '1. This chapter does not cover:\n\n    a. disposable foot or shoe coverings of flimsy material (for example, paper, sheeting of plastics) without applied soles. These products are classified according to their constituent material;\n\n    b. footwear of textile material, without an outer sole glued, sewn or otherwise affixed or applied to the upper (Section XI);\n\n    c. worn footwear of heading 6309;\n\n    d. articles of asbestos (heading 6812);\n\n    e. orthopaedic footwear or other orthopaedic appliances, or parts thereof (heading 9021); or\n\n    f. toy footwear or skating boots with ice or roller skates attached; shin-guards or similar protective sportswear (Chapter 95).\n\n2. For the purposes of heading 6406, the term \'parts\' does not include pegs, protectors, eyelets, hooks, buckles, ornaments, braid, laces, pompons or other trimmings (which are to be classified in their appropriate headings) or buttons or other goods of heading 9606.\n\n3. For the purposes of this Chapter:\n\n    a. the terms \'rubber\' and \'plastics\' include woven fabrics or other textile products with an external layer of rubber or plastics being visible to the naked eye; for the purpose of this provision, no account should be taken of any resulting change of colour; and\n\n    b. the term \'leather\' refers to the goods of heading 4107 and 4112 to 4114.\n\n4. Subject to Note 3 to this chapter:\n\n    a. the material of the upper shall be taken to be the constituent material having the greatest external surface area, no account being taken of accessories or reinforcements such as ankle patches, edging,\n    ornamentation, buckles, tabs, eyelet stays or similar attachments;\n\n    b. the constituent material of the outer sole shall be taken to be the material having the greatest surface area in contact with the ground, no account being taken of accessories or reinforcements such as spikes, bars, nails, protectors or similar attachments.\n\n### Subheading note\n\n1. For the purposes of subheadings 6402 12, 6402 19, 6403 12, 6403 19 and 6404 11, the expression \'sports footwear\' applies only to:\n\n    a. footwear which is designed for a sporting activity and has, or has provision for the attachment of, spikes, sprigs, stops, clips, bars or the like;\n\n    b. skating boots, ski-boots and cross-country ski footwear, snowboard boots, wrestling boots, boxing boots and cycling shoes.\n\n### Additional chapter notes\n\n1. Within the meaning of Note 4 (a), \'reinforcements\' is taken to mean all pieces of material (for example, plastics or leather) attached to the external surface of the upper to give additional strength, whether or not also attached to the sole. \n\n    After the removal of reinforcements, the visible material must have the\n    characteristics of an upper and not lining, supporting the foot sufficiently to enable the wearer, with the original fastening systems in place, to walk in the footwear.\n\n    Account is to be taken of sections covered by accessories or reinforcements when deciding on the composition of the upper.\n\n2. Within the meaning of note 4 (b), one or more layers of textile material which do not possess the characteristics usually required for normal use of an outer sole (for example, durability, strength, etc.) are not to be taken into consideration for classification purposes.', note_length: 3339 },
  { chapter_number: 65, chapter_code: '65', description: 'HEADGEAR AND PARTS THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. worn headgear of heading 6309;\n\n    b. asbestos headgear (heading 6812); or\n\n    c. dolls\' hats, other toy hats or carnival articles of Chapter 95.\n\n2. Heading 6502 does not cover hat-shapes made by sewing, other than those obtained simply by sewing strips in spirals.', note_length: 316 },
  { chapter_number: 66, chapter_code: '66', description: 'UMBRELLAS, SUN UMBRELLAS, WALKING STICKS, SEAT-STICKS, WHIPS, RIDING-CROPS AND PARTS THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. measure walking sticks or the like (heading 9017);\n\n    b. firearm-sticks, swordsticks, loaded walking sticks or the like (Chapter 93); or\n\n    c. goods of Chapter 95 (for example, toy umbrellas, toy sun umbrellas).\n\n2. Heading 6603 does not cover parts, trimmings or accessories of textile material, or covers, tassels, thongs, umbrella cases or the like, of any material. Such goods presented with, but not fitted to, articles of heading 6601 or 6602 are to be classified separately and are not to be treated as forming part of those articles.', note_length: 593 },
  { chapter_number: 67, chapter_code: '67', description: 'PREPARED FEATHERS AND DOWN AND ARTICLES MADE OF FEATHERS OR OF DOWN; ARTIFICIAL FLOWERS; ARTICLES OF HUMAN HAIR', chapter_note: '1. This chapter does not cover:\n\n    a. filtering or straining cloth of human hair (heading 5911);\n\n    b. floral motifs of lace, of embroidery or other textile fabric (Section XI);\n\n    c. footwear (Chapter 64);\n\n    d. headgear or hairnets (Chapter 65);\n\n    e. toys, sports requisites or carnival articles (Chapter 95); or\n\n    f. feather dusters, powder-puffs or hair sieves (Chapter 96).\n\n2. Heading 6701 does not cover:\n\n    a. articles in which feathers or down constitute only filling or padding (for example, bedding of heading 9404);\n\n    b. articles of apparel or clothing accessories in which feathers or down constitute no more than mere trimming or padding; or\n\n    c. artificial flowers or foliage or parts thereof or made up articles of heading 6702.\n\n3. Heading 6702 does not cover:\n\n    a. articles of glass (Chapter 70); or\n\n    b. artificial flowers, foliage or fruit of pottery, stone, metal, wood or other materials, obtained in one piece by moulding, forging, carving, stamping or other process, or consisting of parts assembled otherwise than by binding, glueing, fitting into one another or similar methods.', note_length: 1158 },
  { chapter_number: 68, chapter_code: '68', description: 'ARTICLES OF STONE, PLASTER, CEMENT, ASBESTOS, MICA OR SIMILAR MATERIALS', chapter_note: '1. This chapter does not cover:\n\n    a. goods of Chapter 25;\n\n    b. coated, impregnated or covered paper and paperboard of heading 4810 or 4811 (for example, paper and paperboard coated with mica powder or graphite, bituminised or asphalted paper and paperboard);\n\n    c. coated, impregnated or covered textile fabric of Chapter 56 or 59 (for example, fabric coated or covered with mica powder, bituminised or asphalted fabric);\n\n    d. articles of Chapter 71;\n\n    e. tools or parts of tools, of Chapter 82;\n\n    f. lithographic stones of heading 8442;\n\n    g. electrical insulators (heading 8546) or fittings of insulating material of heading 8547;\n\n    h. dental burrs (heading 9018);\n\n    ij. articles of Chapter 91 (for example, clocks and clock cases);\n\n    k. articles of Chapter 94 (for example, furniture, luminaires and lighting fittings, prefabricated buildings);\n\n    l. articles of Chapter 95 (for example, toys, games and sports requisites);\n\n    m. articles of heading 9602, if made of materials specified in Note 2(b) to Chapter 96, or of heading 9606 (for example, buttons), of heading 9609 (for example, slate pencils), heading 9610 (for example, drawing slates) or of heading 9620 (monopods, bipods, tripods and similar articles); or\n\n    n. articles of Chapter 97 (for example, works of art).\n\n2. In heading 6802, the expression \'worked monumental or building stone\' applies not only to the varieties of stone referred to in heading 2515 or 2516 but also to all other natural stone (for example, quartzite, flint, dolomite and steatite) similarly worked; it does not, however, apply to slate.', note_length: 1641 },
  { chapter_number: 69, chapter_code: '69', description: 'CERAMIC PRODUCTS', chapter_note: '1. This chapter applies only to ceramic products which have been fired after shaping. \n\n    - a. heading 6904 to 6914 apply only to such products other than those classifiable in heading 6901 to 6903;\n\n    - b. articles heated to temperatures less than 800 °C for purposes such as curing of resins, accel-erating hydration reactions, or for the removal of water or other volatile components, are not considered to be fired. Such articles are excluded from Chapter 69; and \n\n    - c. ceramic articles are obtained by firing inorganic, non-metallic materials which have been prepared and shaped previously at, in general, room temperature. Raw materials comprise, inter alia, clays, siliceous materials including fused silica, materials with a high melting point, such as oxides, carbides, nitrides, graphite or other carbon, and in some cases binders such as refractory clays or phosphates. \n\n2. This Chapter does not cover:\n\n    - a. products of heading 2844;\n\n    - b. articles of heading 6804;\n\n    - c. articles of Chapter 71 (for example, imitation jewellery);\n\n    - d. cermets of heading 8113;\n\n    - e. articles of Chapter 82;\n\n    - f. electrical insulators (heading 8546) or fittings of insulating material of heading 8547;\n\n    - g. artificial teeth (heading 9021);\n\n    - h. articles of Chapter 91 (for example, clocks and clock cases);\n\n    - ij articles of Chapter 94 (for example, furniture, luminaires and lighting fittings, prefabricated buildings);\n\n    - k. articles of Chapter 95 (for example, toys, games and sports requisites);\n\n    - l. articles of heading 9606 (for example, buttons) or of heading 9614 (for example, smoking pipes); or \n\n    - m. articles of Chapter 97 (for example, works of art).', note_length: 1753 },
  { chapter_number: 70, chapter_code: '70', description: 'GLASS AND GLASSWARE', chapter_note: '1. This chapter does not cover:\n\n    - a. goods of heading 3207 (for example, vitrifiable enamels and glazes, glass frit, other glass in the form of powder, granules or flakes);\n\n    - b. articles of Chapter 71 (for example, imitation jewellery);\n\n    - c. optical fibre cables of heading 8544, electrical insulators (heading 8546) or fittings of insulating material of heading 8547;\n\n    - d. front windscreens (windshields), rear windows and other windows, framed, for vehicles of Chapter 86 to Chapter 88;\n\n    - e. front windscreens (windshields), rear windows and other windows, whether or not framed, incorporating heating devices or other electrical or electronic devices, for vehicles of Chapter 86 to Chapter 88;\n\n    - f. optical fibres, optically worked optical elements, hypodermic syringes, artificial eyes, thermometers, barometers, hydrometers or other articles of Chapter 90;\n\n    - g. luminaires and lighting fittings, illuminated signs, illuminated nameplates or the like, having a permanently fixed light source, or parts thereof of heading 9405;\n\n    - h. toys, games, sports requisites, Christmas tree ornaments or other articles of Chapter 95 (excluding glass eyes without mechanisms for dolls or for other articles of Chapter 95); or\n\n    - ij. buttons, fitted vacuum flasks, scent or similar sprays or other articles of Chapter 96.\n\n2. For the purposes of heading 7003, 7004 and 7005:\n\n    - a. glass is not regarded as \'worked\' by reason of any process it has undergone before annealing;\n\n    - b. cutting to shape does not affect the classification of glass in sheets;\n\n    - c. the expression \'absorbent, reflecting or non-reflecting layer\' means a microscopically thin coating of metal or of a chemical compound (for example, metal oxide) which absorbs, for example, infra-red light or improves the reflecting qualities of the glass while still allowing it to retain a degree of transparency or translucency; or which prevents light from being reflected on the surface of the glass.\n\n3. The products referred to in heading 7006 remain classified in that heading, whether or not they have the character of articles.\n\n4. For the purposes of heading 7019, the expression \'glass wool\' means:\n\n    - a. mineral wools with a silica (SiO2) content not less than 60% by weight;\n\n    - b. mineral wools with a silica (SiO2) content less than 60% but with an alkaline oxide (K2O or Na2O) content exceeding 5% by weight or a boric oxide (B2O3) content exceeding 2% by weight.\n\n        Mineral wools which do not comply with the above specifications fall in heading 6806.\n\n5. Throughout the nomenclature, the expression \'glass\' includes fused quartz and other fused silica.\n\n### Subheading note\n\n1. For the purposes of subheadings 7013 22, 7013 33, 7013 41 and 7013 91, the expression \'lead crystal\' means only glass having a minimum lead monoxide (PbO) content by weight of 24%.', note_length: 2937 },
  { chapter_number: 71, chapter_code: '71', description: 'NATURAL OR CULTURED PEARLS, PRECIOUS OR SEMI-PRECIOUS STONES, PRECIOUS METALS, METALS CLAD WITH PRECIOUS METAL, AND ARTICLES THEREOF; IMITATION JEWELLERY; COIN', chapter_note: '1. Subject to note 1(A) to Section VI and except as provided below, all articles consisting wholly or partly:\n\n    a. of natural or cultured pearls or of precious or semi-precious stones (natural, synthetic or reconstructed),\n\n    or\n\n    b. of precious metal or of metal clad with precious metal, are to be classified in this chapter.\n\n2. (A) Headings 7113, 7114 and 7115 do not cover articles in which precious metal or metal clad with precious metal is present as minor constituents only, such as minor fittings or minor ornamentation (for example, monograms, ferrules and rims), and paragraph (b) of the foregoing note does not apply to such articles.\n\n    (B) Heading 7116 does not cover articles containing precious metal or metal clad with precious metal (other than as minor constituents).\n\n3. This chapter does not cover:\n\n    a. amalgams of precious metal, or colloidal precious metal (heading 2843);\n\n    b. sterile surgical suture materials, dental fillings or other goods of Chapter 30;\n\n    c. goods of Chapter 32 (for example, lustres);\n\n    d. supported catalysts (heading 3815);\n\n    e. articles of heading 4202 or 4203 referred to in note 3(B) to Chapter 42;\n\n    f. articles of heading 4303 or 4304;\n\n    g. goods of Section XI (textiles and textile articles);\n\n    h. footwear, headgear or other articles of Chapter 64 or 65;\n\n    ij. umbrellas, walking sticks or other articles of Chapter 66;\n\n    k. abrasive goods of heading 6804 or 6805 or Chapter 82, containing dust or powder of precious or semiprecious stones (natural or synthetic); articles of Chapter 82 with a working part of precious or semiprecious stones (natural, synthetic or reconstructed); machinery, mechanical appliances or electrical goods, or parts thereof, of Section XVI. However, articles and parts thereof, wholly of precious or semiprecious stones (natural, synthetic or reconstructed) remain classified in this Chapter, except unmounted worked sapphires and diamonds for styluses (heading 8522);\n\n    l. articles of Chapter 90, 91 or 92 (scientific instruments, clocks and watches, musical instruments);\n\n    m. arms or parts thereof (Chapter 93);\n\n    n. articles covered by note 2 to Chapter 95;\n\n    o. articles classified in Chapter 96 by virtue of note 4 to that chapter; or\n\n    p. original sculptures or statuary (heading 9703), collectors\' pieces (heading 9705) or antiques of an age exceeding 100 years (heading 9706), other than natural or cultured pearls or precious or semi-precious stones.\n\n4. (A) The expression \'precious metal\' means silver, gold and platinum.\n\n    (B) The expression \'platinum\' means platinum, iridium, osmium, palladium, rhodium and ruthenium.\n\n    (C) The expression \'precious or semi-precious stones\' does not include any of the substances specified in note 2(b) to Chapter 96.\n\n5. For the purposes of this chapter, any alloy (including a sintered mixture and an inter-metallic compound) containing precious metal is to be treated as an alloy of precious metal if any one precious metal constitutes as much as 2%, by weight, of the alloy.\n\n    Alloys of precious metal are to be classified according to the following rules:\n\n    a. An alloy containing 2% or more, by weight, of platinum is to be treated as an alloy of platinum.\n\n    b. An alloy containing 2% or more, by weight, of gold but no platinum, or less than 2%, by weight, of platinum, is to be treated as an alloy of gold.\n\n    c. Other alloys containing 2% or more, by weight, of silver are to be treated as alloys of silver.\n\n6. Except where the context otherwise requires, any reference in the nomenclature to precious metal or to any particular precious metal includes a reference to alloys treated as alloys of precious metal or of the particular metal in accordance with the rules in note 5 above, but not to metal clad with precious metal or to base metal or non-metals plated with precious metal.\n\n7. Throughout the nomenclature, the expression \'metal clad with precious metal\' means material made with a base of metal upon one or more surfaces of which there is affixed by soldering, brazing, welding, hotrolling or similar mechanical means a covering of precious metal. Except where the context otherwise requires, the expression also covers base metal inlaid with precious metal.\n\n8. Subject to note 1(A) to Section VI, goods answering to a description in heading 7112 are to be classified in that heading and in no other heading of the nomenclature.\n\n9. For the purposes of heading 7113, the expression \'articles of jewellery\' means:\n\n    a. any small objects of personal adornment (for example, rings, bracelets, necklaces, brooches, earrings, watch-chains, fobs, pendants, tiepins, cuff-links, dress-studs, religious or other medals and insignia); and\n\n    b. articles of personal use of a kind normally carried in the pocket, in the handbag or on the person (for example cigar or cigarette cases, snuff boxes, cachou or pill boxes, powder boxes, chain purses or prayer beads).\n\n    These articles may be combined or set, for example, with natural or cultured pearls, precious or semiprecious stones, synthetic or reconstructed precious or semi-precious stones, tortoise shell, mother-of-pearl, ivory, natural or reconstituted amber, jet or coral.\n\n10. For the purposes of heading 7114, the expression \'articles of goldsmiths\' or silversmiths\' wares\' includes such articles as ornaments, tableware, toilet-ware, smokers\' requisites and other articles of household, office or religious use.\n\n11. For the purposes of heading 7117, the expression \'imitation jewellery\' means articles of jewellery within the meaning of paragraph (a) of note 9 (but not including buttons or other articles of heading 9606, or dresscombs, hairslides or the like, or hairpins, of heading 9615), not incorporating natural or cultured pearls, precious or semi-precious stones (natural, synthetic or reconstructed) nor (except as plating or as minor constituents) precious metal or metal clad with precious metal.\n\n### Subheading notes\n\n1. For the purposes of subheadings 7106 10, 7108 11, 7110 11, 7110 21, 7110 31 and 7110 41, the expressions \'powder\' and \'in powder form\' mean products of which 90% or more by weight passes through a sieve having a mesh aperture of 0.5 mm.\n\n2. Notwithstanding the provisions of chapter note 4(B), for the purposes of subheadings 7110 11 and 7110 19, the expression \'platinum\' does not include iridium, osmium, palladium, rhodium or ruthenium.\n\n3. For the classification of alloys in subheadings of heading 7110, each alloy is to be classified with that metal, platinum, palladium, rhodium, iridium, osmium or ruthenium which predominates by weight over each other of these metals.', note_length: 6784 },
  { chapter_number: 72, chapter_code: '72', description: 'IRON AND STEEL', chapter_note: '1. In this chapter and, in the case of notes (d), (e) and (f) throughout the nomenclature, the following expressions have the meanings hereby assigned to them:\n\n    a. pig Iron\n\n    Iron-carbon alloys not usefully malleable, containing more than 2% by weight of carbon and which may contain by weight one or more other elements within the following limits:\n\n    - not more than 10% of chromium\n\n    - not more than 6% of manganese\n\n    - not more than 3% of phosphorus\n\n    - not more than 8% of silicon\n\n    - a total of not more than 10% of other elements.\n\n    b. spiegeleisen\n\n    Iron-carbon alloys containing by weight more than 6% but not more than 30% of manganese and otherwise conforming to the specification at (a) above.\n\n    c. ferro-alloys\n\n    Alloys in pigs, blocks, lumps or similar primary forms, in forms obtained by continuous casting and also in granular or powder forms, whether or not agglomerated, commonly used as an additive in the manufacture of other alloys or as de-oxidants, de-sulphurising agents or for similar uses in ferrous metallurgy and\n    generally not usefully malleable, containing by weight 4% or more of the element iron and one or more of the following:\n\n    - more than 10% of chromium\n\n    - more than 30% of manganese\n\n    - more than 3% of phosphorus\n\n    - more than 8% of silicon\n\n    - a total of more than 10% of other elements, excluding carbon, subject to a maximum content of 10% in the case of copper.\n\n    d. steel\n\n    Ferrous materials other than those of heading 7203 which (with the exception of certain types produced in the form of castings) are usefully malleable and which contain by weight 2% or less of carbon. However, chromium steels may contain higher proportions of carbon.\n\n    e. stainless steel\n\n    Alloy steels containing, by weight, 1.2% or less of carbon and 10.5% or more of chromium, with or without other elements.\n\n    f. other alloy steel\n\n    Steels not complying with the definition of stainless steel and containing by weight one or more of the following elements in the proportion shown:\n\n    - 0.3% or more of aluminium\n\n    - 0.0008% or more of boron\n\n    - 0.3% or more of chromium\n\n    - 0.3% or more of cobalt\n\n    - 0.4% or more of copper\n\n    - 0.4% or more of lead\n\n    - 1.65% or more of manganese\n\n    - 0.08% or more of molybdenum\n\n    - 0.3% or more of nickel\n\n    - 0.06% or more of niobium\n\n    - 0.6% or more of silicon\n\n    - 0.05% or more of titanium\n\n    - 0.3% or more of tungsten (wolfram)\n\n    - 0.1% or more of vanadium\n\n    - 0.05% or more of zirconium\n\n    - 0.1% or more of other elements (except sulphur, phosphorus, carbon and nitrogen), taken separately.\n\n    g. remelting scrap ingots of iron or steel\n\n    Products roughly cast in the form of ingots without feeder-heads or hot tops, or of pigs, having obvious surface faults and not complying with the chemical composition of pig iron, spiegeleisen or ferro-alloys.\n\n    h. granules\n\n    Products of which less than 90% by weight passes through a sieve with a mesh aperture of 1mm and of which 90% or more by weight passes through a sieve with a mesh aperture of 5mm.\n\n    ij. semi-finished products\n\n    Continuous cast products of solid section, whether or not subjected to primary hot-rolling; and other products of solid section, which have not been further worked than subjected to primary hot-rolling or roughly shaped by forging, including blanks for angles, shapes or sections. These products are not presented in coils.\n\n    k. flat-rolled products\n\n    Rolled products of solid rectangular (other than square) cross-section, which do not conform to the definition at (ij) above in the form of:\n\n    - coils of successively superimposed layers, or\n\n    - straight lengths, which if of a thickness less than 4.75mm are of a width measuring at least 10 times the thickness or if of a thickness of 4.75mm or more are of a width which exceeds 150mm and measures at least twice the thickness.\n\n    Flat-rolled products include those with patterns in relief derived directly from rolling (for example, grooves, ribs, chequers, tears, buttons, lozenges) and those which have been perforated, corrugated or polished, provided that they do not thereby assume the character of articles or products of other headings.\n\n    Flat-rolled products of a shape other than rectangular or square, of any size are to be classified as products of a width of 600mm or more, provided that they do not assume the character of articles or products of other headings.\n\n    l. bars and rods, hot-rolled, in irregularly wound coils\n\n    Hot-rolled products in irregularly wound coils, which have a solid cross-section in the shape of circles, segments of circles, ovals, rectangles (including squares), triangles or other convex polygons (including \'flattened circles\' and \'modified rectangles\', of which two opposite sides are convex arcs, the other two sides being straight, of equal length and parallel). These products may have indentations, ribs, grooves or other deformations produced during the rolling process (reinforcing bars and rods).\n\n    m. other bars and rods\n\n    Products which do not conform to any of the definitions at (ij), (k) or (l) above or to the definition of wire, which have a uniform solid cross-section along their whole length in the shape of circles, segments of circles, ovals, rectangles (including squares), triangles or other convex polygons (including \'flattened circles\' and \'modified rectangles\', of which two opposite sides are convex arcs, the other two sides being straight, of equal length and parallel). \n\n    These products may:\n\n    - have indentations, ribs, grooves or other deformations produced during the rolling process (reinforcing bars and rods);\n\n    - be twisted after rolling.\n\n    n. angles, shapes and sections\n\n    Products having a uniform solid cross-section along their whole length which do not conform to any of the definitions at (ij), (k), (l) or (m) above or to the definition of wire.\n\n    Chapter 72 does not include products of heading 7301 or 7302.\n\n    o. wire\n\n    Cold-formed products in coils, of any uniform solid cross-section along their whole length, which do not conform to the definition of flat-rolled products.\n\n    p. hollow drill bars and rods\n\n    Hollow bars and rods of any cross-section, suitable for drills, of which the greatest external dimension of the cross-section exceeds 15mm but does not exceed 52mm, and of which the greatest internal dimension does not exceed one half of the greatest external dimension. Hollow bars and rods of iron or steel not conforming to this definition are to be classified in heading 7304.\n\n2. Ferrous metals clad with another ferrous metal are to be classified as products of the ferrous metal predominating by weight.\n\n3. Iron or steel products obtained by electrolytic deposition, by pressure casting or by sintering are to be classified, according to their form, their composition and their appearance, in the headings of this Chapter appropriate to similar hot-rolled products.\n\n### Subheading notes\n\n1. In this chapter, the following expressions have the meanings hereby assigned to them:\n\n    a. alloy pig iron\n\n    Pig iron containing, by weight, one or more of the following elements in the specified proportions:\n\n    - more than 0.2% of chromium\n\n    - more than 0.3% of copper\n\n    - more than 0.3% of nickel\n\n    - more than 0.1% of any of the following elements: aluminium, molybdenum, titanium, tungsten (wolfram), vanadium.\n\n    b. non-alloy free-cutting steel\n\n    Non-alloy steel containing, by weight, one or more of the following elements in the specified proportions:\n\n    - 0.08% or more of sulphur\n\n    - 0.1% or more of lead\n\n    - more than 0.05% of selenium\n\n    - more than 0.01% of tellurium\n\n    - more than 0.05% of bismuth.\n\n    c. silicon-electrical steel\n\n    Alloy steels containing by weight at least 0.6% but not more than 6% of silicon and not more than 0.08% of carbon. They may also contain by weight not more than 1% of aluminium but no other element in a proportion that would give the steel the characteristics of another alloy steel.\n\n    d. high speed steel\n\n    Alloy steels containing, with or without other elements, at least two of the three elements molybdenum, tungsten and vanadium with a combined content by weight of 7% or more, 0.6% or more of carbon and 3 to 6% of chromium.\n\n    e. silico-manganese steel\n\n    Alloy steels containing by weight:\n\n    - not more than 0.7% of carbon,\n\n    - 0.5% or more but not more than 1.9% of manganese, and\n\n    - 0.6% or more but not more than 2.3% of silicon, but no other element in a proportion that would give the steel the characteristics of another alloy steel.\n\n2. For the classification of ferro-alloys in the subheadings of heading 7202 the following rule should be observed:\n\n    A ferro-alloy is considered as binary and classified under the relevant subheading (if it exists) if only one of the alloy elements exceeds the minimum percentage laid down in note 1(c) to this Chapter; by analogy, it is considered respectively as ternary or quaternary if two or three alloy elements exceed the minimum percentage.\n\n    For the application of this rule, the unspecified \'other elements\' referred to in note 1(c) to this Chapter must each exceed 10% by weight.\n\n### Additional chapter note\n\nThe following expressions have the meanings hereby assigned to them:\n\n- \'Electrical\': for the purposes of codes 7209 16 10, 7209 17 10, 7209 18 10, 7209 26 10, 7209 27 10, 7209 28 10 and 7211 23 20, flat-rolled products which under a current of 50 Hz and a magnetic flux of 1 T have a watt-loss per kg, calculated by the Epstein method, of:\n\n- 2.1 W or less, when their thickness does not exceed 0.20mm,\n\n- 3.6 W or less, when their thickness is not less than 0.20mm but less than 0.60mm,\n\n- 6 W or less, when their thickness is not less than 0.60mm but not greater than 1.50mm.\n\n- \'Tinplate\': for the purposes of codes 7210 12 20, 7210 70 10, 7212 10 10 and 7212 40 20, flat-rolled products (of a thickness of less than 0.5mm) coated with a layer of metal containing, by weight, 97% or more of tin.\n\n- \'Tool steel\': for the purposes of codes 7224 10 10, 7224 90 02, 7225 30 10, 7225 40 12, 7226 91 20, 7228 30 20, 7228 40 10, 7228 50 20 and 7228 60 20, alloy steels, other than stainless or high-speed steel, containing, by weight, one of the following compositions, with or without other elements:\n\n- less than 0.6% of carbon \n\n    and 0.7% or more of silicon and 0.05% or more of vanadium\n\n    or\n\n    4% or more of tungsten;\n\n- 0.8% or more of carbon\n\n    and\n\n    0.05% or more of vanadium;\n\n- more than 1.2% of carbon\n\n    and\n\n    not less than 11% but not more than 15% of chromium;\n\n- 0.16% or more but not more than 0.5% of carbon\n\n    and\n\n    3.8% or more but not more than 4.3% of nickel\n\n    and\n\n    1.1% or more but not more than 1.5% of chromium\n\n    and\n\n    0.15% or more but not more than 0.5% of molybdenum;\n\n    0.3% or more but not more than 0.5% of carbon\n\n    and\n\n    1.4% or more but not more than 2.1% of chromium\n\n    and\n\n    0.15% or more but not more than 0.5% of molybdenum\n\n    and\n\n    less than 1.2% of nickel;\n\n- 0.3% or more of carbon\n\n    and\n\n    less than 5.2% of chromium\n\n    and\n\n    0.65% or more of molybdenum or 0.4% or more of tungsten;\n\n- 0.5% or more but not more than 0.6% of carbon\n\n    and\n\n    1.25% or more but not more than 1.8% of nickel\n\n    and\n\n    0.5% or more but not more than 1.2% of chromium\n\n    and\n    0.15% or more but not more than 0.5% of molybdenum', note_length: 11859 },
  { chapter_number: 73, chapter_code: '73', description: 'ARTICLES OF IRON OR STEEL', chapter_note: '1. In this chapter, the expression \'cast iron\' applies to products obtained by casting in which iron predominates by weight over each of the other elements and which do not comply with the chemical composition of steel as defined in Note 1(d) to Chapter 72.\n\n2. In this chapter, the word \'wire\' means hot- or cold-formed products of any cross-sectional shape, of which no cross-sectional dimension exceeds 16mm.', note_length: 413 },
  { chapter_number: 74, chapter_code: '74', description: 'COPPER AND ARTICLES THEREOF', chapter_note: 'In this chapter, the following expressions have the meanings hereby assigned to them:\n\na. Refined copper:\n\nMetal containing at least 99.85% by weight of copper; or\n\nMetal containing at least 97.5% by weight of copper, provided that the content by weight of any other element does not exceed the limit specified in the following table:\n\n**Other elements**\n\n| Element              | Limiting content % by weight |\n|----------------------|------------------------------|\n| Ag Silver            | 0.25                         |\n| As Arsenic           | 0.5                          |\n| Cd Cadmium           | 1.3                          |\n| Cr Chromium          | 1.4                          |\n| Mg Magnesium         | 0.8                          |\n| Pb Lead              | 1.5                          |\n| S Sulphur            | 0.7                          |\n| Sn Tin               | 0.8                          |\n| Te Tellurium         | 0.8                          |\n| Zn Zinc              | 1                            |\n| Zr Zirconium         | 0.3                          |\n| Other elements, each | 0.3                          |\n\n\nOther elements are, for example, Al, Be, Co, Fe, Mn, Ni, Si\n\n\nb. Copper alloys:\n\nMetallic substances other than unrefined copper in which copper predominates by weight over each of the other elements, provided that:\n\n(1) the content by weight of at least one of the other elements is greater than the limit specified in the foregoing table; or\n\n(2) the total content by weight of such other elements exceeds 2.5%\n\nc. Master alloys:\n\nAlloys containing with other elements more than 10% by weight of copper, not usefully malleable and commonly used as an additive in the manufacture of other alloys or as de-oxidants, de-sulphurising agents or for similar uses in the metallurgy of non-ferrous metals. However, copper phosphide (phosphor copper) containing more than 15% by weight of phosphorus falls in heading 2853.\n\n### Subheading note\n\nIn this chapter, the following expressions have the meanings hereby assigned to them:\n\na. Copper-zinc base alloys (brasses):\n\nAlloys of copper and zinc, with or without other elements. When other elements are present:\n\n- zinc predominates by weight over each of such other elements,\n- any nickel content by weight is less than 5% (see copper-nickel-zinc alloys (nickel silvers)), and\n- any tin content by weight is less than 3% (see copper-tin alloys (bronzes)).\n\nb. Copper-tin base alloys (bronzes):\n\nAlloys of copper and tin, with or without other elements. When other elements are present, tin predominates by weight over each of such other elements, except that when the tin content is 3% or more the zinc content by weight may exceed that of tin but must be less than 10%.\n\nc. Copper-nickel-zinc base alloys (nickel silvers):\n\nAlloys of copper, nickel and zinc, with or without other elements. The nickel content is 5% or more by weight (see copper-zinc alloys (brasses)).\n\nd. Copper-nickel base alloys:\n\nAlloys of copper and nickel, with or without other elements but in any case, containing by weight not more than 1% of zinc. When other elements are present, nickel predominates by weight over each of such other elements.', note_length: 3273 },
  { chapter_number: 75, chapter_code: '75', description: 'NICKEL AND ARTICLES THEREOF', chapter_note: '### Subheading notes\n\n1. In this chapter, the following expressions have the meanings hereby assigned to them:\n\n    a. nickel, not alloyed:\n\n    Metal containing by weight at least 99% of nickel plus cobalt, provided that:\n\n    (i) the cobalt content by weight does not exceed 1.5%, and\n    (ii) the content by weight of any other element does not exceed the limit specified in the following table:\n\n\n    | Element | Limiting content % by weight |\n    |-|-|\n    | Fe (Iron) | 0.5 |\n    | O (Oxygen) | 0.4 |\n    | Other elements, each | 0.3 |\n\n\n    b. nickel alloys:\n\n    Metallic substances in which nickel predominates by weight over each of the other elements provided that:\n\n    (i) the content by weight of cobalt exceeds 1.5%,\n    (ii) the content by weight of at least one of the other elements is greater than the limit specified in the foregoing table, or\n    (iii) the total content by weight of elements other than nickel plus cobalt exceeds 1%.\n\n2. Notwithstanding the provisions of Note 9(c) to Section XV, for the purposes of subheading 7508 10 the term \'wire\' applies only to products, whether or not in coils, of any cross-sectional shape, of which no cross sectional dimension exceeds 6 mm.', note_length: 1233 },
  { chapter_number: 76, chapter_code: '76', description: 'ALUMINIUM AND ARTICLES THEREOF', chapter_note: '### Subheading notes\n\n1. In this chapter, the following expressions have the meanings hereby assigned to them:\n\n    a. Aluminium, not alloyed:\n\n    Metal containing by weight at least 99% of aluminium, provided that the content by weight of any other element does not exceed the limit specified in the following table:\n\n    **Other elements**\n\n    | Element                                                    | Limiting content % by weight                                                                                                                             |\n    |------------------------------------------------------------|----------------------------------------------------------------------------------------------------------------------------------------------------------|\n    | Fe + Si (iron plus silicon)                                | 1                                                                                                                                                        |\n    | Other elements each                                        | 0.1                                                                                                                                                      |\n    | (Other elements are, for example, Cr, Cu, Mg, Mn, Ni, Zn.) | (Copper is permitted in a proportion greater than 0.1 % but not more than 0.2 %, provided that neither the chromium nor manganese content exceeds 0.05%) |\n\n    b. Aluminium alloys:\n\n    Metallic substances in which aluminium predominates by weight over each of the other elements, provided that:\n\n    1. the content by weight of at least one of the other elements or of iron plus silicon taken together is greater than the limit specified in the foregoing table, or\n\n    2. the total content by weight of such other elements exceeds 1%.\n\n1. Notwithstanding the provisions of note 9(c) to Section XV, for the purposes of subheading 7616 91 the term ‘wire’ applies only to products, whether or not in coils, of any cross-sectional shape, of which no cross sectional dimension exceeds 6 mm.\n\n### Additional chapter notes\n\n1. For the purposes of codes 7601 10 10,7601 20 30 and 7601 20 40, the following terms shall have the meanings hereby assigned to them:\n\n    - ‘slabs’: unwrought products which have a uniform solid cross-section along their whole length in the shape of a rectangle or other polygon, of a width exceeding 800 mm, of a thickness exceeding 280 mm and of a length always superior to the width and to the thickness. These products are intended for being rolled.\n\n    - ‘billets’: unwrought products which have a uniform solid cross-section along their whole length in the shape of a circle (including a ‘flattened circle’), of a diameter exceeding 125 mm.\n\n2. For the purposes of codes 7606 12 11 and 7606 12 19, the following terms shall have the meaning hereby assigned to them:\n\n    - ‘beverage can body stock’: sheets or strips in coils, rolled, having manganese and magnesium as the main alloying elements and having a minimum tensile strength of 262 MPa. The sheets or strips have a uniform solid cross section along their whole length, are of a width of 300 mm or more but not more than 2000 mm, of a thickness exceeding 0.2 mm but not exceeding 0.4 mm, and of a length always superior to the width and to the thickness. Beverage can body stock is pre lubricated, with a bright surface;\n\n    - ‘beverage can end stock and tab stock’: sheets or strips in coils, having magnesium as the main alloying element and having a minimum tensile strength of 345 MPa. The sheets or strips have a uniform solid cross-section along their whole length, are of a width of 30 mm or more but not more than 2000 mm, of a thickness exceeding 0.2 mm but not exceeding 0.35 mm, and of a length always superior to the width and to the thickness. Beverage can end stock is varnished on both sides. Beverage can tab stock is degreased and oiled.\n\n    These products are to be used for the fabrication of rigid beverage cans, including ends (lids) and tabs.\n\n3. For the purposes of codes 7606 11 30, 7606 12 30 and 7607 20 91, the following term shall have the meaning hereby assigned to it:\n\n   - ‘Aluminium Composite Panel’: laminated goods consisting of two flat-rolled sheets or foils of aluminium, whether or not alloyed, each of them having a thickness of not less than 0.08 mm but not exceeding 0.55 mm, and a continuous core of non-porous polymer or mineral material, held together with an adhesive, all together having a thickness of 1.0 mm or more, but not exceeding 6.1 mm. The two external aluminium cover sheets or foils can have different finishes. These goods cannot be coiled.', note_length: 4731 },
  { chapter_number: 78, chapter_code: '78', description: 'LEAD AND ARTICLES THEREOF', chapter_note: '### Subheading note\n\n1. In this chapter, the expression `refined lead\' means:\n\n    Metal containing by weight at least 99.9% of lead, provided that the content by weight of any other element does not exceed the limit specified in the following table:\n\n    **Other elements**\n\n    | Element                       | Element name | Limiting content % by weight |\n    |-------------------------------|--------------|------------------------------|\n    | Ag                            | Silver       | 0.02                         |\n    | As                            | Arsenic      | 0.005                        |\n    | Bi                            | Bismuth      | 0.05                         |\n    | Ca                            | Calcium      | 0.002                        |\n    | Cd                            | Cadmium      | 0.002                        |\n    | Cu                            | Copper       | 0,08                         |\n    | Fe                            | Iron         | 0.002                        |\n    | S                             | Sulphur      | 0.002                        |\n    | Sb                            | Antimony     | 0.005                        |\n    | Sn                            | Tin          | 0.005                        |\n    | Zn                            | Zinc         | 0.002                        |\n    | Other (for example, Te), each |              | 0.001                        |', note_length: 1472 },
  { chapter_number: 79, chapter_code: '79', description: 'ZINC AND ARTICLES THEREOF', chapter_note: '### Subheading note\n\nIn this chapter, the following expressions have the meanings hereby assigned to them:\n\n- a. Zinc, not alloyed:\n\n    Metal containing by weight at least 97.5% of zinc.\n\n- b. Zinc alloys:\n\n    Metallic substances in which zinc predominates by weight over each of the other elements, provided that the total content by weight of such other elements exceeds 2.5%.\n\n- c. Zinc dust:\n\n    Dust obtained by condensation of zinc vapour, consisting of spherical particles which are finer than zinc powders. At least 80% by weight of the particles pass through a sieve with 63 micrometres (microns) mesh. It must contain at least 85% by weight of metallic zinc.', note_length: 685 },
  { chapter_number: 80, chapter_code: '80', description: 'TIN AND ARTICLES THEREOF', chapter_note: '### Subheading note\n\nIn this chapter, the following expressions have the meanings hereby assigned to them: \n\na. Tin, not alloyed:\n\nMetal containing by weight at least 99% of tin, provided that the content by weight of any bismuth or copper is less than the limit specified in the following table:\n\n**Other elements**\n\n| Element | Element name | Limiting content % by weight |\n|---------|--------------|------------------------------|\n| Bi      | Bismuth      | 0.1                          |\n| Cu      | Copper       | 0.4                          |\n\n\nb. Tin alloys:\n\nMetallic substances in which tin predominates by weight over each of the other elements, provided that:\n\n(1) the total content by weight of such other elements exceeds 1% or\n\n(2) the content by weight of either bismuth or copper is equal to or greater than the limit specified in the foregoing table.', note_length: 890 },
  { chapter_number: 81, chapter_code: '81', description: 'OTHER BASE METALS; CERMETS; ARTICLES THEREOF', chapter_note: '', note_length: 0 },
  { chapter_number: 82, chapter_code: '82', description: 'TOOLS, IMPLEMENTS, CUTLERY, SPOONS AND FORKS, OF BASE METAL; PARTS THEREOF OF BASE METAL', chapter_note: '1. Apart from blow lamps, portable forges, grinding wheels with frameworks, manicure and pedicure sets, and goods of heading 8209, this Chapter covers only articles with a blade, working edge, working surface or other working part of:\n\n    a. base metal;\n\n    b. metal carbides or cermets;\n\n    c. precious or semi-precious stones (natural, synthetic or reconstructed) on a support of base metal, metal carbide or cermet; or\n\n    d. abrasive materials on a support of base metal, provided that the articles have cutting teeth, flutes, grooves, or the like, of base metal, which retain their identity and function after the application of the abrasive.\n\n2. Parts of base metal of the articles of this chapter are to be classified with the articles of which they are parts, except parts separately specified as such and tool-holders for hand tools (heading 8466). However, parts of general use as defined in note 2 to Section XV are in all cases excluded from this chapter.\n\n    Heads, blades and cutting plates for electric shavers or electric hair clippers are to be classified in heading 8510.\n\n3. Sets consisting of one or more knives of heading 8211 and at least an equal number of articles of heading 8215 are to be classified in heading 8215.', note_length: 1261 },
  { chapter_number: 83, chapter_code: '83', description: 'MISCELLANEOUS ARTICLES OF BASE METAL', chapter_note: '1. For the purposes of this chapter, parts of base metal are to be classified with their parent articles. However, articles of iron or steel of heading 7312, 7315, 7317, 7318 or 7320, or similar articles of other base metal (Chapter 74 to Chapter 76 and Chapter 78 to Chapter 81) are not to be taken as parts of articles of this chapter.\n\n2. For the purposes of heading 8302, the word \'castors\' means those having a diameter (including, where appropriate, tyres) not exceeding 75mm, or those having a diameter (including, where appropriate, tyres) exceeding 75mm provided that the width of the wheel or tyre fitted thereto is less than 30mm.', note_length: 643 },
  { chapter_number: 84, chapter_code: '84', description: 'NUCLEAR REACTORS, BOILERS, MACHINERY AND MECHANICAL APPLIANCES; PARTS THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. millstones, grindstones or other articles of Chapter 68;\n    \n    b. machinery or appliances (for example, pumps) of ceramic material and ceramic parts of machinery or appliances of any material (Chapter 69);\n    \n    c. laboratory glassware (heading 7017); machinery, appliances or other articles for technical uses or parts thereof, of glass (heading 7019 or 7020);\n    \n    d. articles of heading 7321 or 7322 or similar articles of other base metals (Chapter 74 to Chapter 76 or Chapter 78 to Chapter 81);\n    \n    e. vacuum cleaners of heading 8508;\n    \n    f. electromechanical domestic appliances of heading 8509; digital cameras of heading 8525; or\n    \n    g. radiators for the articles of Section XVII; or\n    \n    h. hand-operated mechanical floor sweepers, not motorised (heading 9603).\n\n2. Subject to the operation of note 3 to Section XVI and subject to note 11 to this chapter, a machine or appliance which answers to a description in one or more of the heading 8401 to 8424, or heading 8486 and at the same time to a description in one or more of the heading 8425 to 8480 is to be classified under the appropriate heading of the former group or under heading 8486, as the case may be, and not the latter group.\n\n    - (A) Heading 8419 does not, however, cover:\n\n        - i. germination plant, incubators or brooders (heading 8436);\n\n        - ii. grain dampening machines (heading 8437);\n\n        - iii. diffusing apparatus for sugar juice extraction (heading 8438);\n\n        - iv. machinery for the heat treatment of textile yarns, fabrics or made-up textile articles (heading 8451); or\n\n        - v. machinery, plant or laboratory equipment, designed for a mechanical operation, in which a change of temperature, even if necessary, is subsidiary.\n\n    - (B) Heading 8422 does not cover:\n\n      - i. sewing machines for closing bags or similar containers (heading 8452); or\n\n      - ii. office machinery of heading 8472.\n\n    - (C) Heading 8424 does not cover:\n\n      - i. ink-jet printing machines (heading 8443); or\n\n      - ii. water-jet cutting machines (heading 8456).\n\n\n3. A machine tool for working any material which answers to a description in heading 8456 and at the same time to a description in heading 8457, 8458, 8459, 8460, 8461, 8464 or 8465 is to be classified in heading 8456.\n\n4. Heading 8457 applies only to machine tools for working metal, other than lathes (including turning centres), which can carry out different types of machining operations either:\n\n    a. by automatic tool change from a magazine or the like in conformity with a machining programme (machining centres),\n    \n    b. by the automatic use, simultaneously or sequentially, of different unit heads working on a fixed position workpiece (unit construction machines, single station); or\n    \n    c. by the automatic transfer of the workpiece to different unit heads (multi-station transfer machines).\n\n5. the purposes of heading 8462, a “slitting line” for flat products is a processing line composed of an uncoiler, a coil flattener, a slitter and a recoiler. A “cut-to-length line” for flat products is a processing line composed of an uncoiler, a coil flattener, and a shear.\n\n6. (A) For the purposes of heading 8471, the expression \'automatic data-processing machines\' means machines, capable of\n\n    (1) storing the processing program or programs and at least the data immediately necessary for the execution of the program;\n    \n    (2) being freely programmed in accordance with the requirements of the user;\n    \n    (3) performing arithmetical computations specified by the user; and\n    \n    (4) executing, without human intervention, a processing program which requires them to modify their execution, by logical decision during the processing run.\n    \n    (B) Automatic data-processing machines may be in the form of systems consisting of a variable number of separate units.\n    \n    (C) Subject to paragraphs (D) and (E) below, a unit is to be regarded as being a part of an automatic data processing system if it meets all the following conditions:\n    \n    (1) it is of a kind solely or principally used in an automatic data-processing system;\n    \n    (2) it is connectable to the central processing unit either directly or through one or more other units; and\n    \n    (3) it is able to accept or deliver data in a form (codes or signals) which can be used by the system.\n    \n    Separately presented units of an automatic data-processing machine are to be classified in heading 8471.\n    \n    However keyboards, X-Y coordinate input devices and disk storage units which satisfy the conditions of paragraphs (C)(2) and (C)(3) above, are in all cases to be classified as units of heading 8471.\n    \n    (D) Heading 8471 does not cover the following when presented separately, even if they meet all of the conditions set forth in note 6(C) above:\n    \n    (1) printers, copying machines, facsimile machines, whether or not combined;\n    \n    (2) apparatus for the transmission or reception of voice, images or other data, including apparatus for\n    communication in a wired or wireless network (such as a local or wide area network);\n    \n    (3) loudspeakers and microphones;\n    \n    (4) television cameras, digital cameras and video camera recorders;\n    \n    (5) monitors and projectors, not incorporating television reception apparatus.\n    \n    (E) Machines incorporating or working in conjunction with an automatic data-processing machine and performing a specific function other than data processing are to be classified in the headings appropriate to their respective functions or, failing that, in residual headings.\n\n7. Heading 8482 applies, inter alia, to polished steel balls, the maximum and minimum diameters of which do not differ from the nominal diameter by more than 1% or by more than 0.05 mm, whichever is less.\n\n    Other steel balls are to be classified in heading 7326.\n\n8. A machine which is used for more than one purpose is, for the purposes of classification, to be treated as if its principal purpose were its sole purpose.\n\n    Subject to note 2 to this chapter and note 3 to Section XVI, a machine the principal purpose of which is not described in any heading or for which no one purpose is the principal purpose is, unless the context otherwise requires, to be classified in heading 8479. Heading 8479 also covers machines for making rope or cable (for example, stranding, twisting or cabling machines) from metal wire, textile yarn or any other material or from a combination of such materials.\n\n9.  For the purposes of heading 8470, the term \'pocket-size\' applies only to machines the dimensions of which do not exceed 170 mm x 100 mm x 45 mm.\n\n10. For the purposes of heading 8485, the expression “additive manufacturing” (also referred to as 3D printing) means the formation of physical objects, based on a digital model, by the successive addition and layering, and consolidation and solidification, of material (for example, metal, plastics or ceramics). \n\n    Subject to Note 1 to Section XVI and Note 1 to Chapter 84, machines answering to the description in heading 8485 are to be classified in that heading and in no other heading of the Nomenclature. \n\n\n11. (A) Notes 12(a) and (b) to Chapter 85 also apply with respect to the expressions \'semiconductor devices\' and \'electronic integrated circuits\', respectively, as used in this note and in heading 8486. However, for the purposes of this note and of heading 8486, the expression \'semiconductor devices\' also covers photosensitive semiconductor devices and light emitting diodes.\n\n    (B) For the purposes of this note and of heading 8486, the expression \'manufacture of flat panel displays\' covers the fabrication of substrates into a flat panel. It does not cover the manufacture of glass or the assembly of printed circuit boards or other electronic components onto the flat panel. The expression \'flat panel display\' does not cover cathode-ray tube technology.\n    \n    (C) Heading 8486 also includes machines and apparatus solely or principally of a kind used for:\n    \n    (1) the manufacture or repair of masks and reticles;\n    \n    (2) assembling semiconductor devices or electronic integrated circuits; and\n    \n    (3) lifting, handling, loading or unloading of boules, wafers, semiconductor devices, electronic integrated circuits and flat panel displays.\n    \n    (D) Subject to note 1 to Section XVI and note 1 to Chapter 84, machines and apparatus answering to the description in heading 8486 are to be classified in that heading and in no other heading of the nomenclature.\n\n### Subheading notes\n\n1. For the purposes of subheading 8465 20, the term “machining centres” applies only to machine-tools for working wood, cork, bone, hard rubber, hard plastics or similar hard materials, which can carry out different types of machining operations by automatic tool change from a magazine or the like in conformity with a machining programme.\n\n2. For the purposes of subheading 8471 49, the term ‘systems’ means automatic data-processing machines whose units satisfy the conditions laid down in note 6(C) to Chapter 84 and which comprise at least a central processing unit, one input unit (for example, a keyboard or a scanner), and one output unit (for example, a visual display unit or a printer).\n\n3. For the purposes of subheading 8481 20, the expression “valves for oleohydraulic or pneumatic transmissions” means valves which are used specifically in the transmission of “fluid power” in a hydraulic or pneumatic system, where the energy source is supplied in the form of pressurised fluids (liquid or gas).\n\n    These valves may be of any type (for example, pressure-reducing type, check type). Subheading 8481 20 takes precedence over all other subheadings of heading 8481.\n\n4. Subheading 8482 40 applies only to bearings with cylindrical rollers of a uniform diameter not exceeding 5 mm and having a length which is at least three times the diameter. The ends of the rollers may be rounded.\n\n### Additional chapter notes\n\n1. For the purposes of subheadings 8407 10 and 8409 10, the expression \'aircraft engines\' shall apply only to engines designed for fitting with an airscrew or rotor.\n\n2. Code 8471 70 30 shall also apply to CD-ROM drives, being storage units for automatic data processing machines, which consist of drive units designed for retrieving the signals from CD-ROMs, audio CDs and photo CDs and equipped with a jack for earphones, a volume-control button or a start/stop button.\n\n3. Code 8472 90 80 includes apparatus consisting of a bank note validator and cash boxes (so called ‘note float unit’). The bank note validator uses optical scanning technology to check the authenticity of bank notes according to predefined specifications. In addition to checking the authenticity of bank notes, it also carries out other functions such as sorting and distributing bank notes between different storage boxes and dispensing bank notes.', note_length: 11172 },
  { chapter_number: 85, chapter_code: '85', description: 'ELECTRICAL MACHINERY AND EQUIPMENT AND PARTS THEREOF; SOUND RECORDERS AND REPRODUCERS, TELEVISION IMAGE AND SOUND RECORDERS AND REPRODUCERS, AND PARTS AND ACCESSORIES OF SUCH ARTICLES', chapter_note: '1. This chapter does not cover:\n\n    a. electrically warmed blankets, bed pans, foot-muffs or the like; electrically warmed clothing, footwear or ear pads or other electrically warmed articles worn on or about the person;\n\n    b. articles of glass of heading 7011;\n\n    c. machines and apparatus of heading 8486;\n\n    d. vacuum apparatus of a kind used in medical, surgical, dental or veterinary science (heading 9018); or\n\n    e. electrically heated furniture of Chapter 94.\n\n2. Headings 8501 to 8504 do not apply to goods described in heading 8511, 8512, 8540, 8541 or 8542. However, metal tank mercury arc rectifiers remain classified in heading 8504.\n\n3. For the purposes of heading 8507, the expression \'electric accumulators\' includes those presented with ancillary components which contribute to the accumulator\'s function of storing and supplying energy or protect it from damage, such as electrical connectors, temperature control devices (e.g., thermistors) and circuit protection devices. They may also include a portion of the protective housing of the goods in which they are to be used.\n\n4. Heading 8509 covers only the following electromechanical machines of the kind commonly used for domestic purposes:\n\n    a. floor polishers, food grinders and mixers, and fruit or vegetable juice extractors, of any weight;\n\n    b. other machines provided the weight of such machines does not exceed 20kg. The heading does not, however, apply to fans or ventilating or recycling hoods incorporating a fan, whether or not fitted with filters (heading 8414), centrifugal clothes-dryers (heading 8421), dishwashing machines (heading 8422), household washing machines (heading 8450), roller or other ironing machines (heading 8420 or 8451), sewing machines (heading 8452), electric scissors (heading 8467) or to electro-thermic appliances (heading 8516).\n\n5. For the purposes of heading 8517, the term "smartphones” means telephones for cellular networks, equipped with a mobile operating system designed to perform the functions of an automatic data processing machine such as downloading and running multiple applications simultaneously, including third-party applications, and whether or not integrating other features such as digital cameras and navigational aid systems.\n\n6. For the purposes of heading 8523:\n\n    a. \'solid-state non-volatile storage devices\' (for example, \'flash memory cards\' or \'flash electronic storage cards\') are storage devices with a connecting socket, comprising in the same housing one or more flash memories (for example, \'Flash E2PROM\') in the form of integrated circuits mounted on a printed circuit board. They may include a controller in the form of an integrated circuit and discrete passive components, such as capacitors and resistors;\n\n    b. the term \'smart cards\' means cards which have embedded in them one or more electronic integrated circuits (a microprocessor, random access memory (RAM) or read-only memory (ROM)) in the form of chips. These cards may contain contacts, a magnetic stripe or an embedded antenna but do not contain any other active or passive circuit elements.\n\n7. For the purposes of heading 8524, “flat panel display modules” refer to devices or apparatus for the display of information, equipped at a minimum with a display screen, which are de-signed to be incorporated into articles of other headings prior to use. Display screens for flat panel display modules include, but are not limited to, those which are flat, curved, flexible, foldable or stretchable in form. Flat panel display modules may incorporate additional elements, including those necessary for receiving video signals and the allocation of those signals to pix-els on the display. However, heading 8524 does not include display modules which are equipped with components for converting video signals (e.g., a scaler IC, decoder IC or application processer) or have otherwise assumed the character of goods of other headings.\n\n    For the classification of flat panel display modules defined in this Note, heading 8524 shall take precedence over any other heading in the Nomenclature.\n\n8. For the purposes of heading 8534, \'printed circuits\' are circuits obtained by forming on an insulating base, by any printing process (for example, embossing, plating-up, etching) or by the \'film circuit\' technique, conductor elements, contacts or other printed components (for example, inductances, resistors, capacitors) alone or interconnected according to a pre-established pattern, other than elements which can produce, rectify, modulate or amplify an electrical signal (for example, semiconductor elements).\n\n    The expression \'printed circuits\' does not cover circuits combined with elements other than those obtained during the printing process, nor does it cover individual, discrete resistors, capacitors or inductances. Printed circuits may, however, be fitted with non-printed connecting elements.\n\n    Thin- or thick-film circuits comprising passive and active elements obtained during the same technological process are to be classified in heading 8542.\n\n9. For the purpose of heading 8536, \'connectors for optical fibres, optical fibre-bundles or cables\' means connectors that simply mechanically align optical fibres end to end in a digital line system. They perform no other function, such as the amplification, regeneration or modification of a signal.\n\n10. Heading 8537 does not include cordless infrared devices for the remote control of television receivers or other electrical equipment (heading 8543).\n\n11. For the purposes of heading 8539, the expression “light-emitting diode (LED) light sources” covers :\n\n    (a) “Light-emitting diode (LED) modules” which are electrical light sources based on light-emitting diodes (LED) arranged in electrical circuits and containing further elements like electrical, mechanical, thermal or optical elements. They also contain discrete active elements, discrete passive elements, or articles of heading 8536 or 8542 for the purposes of providing power supply or power control. Light-emitting diode (LED) modules do not have a cap designed to allow easy installation or replacement in a luminaire and ensure mechanical and electrical contact.\n\n    (b) “Light-emitting diode (LED) lamps” which are electrical light sources containing one or more LED modules containing further elements like electrical, mechanical, thermal or optical elements. The distinction between light-emitting diode (LED) modules and light-emitting diode (LED) lamps is that lamps have a cap designed to allow easy installation or replacement in a luminaire and ensure mechanical and electrical contact.\n\n12. For the purpose of heading 8541 and 8542:\n\n    (a)\n\n    (i) “Semiconductor devices” are semiconductor devices the operation of which depends on variations in resistivity on the application of an electric field or semiconductor based transducers.\n\n    Semiconductor devices may also include assembly of plural elements, whether or not equipped with active and passive device ancillary functions.\n\n    “Semiconductor-based transducers” are, for the purposes of this definition, semiconductor-based sensors, semiconductor-based actuators, semiconductor-based resonators and semiconductor-based oscillators, which are types of discrete semiconductor-based devices, which perform an intrinsic function, which are able to convert any kind of physical or chemical phenomena or an action into an electrical signal or an electrical signal into any type of physical phenomenon or an action.\n\n    All the elements in semiconductor-based transducers are indivisibly combined, and may also include necessary materials indivisibly attached, that enable their construction or function.\n\n    The following expressions mean :\n\n    - (1) “Semiconductor-based” means built or manufactured on a semiconductor substrate or made of semiconductor materials, manufactured by semiconductor technology, in which the semiconductor substrate or material plays a critical and unreplaceable role of transducer function and performance, and the operation of which is based on semiconductor properties including physical, electrical, chemical and optical properties\n\n    - (2) “Physical or chemical phenomena” relate to phenomena, such as pressure, acoustic waves, acceleration, vibration, movement, orientation, strain, magnetic field strength, electric field strength, light, radioactivity, humidity, flow, chemicals concentration, etc.\n\n    - (3) “Semiconductor-based sensor” is a type of semiconductor device, which consists of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of detecting physical or chemical quantities and converting these into electric signals caused by resulting variations in electric properties or displacement of a mechanical structure.\n\n    - (4) “Semiconductor-based actuator” is a type of semiconductor device, which consists of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of converting electric signals into physical movement.\n\n    - (5) Semiconductor-based resonator” is a type of semiconductor device, which consists of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of generating a mechanical or electrical oscillation of a predefined frequency that depends on the physical geometry of these structures in response to an external input\n\n    - (6) “Semiconductor-based oscillator” is a type of semiconductor device, which consists of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of generating a mechanical or electrical oscillation of a predefined frequency that depends on the physical geometry of these structures.\n\n    (ii) “Light-emitting diodes (LED)” are semiconductor devices based on semiconductor materials which convert electrical energy into visible, infra-red or ultra-violet rays, whether or not electrically connected among each other and whether or not combined with protective diodes. Light-emitting diodes (LED) of heading 8541 do not incorporate elements for the purposes of providing power supply or power control;\n\n    b. \'Electronic integrated circuits\' are:\n\n    - (1) monolithic integrated circuits in which the circuit elements (diodes, transistors, resistors, capacitors, inductances, etc.) are created in the mass (essentially) and on the surface of a semiconductor or compound semiconductor material (for example doped silicon, gallium arsenide, silicon germanium, lndium phosphide) and are inseparably associated;\n\n    - (2) hybrid integrated circuits in which passive elements (resistors, capacitors, inductances, etc), obtained by thin-or thick-film technology, and active elements (diodes, transistors, monolithic integrated circuits, etc.), obtained by semiconductor technology, are combined to all intents and purposes indivisibly, by interconnections or inter connecting cables, on a single insulating substrate (glass, ceramic, etc.). These circuits may also include discrete components;\n\n    - (3) multichip integrated circuits consisting of two or more interconnected monolithic integrated circuits combined to all intents and purposes indivisibly, whether or not on one or more insulating substrates, with or without leadframes, but with no other active or passive circuit elements.\n\n    - (4) multi-component integrated circuits (MCOs): a combination of one or more monolithic, hybrid, or multichip integrated circuits with at least one of the following components: silicon-based sensors, actuators, oscillators, resonators or combinations thereof, or components performing the functions of articles classifiable under heading 8532, 8533, 8541, or inductors classifiable under heading 8504, formed to all intents and purposes indivisibly into a single body like an integrated circuit, as a component of a kind used for assembly onto a printed circuit board (PCB) or other carrier, through the connecting of pins, leads, balls, lands, bumps, or pads.\n\n        For the purpose of this definition:\n\n        - (1) \'Components\' may be discrete, manufactured independently then assembled onto the rest of the MCO, or integrated into other components.\n\n        - (2) \'Silicon based\' means built on a silicon substrate, or made of silicon materials, or manufactured onto integrated circuit die.\n\n        - (3)\n            (a) \'Silicon based sensors\' consist of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of detecting physical or chemical phenomena and transducing these into electric signals, caused by resulting variations in electric properties or displacement of a mechanical structure. \'Physical or chemical phenomena relates to phenomena, such as pressure, acoustic waves, acceleration, vibration, movement, orientation, strain, magnetic field strength, electric field strength, light, radioactivity, humidity, flow, chemicals concentration, etc.\n\n            (b) \'Silicon based actuators” consist of microelectronic and mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of converting electrical signals into physical movement.\n\n            (c) \'Silicon based resonators\' are components that consist of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and have the function of generating a mechanical or electrical oscillation of a predefined frequency that depends on the physical geometry of these structures in response to an external input.\n\n            (d) \'Silicon based oscillators\' are active components that consist of microelectronic or mechanical structures that are created in the mass or on the surface of a semiconductor and that have the function of generating a mechanical or electrical oscillation of a predefined frequency that depends on the physical geometry of these structures.\n\n    For the classification of the articles defined in this note, heading 8541 and 8542 shall take precedence over any other heading in the nomenclature, except in the case of heading 8523, which might cover them by reference to, in particular, their function.\n\n### Subheading notes\n\n1. Subheading 8525 81 covers only high-speed television cameras, digital cameras and video camera recorders having one or more of the following characteristics:\n\n    - writing speed exceeding 0.5 mm per microsecond;\n\n    - time resolution 50 nanoseconds or less;\n\n    - frame rate exceeding 225,000 frames per second\n\n2. In respect of subheading 8525 82, radiation-hardened or radiation-tolerant television cameras, digital cameras and video camera recorders are designed or shielded to enable operation in a high-radiation environment. These cameras are designed to withstand a total radiation dose of at least 50 × 10<sup>3</sup> Gy(silicon) (5 × 10<sup>6</sup> RAD (silicon)), without operational degradation.\n\n3. Subheading 8525 83 covers night vision television cameras, digital cameras and video camera recorders which use a photocathode to convert available light to electrons, which can be amplified and converted to yield a visible image. This subheading excludes thermal imaging cameras (generally subheading 8525 89).\n\n4. Subheading 8527 12 covers only cassette-players with built-in amplifier, without built-in loudspeaker, capable of operating without an external source of electric power and the dimensions of which do not exceed 170 mm x 100 mm x 45 mm.\n\n5. For the purposes of subheadings 8549 11 to 8549 19, “spent primary cells, spent primary batteries and spent electric accumulators” are those which are neither usable as such because of breakage, cutting-up, wear or other reasons, nor capable of being recharged.\n\n### Additional chapter notes\n\n1. Heading 8517 does not include apparatus which incorporates an interface (for example, an RJ-45 interface), which does not enable the transmission of, for example, video signals, see also the Additional chapter note to code 8543 70 90.\n\n2. Codes 8519 20 10 and 8519 30 00 are to be taken not to apply to sound reproducing apparatus with laser reading system.\n\n3. Code 8543 70 90 8543 70 90 includes electrical apparatus (so-called ‘video converter’) designed to convert video signals from SDI format to HDMI format. They are rectangular shaped, and typically have the following sockets: a Serial Digital Interface (SDI), a High Definition Multimedia Interface (HDMI), an RJ-45 interface, a power connector.\nThe apparatus is designed to convert video signals from SDI format to HDMI format. The RJ-45 interface serves to connect the apparatus to the Ethernet only for software updates and to get electric power needed for those updates, it does not enable the transmission of video signals.\n\n4. Code 8543 40 00 excludes disposable electronic cigarettes (disposable e-cigarettes) and similar disposable personal electric vaporising devices, that incorporate both the product intended for inhalation without combustion (e.g. e-liquid, gels) and the delivery mechanism in an integrated housing, that are designed for disposal after the incorporated product is exhausted or the battery runs out (not designed for refilling or recharging).', note_length: 17588 },
  { chapter_number: 86, chapter_code: '86', description: 'RAILWAY OR TRAMWAY LOCOMOTIVES, ROLLING STOCK AND PARTS THEREOF; RAILWAY OR TRAMWAY TRACK FIXTURES AND FITTINGS AND PARTS THEREOF; MECHANICAL (INCLUDING ELECTROMECHANICAL) TRAFFIC SIGNALLING EQUIPMENT OF ALL KINDS', chapter_note: '1. This chapter does not cover:\n\n    a. railway or tramway sleepers of wood or of concrete, or concrete guide-track sections for hovertrains (heading 4406 or 6810);\n    \n    b. railway or tramway track construction material of iron or steel of heading 7302; or\n    \n    c. electrical signalling, safety or traffic control equipment of heading 8530.\n\n2. Heading 8607 applies, inter alia, to:\n\n    a. axles, wheels, wheels sets (running gear), metal tyres, hoops and hubs and other parts of wheels;\n    \n    b. frames, underframes, bogies and bissel-bogies;\n    \n    c. axle boxes; brake gear;\n    \n    d. buffers for rolling-stock; hooks and other coupling gear and corridor connections;\n    \n    e. coachwork.\n\n3. Subject to the provisions of note 1 above, heading 8608 applies, inter alia, to:\n\n    a. assembled track, turntables, platform buffers, loading gauges;\n    \n    b. semaphores, mechanical signal discs, level-crossing control gear, signal and point controls, and other mechanical (including electro-mechanical) signalling, safety or traffic control equipment, whether or not fitted for electric lighting, for railways, tramways, roads, inland waterways, parking facilities, port installations or airfields.', note_length: 1242 },
  { chapter_number: 87, chapter_code: '87', description: 'VEHICLES OTHER THAN RAILWAY OR TRAMWAY ROLLING STOCK, AND PARTS AND ACCESSORIES THEREOF', chapter_note: '1. This chapter does not cover railway or tramway rolling-stock designed solely for running on rails.\n\n2. For the purposes of this chapter, \'tractors\' means vehicles constructed essentially for hauling or pushing another vehicle, appliance or load, whether or not they contain subsidiary provision for the transport, in connection with the main use of the tractor, of tools, seeds, fertilisers or other goods.\n\n    Machines and working tools designed for fitting to tractors of heading 8701 as interchangeable equipment remain classified in their respective headings even if presented with the tractor, and whether or not mounted on it.\n\n3. Motor chassis fitted with cabs fall in heading 8702 to 8704, and not in heading 8706.\n\n4. Heading 8712 includes all children\'s bicycles. Other children\'s cycles fall in heading 9503.\n\n### Subheading Note\n\nSubheading 8708 22 covers:\n\n   - a. front windscreens (windshields), rear windows and other windows, framed; and \n\n   - b. front windscreens (windshields), rear windows and other windows, whether or not framed, incorporating heating devices or other electrical or electronic devices\n\n   when suitable for use solely or principally with the motor vehicles of heading 8701 to 8705.\n\n### Additional chapter notes\n\n1. Code 8703 10 18 includes mobility scooters which typically include a separate adjustable steering column, a horizontal platform, an adjustable seat, a steering column that can be folded down, thumb-operated levers for accelerating, braking and reversing.  They are not specially designed for the transport of disabled persons as they have no special features to alleviate a dis-ability.\n\n2. Heading 8713 does not include mobility scooters, see also the Additional chapter note to code 8703 10 18.', note_length: 1780 },
  { chapter_number: 88, chapter_code: '88', description: 'AIRCRAFT, SPACECRAFT, AND PARTS THEREOF', chapter_note: '1. For the purposes of this Chapter, the expression “unmanned aircraft” means any aircraft, other than those of heading 8801, designed to be flown without a pilot on board. They may be designed to carry a payload or equipped with permanently integrated digital cameras or other equipment which would enable them to perform utilitarian functions during their flight. \n\n    The expression “unmanned aircraft”, however, does not cover flying toys, designed solely for amusement purposes (heading 9503).\n\n### Subheading notes\n\n1. For the purposes of subheadings 8802 11 to 8802 40, the expression \'unladen weight\' means the weight of the machine in normal flying order, excluding the weight of the crew and of fuel and equipment other than permanently-fitted items of equipment.\n\n2. For the purposes of subheadings 8806 21 to 8806 24 and 8806 91 to 8806 94, the expression "maximum take-off weight" means the maximum weight of the machine in normal flying order, at take-off, including the weight of payload, equipment and fuel.', note_length: 1032 },
  { chapter_number: 89, chapter_code: '89', description: 'SHIPS, BOATS AND FLOATING STRUCTURES', chapter_note: '1. A hull, an unfinished or incomplete vessel, assembled, unassembled or disassembled, or a complete vessel unassembled or disassembled, is to be classified in heading 8906 if it does not have the essential character of a vessel of a particular kind.\n\n### Additional chapter notes\n\n1. Codes 8901 10 10, 8901 20 10, 8901 30 10, 8901 90 10, 8902 00 10, 8903 22 10, 8903 23 10, 8903 32 10, 8903 33 10, 8904 00 91 and 8906 90 10 are to be taken to apply only to vessels, designed as sea going, having a hull of an overall length (excluding any projecting parts) of not less than 12m. However, fishing boats and lifeboats, designed as sea going, shall be considered as sea going vessels regardless of their length.\n\n2. Codes 8905 10 10 and 8905 90 10 are to be taken to apply only to vessels and floating docks, designed as sea going.\n\n3. For the purpose of heading 8908, the expression `vessels and other floating structures for breaking up\' includes the following articles when presented for breaking up, on condition that they have formed part of their normal equipment:\n\n    - spare parts (such as propellers), whether or not in a new condition,\n    - moveable articles (furniture, kitchen equipment, tableware, etc.) showing clear evidence of use.', note_length: 1258 },
  { chapter_number: 90, chapter_code: '90', description: 'OPTICAL, PHOTOGRAPHIC, CINEMATOGRAPHIC, MEASURING, CHECKING, PRECISION, MEDICAL OR SURGICAL INSTRUMENTS AND APPARATUS; PARTS AND ACCESSORIES THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. articles of a kind used in machines, appliances or for other technical uses, of vulcanised rubber other than hard rubber (heading 4016), of leather or of composition leather (heading 4205) or of textile material (heading 5911);\n    \n    b. supporting belts or other support articles of textile material, whose intended effect on the organ to be supported or held derives solely from their elasticity (for example, maternity belts, thoracic support bandages, abdominal support bandages, supports for joints or muscles) (Section XI);\n    \n    c. refractory goods of heading 6903; ceramic wares for laboratory, chemical or other technical uses, of heading 6909;\n    \n    d. glass mirrors, not optically worked, of heading 7009, or mirrors of base metal or of precious metal, not being optical elements (heading 8306 or Chapter 71);\n    \n    e. goods of heading 7007, 7008, 7011, 7014, 7015 or 7017;\n    \n    f. parts of general use, as defined in note 2 to Section XV, of base metal (Section XV) or similar goods of plastics (Chapter 39), however, articles specially designed for use exclusively in implants in medical, surgical, dental or veterinary sciences are to be classified in heading 9021;\n    \n    g. pumps incorporating measuring devices, of heading 8413; weight-operated counting and checking machinery, or separately presented weights for balances (heading 8423); lifting or handling machinery (heading 8425 to 8428); paper or paperboard cutting machines of all kinds (heading 8441); fittings for adjusting work or tools on machine tools or water-jet cutting machines, of heading 8466, including fittings with optical devices for reading the scale (for example, optical dividing heads) but not those which are in themselves essentially optical instruments (for example, alignment telescopes); calculating machines (heading 8470); valves and other appliances of heading 8481; machines and apparatus (including apparatus for the projection or drawing of circuit patterns on sensitised semiconductor materials) of heading 8486;\n    \n    h. searchlights or spotlights of a kind used for cycles or motor vehicles (heading 8512); portable electric lamps of heading 8513; cinematographic sound recording, reproducing or re-recording apparatus (heading 8519); sound-heads (heading 8522); television cameras, digital cameras and video camera recorders (heading 8525); radar apparatus, radio navigational aid apparatus or radio remote control apparatus (heading 8526); connectors for optical fibres, optical fibre bundles or cables (heading 8536); numerical control apparatus of heading 8537; sealed beam lamp units of heading 8539; optical fibre cables of heading 8544;\n    \n    ij. searchlights or spotlights of heading 9405;\n    \n    k. articles of Chapter 95;\n    \n    l. monopods, bipods, tripods and similar articles, of heading 9620;\n    \n    m. capacity measures, which are to be classified according to their constituent material; or\n    \n    n. spools, reels or similar supports (which are to be classified according to their constituent material, for example, in heading 3923 or Section XV).\n\n2. Subject to note 1 above, parts and accessories for machines, apparatus, instruments or articles of this chapter are to be classified according to the following rules:\n\n    a. Parts and accessories which are goods included in any of the headings of this chapter or of Chapter 84, 85 or 91 (other than heading 8487, 8548 or 9033) are in all cases to be classified in their respective headings.\n    \n    b. Other parts and accessories, if suitable for use solely or principally with a particular kind of machine, instrument or apparatus, or with a number of machines, instruments or apparatus of the same heading (including a machine, instrument or apparatus of heading 9010, 9013 or 9031) are to be classified with the machines, instruments or apparatus of that kind;\n    \n    c. All other parts and accessories are to be classified in heading 9033.\n\n3. The provisions of notes 3 and 4 to Section XVI apply also to this chapter.\n\n4. Heading 9005 does not apply to telescopic sights for fitting to arms, periscopic telescopes for fitting to submarines or tanks, or to telescopes for machines, appliances, instruments or apparatus of this chapter or Section XVI; such telescopic sights and telescopes are to be classified in heading 9013.\n\n5. Measuring or checking optical instruments, appliances or machines which, but for this note, could be classified both in heading 9013 and in heading 9031 are to be classified in heading 9031.\n\n6. For the purposes of heading 9021, the expression \'orthopaedic appliances\' means appliances for:\n\n    - Preventing or correcting bodily deformities; or\n    \n    - Supporting or holding parts of the body following an illness, operation or injury.\n    \n    Orthopaedic appliances include footwear and special insoles designed to correct orthopaedic conditions, provided that they are either (1) made to measure or (2) mass-produced, presented singly and not in pairs and designed to fit either foot equally.\n\n7. Heading 9032 applies only to:\n\n    a. instruments and apparatus for automatically controlling the flow, level, pressure or other variables of liquids or gases, or for automatically controlling temperature, whether or not their operation depends on an electrical phenomenon which varies according to the factor to be automatically controlled, which are designed to bring this factor to, and maintain it at, a desired value, stabilised against disturbances, by constantly or periodically measuring its actual value; and\n    \n    b. automatic regulators of electrical quantities, and instruments or apparatus for automatically controlling non-electrical quantities the operation of which depends on an electrical phenomenon varying according to the factor to be controlled, which are designed to bring this factor to, and maintain it at, a desired value, stabilised against disturbances, by constantly or periodically measuring its actual value.\n\n### Additional chapter notes\n\n1. For the purposes of codes 9015 30 10, 9025 80 40, 9026 10 21, 9026 10 29, 9026 20 20, 9026 80 20, 9027 10 10 and 9032 10 20, the expression ‘electronic’ means instruments and apparatus which incorporate one or more articles of heading 8540, 8541 or 8542 but for the purposes of the foregoing, no account shall be taken of articles of heading 8540, 8541 or 8542 which have solely the function of rectifying current or which are included in the power pack of instruments or apparatus.\n\n2. For the purposes of code 9021 10 10, the expression "orthopaedic appliances" means appliances which are specially designed for a particular orthopaedic purpose, in distinction to products that might be used for various purposes (for example, products for overstrained joints, ligaments or tendons caused by sporting activities, type writing, and products which simply alleviate pain in the defective or disabled part of the body, for example, caused by inflammation).\n\n    The "orthopaedic appliances" must completely prevent a specific movement of the defective or disabled part of the body (for example, joints, ligaments, tendons) in order to exclude further injuries or bodily deformities or an aggravation of such injuries or deformities, as distinct from other products that cannot prevent specific movements, yet prevent reflex movements (movements carried out subconsciously) through the relative inflexibility of those products due to, for example, flexible splints, pressure pads, non-elastic textile material, restrictions through "Velcro-type" straps".\n\n3. Heading 9021 does not include mastectomy bras, see also the Additional chapter note to code6212 10 90.\n\n4. Heading 9031 does not include apparatus consisting of a bank note validator and cash boxes, see also the Additional chapter note to code 8472 90 80.', note_length: 7943 },
  { chapter_number: 91, chapter_code: '91', description: 'CLOCKS AND WATCHES AND PARTS THEREOF', chapter_note: '1. This chapter does not cover:\n\n    (a) clock or watch glasses or weights (classified according to their constituent material);\n    \n    (b) watch chains (heading 7113 or 7117, as the case may be);\n    \n    (c) parts of general use defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39) or of precious metal or metal clad with precious metal (generally heading 7115); clock or watch springs are, however, to be classified as clock or watch parts (heading 9114);\n    \n    (d) bearing balls (heading 7326 or 8482, as the case may be);\n    \n    (e) articles of heading 8412 constructed to work without an escapement;\n    \n    (f) ball bearings (heading 8482); or\n    \n    (g) articles of Chapter 85, not yet assembled together or with other components into watch or clock movements or into articles suitable for use solely or principally as parts of such movements (Chapter 85).\n\n2. Heading 9101 covers only watches with case wholly of precious metal or of metal clad with precious metal, or of the same materials combined with natural or cultured pearls, or precious or semi-precious stones (natural, synthetic or reconstructed) of heading 7101 to 7104. Watches with case of base metal inlaid with precious metal fall in heading 9102.\n\n3. For the purposes of this chapter, the expression \'watch movements\' means devices regulated by a balance wheel and hairspring, quartz crystal or any other system capable of determining intervals of time, with a display or a system to which a mechanical display can be incorporated. Such watch movements shall not exceed 12mm in thickness and 50mm in width, length or diameter.\n\n4. Except as provided in note 1, movements and other parts suitable for use both in clocks or watches and in other articles (for example, precision instruments) are to be classified in this chapter.', note_length: 1881 },
  { chapter_number: 92, chapter_code: '92', description: 'MUSICAL INSTRUMENTS; PARTS AND ACCESSORIES OF SUCH ARTICLES', chapter_note: '1. This chapter does not cover:\n\n    a. parts of general use, as defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39);\n    \n    b. microphones, amplifiers, loud speakers, headphones, switches, stroboscopes and other accessory instruments, apparatus or equipment of Chapter 85 or 90, for use with but not incorporated in or housed in the same cabinet as instruments of this chapter;\n    \n    c. toy instruments and apparatus (heading 9503);\n    \n    d. brushes for cleaning musical instruments (heading 9603), or monopods, bipods, tripods and similar articles (heading 9620); or\n    \n    e. collectors\' pieces or antiques (heading 9705 or 9706).\n\n2. Bows and sticks and similar devices used in playing the musical instruments of heading 9202 or 9206 presented with such instruments in numbers normal thereto and clearly intended for use therewith, are to be classified in the same heading as the relative instruments.\n\n    Cards, discs and rolls of heading 9209 presented with an instrument are to be treated as separate articles and not as forming a part of such instrument.', note_length: 1138 },
  { chapter_number: 93, chapter_code: '93', description: 'ARMS AND AMMUNITION; PARTS AND ACCESSORIES THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. goods of Chapter 36 (for example, percussion caps, detonators, signalling flares);\n    \n    b. parts of general use, as defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39);\n    \n    c. armoured fighting vehicles (heading 8710);\n    \n    d. telescopic sights or other optical devices suitable for use with arms, unless mounted on a firearm or presented with the firearm on which they are designed to be mounted (Chapter 90);\n    \n    e. bows, arrows, fencing foils or toys (Chapter 95); or\n    \n    f. collectors\' pieces or antiques (heading 9705 or 9706).\n\n2. In heading 9306, the reference to \'parts thereof\' does not include radio or radar apparatus of heading 8526', note_length: 772 },
  { chapter_number: 94, chapter_code: '94', description: 'FURNITURE; BEDDING, MATTRESSES, MATTRESS SUPPORTS, CUSHIONS AND SIMILAR STUFFED FURNISHINGS; LUMINAIRES AND LIGHTING FITTINGS, NOT ELSEWHERE SPECIFIED OR INCLUDED; ILLUMINATED SIGNS, ILLUMINATED NAMEPLATES AND THE LIKE; PREFABRICATED BUILDINGS', chapter_note: '1. This chapter does not cover:\n\n    a. pneumatic or water mattresses, pillows or cushions, of Chapter 39, Chapter 40 or Chapter 63;\n    \n    b. mirrors designed for placing on the floor or ground (for example, cheval-glasses (swing-mirrors)) of heading 7009;\n    \n    c. articles of Chapter 71;\n    \n    d. parts of general use as defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39), or safes of heading 8303;\n    \n    e. furniture specially designed as parts of refrigerating or freezing equipment of heading 8418; furniture specially designed for sewing machines (heading 8452);\n    \n    f. lamps or light sources and parts thereof of Chapter 85;\n\n    g. furniture specially designed as parts of apparatus of heading 8518 (heading 8518), of heading 8519 or 8521 (heading 8522) or of heading 8525 to 8528 (heading 8529);\n    \n    h. articles of heading 8714;\n    \n    ij. dentists\' chairs incorporating dental appliances of heading 9018 or dentists\' spittoons (heading 9018);\n    \n    k. articles of Chapter 91 (for example, clocks and clock cases);\n    \n    l. toy furniture or toy luminaires and lighting fittings (heading 9503), billiard tables or other furniture specially constructed for games (heading 9504), furniture for conjuring tricks or decorations (other than lighting strings) such as Chinese lanterns (heading 9505); or \n    \n    m. monopods, bipods, tripods and similar articles (heading 9620).\n\n2. The articles (other than parts) referred to in heading 9401 to 9403 are to be classified in those headings only if they are designed for placing on the floor or ground.\n\n    The following are, however, to be classified in the headings mentioned above even if they are designed to be hung, to be fixed to the wall or to stand one on the other:\n    \n    a. cupboards, bookcases, other shelved furniture (including single shelves presented with supports for fixing them to the wall) and unit furniture;\n    \n    b. seats and beds.\n\n3. (A) In heading 9401 to 9403 references to parts of goods do not include references to sheets or slabs (whether or not cut to shape but not combined with other parts) of glass (including mirrors), marble or other stone or of any other material referred to in Chapter 68 or Chapter 69.\n\n    (B) Goods described in heading 9404, presented separately, are not to be classified in heading 9401, 9402 or 9403 as parts of goods.\n\n4. For the purposes of heading 9406, the expression \'prefabricated buildings\' means buildings which are finished in the factory or put up as elements, presented together, to be assembled on site, such as housing or worksite accommodation, offices, schools, shops, sheds, garages or similar buildings.\n\n    Prefabricated buildings include "modular building units" of steel, normally presented in the size and shape of a standard shipping container, but substantially or completely pre-fitted internally. Such modular building units are normally designed to be assembled together to form permanent buildings.\n\n\n### Additional chapter notes\n\n1. For the purposes of heading 9404, the expression “stuffed or internally fitted with any material” covers material of any thickness.', note_length: 3241 },
  { chapter_number: 95, chapter_code: '95', description: 'TOYS, GAMES AND SPORTS REQUISITES; PARTS AND ACCESSORIES THEREOF', chapter_note: '1. This chapter does not cover:\n\n    a. candles (heading 3406);\n    \n    b. fireworks or other pyrotechnic articles of heading 3604;\n    \n    c. yarns, monofilament, cords or gut or the like for fishing, cut to length but not made up into fishing lines, of Chapter 39, heading 4206 or Section XI;\n    \n    d. sports bags or other containers of heading 4202, 4303 or 4304;\n    \n    e. fancy dress of textiles, of Chapter 61 or 62; sports clothing and special articles of apparel of textiles, of Chapter 61 or 62, whether or not incorporating incidentally protective components such as pads or padding in the elbow, knee or groin areas (for example, fencing clothing or soccer goalkeeper jerseys);\n    \n    f. textile flags or bunting, or sails for boats, sailboards or land craft, of Chapter 63;\n    \n    g. sports footwear (other than skating boots with ice or roller skates attached) of Chapter 64, or sports headgear of Chapter 65;\n    \n    h. walking sticks, whips, riding-crops or the like (heading 6602), or parts thereof (heading 6603);\n    \n    ij. unmounted glass eyes for dolls or other toys, of heading 7018;\n    \n    k. parts of general use, as defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39);\n    \n    l. bells, gongs or the like of heading 8306;\n    \n    m. pumps for liquids (heading 8413), filtering or purifying machinery and apparatus for liquids or gases (heading 8421), electric motors (heading 8501), electric transformers (heading 8504), discs, tapes, solidstate non-volatile storage devices, \'smart cards\' and other media for the recording of sound or of other phenomena, whether or not recorded (heading 8523), radio remote control apparatus (heading 8526) or cordless infrared remote-control devices (heading 8543);\n    \n    n. sports vehicles (other than bobsleighs, toboggans and the like) of Section XVII;\n    \n    o. children\'s bicycles (heading 8712);\n\n    p. Unmanned aircraft (heading 8806);\n    \n    q. sports craft such as canoes and skiffs (Chapter 89), or their means of propulsion (Chapter 44 for such articles made of wood);\n\n    r. spectacles, goggles or the like, for sports or outdoor games (heading 9004);\n\n    s. decoy calls or whistles (heading 9208);\n\n    t. arms or other articles of Chapter 93;\n\n    u. lighting strings of all kinds (heading 9405);\n\n    v. monopods, bipods, tripods and similar articles (heading 9620);\n\n    w. racket strings, tents or other camping goods, or gloves, mittens and mitts (classified according to their constituent material); or\n\n    x. tableware, kitchenware, toilet articles, carpets and other textile floor coverings, apparel, bedlinen, table linen, toilet linen, kitchen linen and similar articles having a utilitarian function (classified according to their constituent material).\n\n2. This chapter includes articles in which natural or cultured pearls, precious or semi-precious stones (natural, synthetic or reconstructed), precious metal or metal clad with precious metal constitute only minor constituents.\n\n3. Subject to note 1 above, parts and accessories which are suitable for use solely or principally with articles of this chapter are to be classified with those articles.\n\n4. Subject to the provision of note 1 above, heading 9503 applies, inter alia, to articles of this heading combined with one or more items, which cannot be considered as sets under the terms of General rule of interpretation 3(b) and which, if presented separately, would be classified in other headings, provided the articles are put up together for retail sale and the combinations have the essential character of toys.\n\n5. Heading 9503 does not cover articles which, on account of their design, shape or constituent material, are identifiable as intended exclusively for animals, for example, \'pet toys\' (classification in their own appropriate heading).\n\n6. For the purposes of heading 9508:\n\n    - a. the expression “amusement park rides” means a device or combination of devices or equipment that carry, convey, or direct a person or persons over or through a fixed or restricted course, including watercourses, or within a defined area for the primary purposes of amusement or entertainment. Such rides may be combined within an amusement park, theme park, water park or fairground. These amusement park rides do not include equipment of a kind commonly installed in residences or playgrounds; \n\n    - b. the expression “water park amusements” means a device or combination of devices or equipment that are characterized by a defined area involving water, with no purposes built path. Water park amusements only include equipment designed specifically for water parks; and \n\n    - c. The expression “fairground amusements” means games of chance, strength or skill, which commonly employ an operator or attendant and may be installed in permanent buildings or in-dependent concession stalls. Fairground amusements do not include equipment of heading 9504. \n\nThis heading does not include equipment more specifically classified elsewhere in the nomenclature.\n\n### Subheading notes\n\n1. Subheading 9504 50 covers:\n\n    a. video game consoles from which the image is reproduced on a television receiver, a monitor or other external screen or surface; or\n    \n    b. video game machines having a self-contained video screen, whether or not portable.\n    \n    This subheading does not cover video game consoles or machines operated by coins, banknotes, bankcards, tokens or by any other means of payment (subheading 9504 30).', note_length: 5619 },
  { chapter_number: 96, chapter_code: '96', description: 'MISCELLANEOUS MANUFACTURED ARTICLES', chapter_note: '1. This chapter does not cover:\n\n   a. pencils for cosmetic or toilet uses (Chapter 33);\n\n   b. articles of Chapter 66 (for example, parts of umbrellas or walking sticks);\n\n   c. imitation jewellery (heading 7117);\n\n   d. parts of general use, as defined in note 2 to Section XV, of base metal (Section XV), or similar goods of plastics (Chapter 39);\n\n   e. cutlery or other articles of Chapter 82 with handles or other parts of carving or moulding materials; heading 9601 or 9602 applies, however, to separately presented handles or other parts of such articles;\n\n   f. articles of Chapter 90 (for example, spectacle frames (heading 9003), mathematical drawing pens (heading 9017), brushes of a kind specialised for use in dentistry or for medical, surgical or veterinary purposes (heading 9018));\n\n   g. articles of Chapter 91 (for example, clock or watch cases);\n\n   h. musical instruments or parts or accessories thereof (Chapter 92);\n\n   ij. articles of Chapter 93 (arms and parts thereof);\n\n   k. articles of Chapter 94 (for example, furniture, luminaires and lighting fittings);\n\n   l. articles of Chapter 95 (toys, games, sports requisites); or\n\n   m. works of art, collectors\' pieces or antiques (Chapter 97).\n\n2. In heading 9602, the expression \'vegetable or mineral carving material\' means:\n\n   a. hard seeds, pips, hulls and nuts and similar vegetable materials of a kind used for carving (for example, corozo and dom);\n\n   b. amber, meerschaum, agglomerated amber and agglomerated meerschaum, jet and mineral substitutes for jet.\n\n3. In heading 9603, the expression \'prepared knots and tufts for broom or brush making\' applies only to unmounted knots and tufts of animal hair, vegetable fibre or other material, which are ready for incorporation without division in brooms or brushes, or which require only such further minor processes as trimming to shape at the top, to render them ready for such incorporation.\n\n4. Articles of this chapter, other than those of heading 9601 to 9606 or 9615, remain classified in the chapter whether or not composed wholly or partly of precious metal or metal clad with precious metal, of natural or cultured pearls, or precious or semi-precious stones (natural, synthetic or reconstructed). However, heading 9601 to 9606 and 9615 include articles in which natural or cultured pearls, precious or semi-precious stones (natural, synthetic or reconstructed), precious metal or metal clad with precious metal constitute only minor constituents.\n\n### Additional chapter notes\n\n1. Codes 9619 00 71 to 9619 00 89 include goods of paper pulp, paper, cellulose wadding or webs of cellulose fibres. Those subheadings also include composite goods consisting of the following:\n\n   a. an inner layer (for example, of nonwovens) designed to wick fluid from the wearer\'s skin and thereby prevent chafing;\n\n   b. an absorbent core for collecting and storing the fluid until the product can be disposed of;\n\n   c. an outer layer (for example, of plastics) to prevent leakage of the fluid from the absorbent core.', note_length: 3088 },
  { chapter_number: 97, chapter_code: '97', description: 'WORKS OF ART, COLLECTORS\' PIECES AND ANTIQUES', chapter_note: '1. This chapter does not cover:\n\n    a. unused postage or revenue stamps, postal stationery (stamped paper) or the like, of heading 4907;\n    \n    b. theatrical scenery, studio back-cloths or the like, of painted canvas (heading 5907) except if they may be classified in heading 9706; or\n    \n    c. pearls, natural or cultured, or precious or semi-precious stones (heading 7101 to 7103).\n\n2. Heading 9701 does not apply to mosaics that are mass-produced reproductions, casts or works of conventional craftsmanship of a commercial character, even if these articles are   de-signed or created by artists. \n\n3. For the purposes of heading 9702, the expression \'original engravings, prints and lithographs\' means impressions produced directly, in black and white or in colour, of one or of several plates wholly executed by hand by the artist, irrespective of the process or of the material employed by him, but not including any mechanical or photomechanical process.\n\n4. Heading 9703 does not apply to mass-produced reproductions or works of conventional craftsmanship of a commercial character, even if these articles are designed or created by artists.\n\n5. (A) Subject to Notes 1 to 4 above, articles of this chapter are to be classified in this chapter and not in any other chapter of the classification.\n\n    (B) Heading 9706 does not apply to articles of the preceding headings of this chapter.\n\n6. Frames around paintings, drawings, pastels, collages or similar decorative plaques, engravings, prints or lithographs are to be classified with those articles, provided they are of a kind and of a value normal to those articles. Frames which are not of a kind or of a value normal to the articles referred to in this note are to be classified separately.\n\n### Additional chapter note\n\n1. Heading 9705 includes collectors\' motor vehicles and aircraft of historical or ethnographic interest which are:\n\n    a. in their original state, without substantial changes to the chassis, body, steering, braking, transmission or suspension system, engine, wings etc. Repairing and restoring is allowed, and broken or worn-out parts, accessories and units can/have been replaced, provided that the vehicle is preserved and maintained in the historically correct condition. Modernised or modified motor vehicles and aircraft are excluded;\n    \n    b. in case of motor vehicles at least thirty years old, in case of aircraft at least fifty years old;\n    \n    c. of a model or type which is no longer in production.\n    \n    The requisite characteristics for inclusion in a collection being relatively rare, not being normally used for its original purpose, being the subject of special transactions outside of the normal trade in similar utility articles, and being of greater value - are presumed to be fulfilled for motor vehicles and aircraft which comply with the above three criteria.\n    \n    This heading also includes, as collectors\' items:\n    \n    - motor vehicles and aircraft, irrespective of their date of manufacture, which can be proved to have been used in the course of an historic event.\n    \n    - motor racing vehicles and racing aircraft which can be proved to have been designed, built and used solely for competition and which have achieved significant sporting success at prestigious national or international events. \n    \n    Parts and accessories for motor vehicles and aircraft are classified in this heading, provided that they are original parts or accessories, that they are at least thirty years old (for motor vehicles), or at least fifty years old (for aircraft), and that they are no longer in production.\n    \n    Replicas and reproductions are excluded, unless they fulfil the above three criteria.', note_length: 3765 },
];
